--
-- Name: _assert_inspection_coherence(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_assert_inspection_coherence"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_area           uuid;
  v_base_tenancy   uuid;
  v_base_completed timestamptz;
begin
  if NEW.kind in ('move_in', 'move_out') and NEW.tenancy_id is null then
    raise exception 'kind % requires a tenancy_id', NEW.kind
      using errcode = 'check_violation';
  end if;

  if NEW.tenancy_id is not null then
    select area_id into v_area
      from public.tenancies
      where account_id = NEW.account_id and id = NEW.tenancy_id and deleted_at is null;
    if v_area is null then
      raise exception 'tenancy % not found in account', NEW.tenancy_id
        using errcode = 'check_violation';
    end if;
    if v_area <> NEW.area_id then
      raise exception 'inspection area % does not match tenancy unit area %', NEW.area_id, v_area
        using errcode = 'check_violation';
    end if;
  end if;

  if NEW.baseline_inspection_id is not null then
    if NEW.kind <> 'move_out' then
      raise exception 'baseline_inspection_id is only valid for kind=move_out'
        using errcode = 'check_violation';
    end if;
    select tenancy_id, completed_at
      into v_base_tenancy, v_base_completed
      from public.inspections
      where account_id = NEW.account_id and id = NEW.baseline_inspection_id;
    if v_base_completed is null then
      raise exception 'baseline inspection must exist and be completed'
        using errcode = 'check_violation';
    end if;
    if v_base_tenancy is distinct from NEW.tenancy_id then
      raise exception 'baseline inspection belongs to a different tenancy'
        using errcode = 'check_violation';
    end if;
  end if;

  return NEW;
end;
$$;


ALTER FUNCTION "public"."_assert_inspection_coherence"() OWNER TO "postgres";

--
-- Name: _capture_maintenance_request_report(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_capture_maintenance_request_report"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_request_xmin xid;
  v_interaction_xmin xid;
begin
  if NEW.maintenance_request_id is null
     or NEW.kind <> 'communication'
     or NEW.direction <> 'inbound'
     or NEW.corrects_id is not null
     or NEW.deleted_at is not null then
    return NEW;
  end if;

  select mr.xmin
    into v_request_xmin
    from public.maintenance_requests mr
   where mr.account_id = NEW.account_id
     and mr.id = NEW.maintenance_request_id;

  if not found then
    return NEW;
  end if;

  select i.xmin
    into v_interaction_xmin
    from public.interactions i
   where i.account_id = NEW.account_id
     and i.id = NEW.id;

  -- xmin is the transaction (or PL/pgSQL exception-block subtransaction) that
  -- inserted each row. Comparing the two rows, rather than comparing either
  -- one with pg_current_xact_id(), also covers the landlord RPC: its exception
  -- handler runs the request + journal writes in one shared subtransaction.
  -- A later follow-up necessarily carries a different xmin.
  if not found or v_request_xmin is distinct from v_interaction_xmin then
    return NEW;
  end if;

  insert into public.maintenance_request_reports (
    account_id, maintenance_request_id, interaction_id
  ) values (
    NEW.account_id, NEW.maintenance_request_id, NEW.id
  )
  on conflict (account_id, maintenance_request_id) do nothing;

  return NEW;
end;
$$;


ALTER FUNCTION "public"."_capture_maintenance_request_report"() OWNER TO "postgres";

