--
-- Name: _comm_choose_persona_route("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_choose_persona_route"("p_account_id" "uuid", "p_parent_id" "uuid", "p_from_address" "text", OUT "o_outcome" "text", OUT "o_party_type" "text", OUT "o_party_id" "uuid", OUT "o_party_source" "text", OUT "o_candidate_count" integer, OUT "o_conflict_party_type" "text", OUT "o_conflict_party_id" "uuid") RETURNS "record"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_matched    int;
  v_conflicted int;
  v_thread_id  uuid;
  v_tenancy_id uuid;
  v_ci_type    text;
  v_ci_id      uuid;
begin
  o_candidate_count := 0;

  select count(*) into v_matched
    from public._comm_resolve_parent_sender(p_account_id, p_parent_id, p_from_address);
  if v_matched = 0 then
    o_outcome := 'parent_sender_mismatch';
    return;
  end if;

  -- A leg whose claims tied at the winning tier is undecidable: fail closed.
  select count(*) into v_conflicted
    from public._comm_resolve_parent_sender(p_account_id, p_parent_id, p_from_address) s
   where s.tier = 'claim_conflict';
  if v_conflicted > 0 then
    o_outcome := 'identity_conflict';
    return;
  end if;

  select count(distinct (s.party_type, s.party_id)) into o_candidate_count
    from public._comm_resolve_parent_sender(p_account_id, p_parent_id, p_from_address) s
   where s.party_id is not null;
  if o_candidate_count = 0 then
    o_outcome := 'unknown';
    return;
  end if;
  if o_candidate_count > 1 then
    o_outcome := 'identity_conflict';
    return;
  end if;

  -- One party; when several tiers matched it, report the strongest.
  select s.party_type, s.party_id, s.tier
    into o_party_type, o_party_id, o_party_source
    from public._comm_resolve_parent_sender(p_account_id, p_parent_id, p_from_address) s
   where s.party_id is not null
   order by array_position(
     array['thread_participant', 'tenancy_member', 'account_member',
           'verified_identity', 'snapshot_frozen', 'snapshot_learned',
           'learned_identity'],
     s.tier)
   limit 1;

  -- The sender's own exact-address claim, if a LIVE one names someone else.
  -- Scope-applicable within the parent's conversation; deterministic order.
  select o.thread_id, o.tenancy_id into v_thread_id, v_tenancy_id
    from public.comm_outbox o
   where o.id = p_parent_id and o.account_id = p_account_id;

  select ci.party_type, ci.party_id into v_ci_type, v_ci_id
    from public.channel_identities ci
   where ci.account_id = p_account_id
     and ci.channel = 'email'
     and ci.address = lower(btrim(p_from_address))
     and ci.superseded_at is null
     and (
       ci.scope_type is null
       or (ci.scope_type = 'tenancy' and ci.scope_id = v_tenancy_id)
       or (ci.scope_type = 'thread'  and ci.scope_id = v_thread_id)
     )
     and (ci.party_type, ci.party_id) is distinct from (o_party_type, o_party_id)
   order by case
              when ci.source = 'human_link' then 0
              when ci.verified_at is not null
                or ci.source in ('thread_rebind', 'parent_recipient', 'authoritative_import')
                then 1
              when ci.source = 'provider_learned' then 2
              else 3
            end,
            ci.created_at desc, ci.id
   limit 1;

  if v_ci_type is not null then
    o_conflict_party_type := v_ci_type;
    o_conflict_party_id   := v_ci_id;
    if o_party_source not in
       ('thread_participant', 'tenancy_member', 'account_member',
        'verified_identity', 'snapshot_frozen') then
      o_outcome := 'identity_conflict';
      return;
    end if;
    -- Authoritative context outranks the contradicting claim: proceed; the
    -- contradiction rides the routing decision for a later, audited repair.
  end if;

  o_outcome := case when o_party_type = 'landlord_user'
                 then 'cc_journaled' else 'matched' end;
end;
$$;


ALTER FUNCTION "public"."_comm_choose_persona_route"("p_account_id" "uuid", "p_parent_id" "uuid", "p_from_address" "text", OUT "o_outcome" "text", OUT "o_party_type" "text", OUT "o_party_id" "uuid", OUT "o_party_source" "text", OUT "o_candidate_count" integer, OUT "o_conflict_party_type" "text", OUT "o_conflict_party_id" "uuid") OWNER TO "postgres";

--
-- Name: _comm_find_parent_outbox("uuid", "text", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_find_parent_outbox"("p_account_id" "uuid", "p_in_reply_to" "text", "p_references" "text"[], OUT "o_match" "text", OUT "o_parent_id" "uuid") RETURNS "record"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_irt  text := public._comm_normalize_msgid(p_in_reply_to);
  v_norm text;
  v_ids  uuid[];
  i      int;
begin
  o_match := 'none';

  if v_irt is not null then
    select coalesce(array_agg(o.id), '{}') into v_ids
      from public.comm_outbox o
     where o.account_id = p_account_id
       and o.channel = 'email'
       and o.status in ('sent', 'delivered')
       and o.rfc822_message_id is not null
       and public._comm_normalize_msgid(o.rfc822_message_id) = v_irt;
    if array_length(v_ids, 1) = 1 then
      o_match := 'unique'; o_parent_id := v_ids[1]; return;
    elsif array_length(v_ids, 1) > 1 then
      o_match := 'multiple'; return;
    end if;
  end if;

  -- RFC 5322 lists References oldest-first; probe newest->oldest.
  if p_references is not null then
    for i in reverse coalesce(array_length(p_references, 1), 0)..1 loop
      v_norm := public._comm_normalize_msgid(p_references[i]);
      continue when v_norm is null or v_norm is not distinct from v_irt;
      select coalesce(array_agg(o.id), '{}') into v_ids
        from public.comm_outbox o
       where o.account_id = p_account_id
         and o.channel = 'email'
         and o.status in ('sent', 'delivered')
         and o.rfc822_message_id is not null
         and public._comm_normalize_msgid(o.rfc822_message_id) = v_norm;
      if array_length(v_ids, 1) = 1 then
        o_match := 'unique'; o_parent_id := v_ids[1]; return;
      elsif array_length(v_ids, 1) > 1 then
        o_match := 'multiple'; return;
      end if;
    end loop;
  end if;
end;
$$;


ALTER FUNCTION "public"."_comm_find_parent_outbox"("p_account_id" "uuid", "p_in_reply_to" "text", "p_references" "text"[], OUT "o_match" "text", OUT "o_parent_id" "uuid") OWNER TO "postgres";

--
-- Name: _comm_group_routing_key("text", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_group_routing_key"("p_number" "text", "p_members" "text"[]) RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
  select p_number || '>' || coalesce((
    select string_agg(x, '|' order by x collate "C")
      from (
        select distinct m as x
          from unnest(p_members) m
         where m is not null and m <> p_number
      ) s
  ), '');
$$;


