--
-- Name: _comm_normalize_msgid("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_normalize_msgid"("p_raw" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $_$
  with n as (
    select lower(regexp_replace(btrim(coalesce(p_raw, '')), '^<(.*)>$', '\1')) as v
  )
  select case when length(v) between 3 and 998 then v else null end from n;
$_$;


ALTER FUNCTION "public"."_comm_normalize_msgid"("p_raw" "text") OWNER TO "postgres";

--
-- Name: _comm_outbox_guard_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_outbox_guard_update"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_rank_old int;
  v_rank_new int;
begin
  if new.account_id   is distinct from old.account_id
     or new.channel      is distinct from old.channel
     or new.to_address   is distinct from old.to_address
     or new.group_addresses is distinct from old.group_addresses
     or new.cc_addresses is distinct from old.cc_addresses
     or new.to_party_type is distinct from old.to_party_type
     or new.to_party_id  is distinct from old.to_party_id
     or new.cc_parties   is distinct from old.cc_parties
     or new.subject      is distinct from old.subject
     or new.body         is distinct from old.body
     or new.approval_ref is distinct from old.approval_ref
     or new.approved_by  is distinct from old.approved_by
     or new.author_type  is distinct from old.author_type
     or new.client_ref   is distinct from old.client_ref
     or new.created_at   is distinct from old.created_at
     or new.recipient_snapshot is distinct from old.recipient_snapshot then
    raise exception 'comm_outbox intent fields are immutable'
      using errcode = 'check_violation';
  end if;

  v_rank_old := case old.status
    when 'queued' then 0 when 'sending' then 1 when 'needs_reconcile' then 2
    when 'sent' then 3 when 'delivered' then 4 else 9 end;
  v_rank_new := case new.status
    when 'queued' then 0 when 'sending' then 1 when 'needs_reconcile' then 2
    when 'sent' then 3 when 'delivered' then 4 else 9 end;

  if v_rank_old = 9 and new.status is distinct from old.status then
    raise exception 'comm_outbox row is terminal (%)', old.status
      using errcode = 'P0003';
  end if;

  if v_rank_new < v_rank_old then
    raise exception 'comm_outbox status may not move backwards (% -> %)', old.status, new.status
      using errcode = 'P0003';
  end if;

  -- A journal link is written exactly once, by the completion path.
  if old.interaction_id is not null and new.interaction_id is distinct from old.interaction_id then
    raise exception 'comm_outbox.interaction_id is write-once'
      using errcode = 'check_violation';
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."_comm_outbox_guard_update"() OWNER TO "postgres";

--
-- Name: _comm_outbox_refuse_opted_out(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_outbox_refuse_opted_out"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if exists (
    select 1 from public.comm_opt_outs
     where channel = new.channel
       and (address = new.to_address
            or (new.group_addresses is not null and address = any(new.group_addresses)))
  ) then
    raise exception 'a destination address has opted out of % messages', new.channel
      using errcode = 'P0004';
  end if;
  if new.cc_addresses is not null then
    select array_agg(u.addr order by u.ord)
      into new.cc_addresses
      from unnest(new.cc_addresses) with ordinality u(addr, ord)
     where not exists (
       select 1 from public.comm_opt_outs o
        where o.channel = new.channel and o.address = u.addr
     );
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."_comm_outbox_refuse_opted_out"() OWNER TO "postgres";

--
-- Name: _comm_outbox_snapshot_recipients(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_outbox_snapshot_recipients"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_type      text;
  v_id        uuid;
  v_label     text;
  v_source    text;
  v_n         int;
  v_hint_type text;
  v_hint_id   uuid;
  r_cc        record;
begin
  -- Always stamped here — a writer-supplied snapshot is discarded (a forged
  -- snapshot would put words in the cast's mouth).
  if new.group_addresses is not null then
    select jsonb_agg(
             jsonb_build_object(
               'address',    ga.addr,
               'party_type', coalesce(p.party_type, 'unknown'),
               'party_id',   p.party_id,
               'label',      public._party_display_name(new.account_id, p.party_type, p.party_id))
             order by ga.ord)
      into new.recipient_snapshot
      from unnest(new.group_addresses) with ordinality ga(addr, ord)
      left join public.thread_channel_bindings b
        on b.account_id = new.account_id
       and b.thread_id = new.thread_id
       and b.participant_address = ga.addr
       and b.active
      left join public.comm_thread_participants p
        on p.id = b.participant_id;
  else
    v_type := null; v_id := null; v_label := null; v_source := null;

    -- Tier (PR 3): an explicit caller party hint. Independently VERIFIED here
    -- (never trusting the row) and frozen as 'caller_intent'; an unverifiable
    -- hint RAISEs — a silent mislabel is strictly worse than a failed insert.
    if new.to_party_type is not null or new.to_party_id is not null then
      if public._comm_party_intent_verdict(
           new.account_id, new.tenancy_id,
           new.to_party_type, new.to_party_id, new.to_address) <> 'ok' then
        raise exception 'comm_outbox to_party hint failed verification'
          using errcode = 'check_violation';
      end if;
      v_type := new.to_party_type; v_id := new.to_party_id; v_source := 'caller_intent';
    end if;

    if v_type is null and new.participant_id is not null then
      select p.party_type, p.party_id
        into v_type, v_id
        from public.comm_thread_participants p
       where p.id = new.participant_id;
      if v_type is not null then
        v_source := 'thread_participant';
      end if;
    end if;
    -- Authoritative context BEFORE the address book: the intent's own tenancy
    -- and the account's users outrank any claim.
    if v_type is null then
      select h.o_party_type, h.o_party_id
        into v_type, v_id
        from public._comm_resolve_context_party(
               new.account_id, new.tenancy_id, new.channel, new.to_address) h;
      if v_type is not null then
        v_source := case when v_type = 'tenant'
                      then 'tenancy_member' else 'account_member' end;
      end if;
    end if;
    if v_type is null then
      select count(distinct (x.party_type, x.party_id)) into v_n
        from public._comm_resolve_identity_claims(
               new.account_id, new.channel, new.to_address,
               new.tenancy_id, new.thread_id) x;
      if v_n = 1 then
        select x.party_type, x.party_id, x.tier
          into v_type, v_id, v_source
          from public._comm_resolve_identity_claims(
                 new.account_id, new.channel, new.to_address,
                 new.tenancy_id, new.thread_id) x
         limit 1;
        -- Best-effort label off the winning party's live claims.
        select ci.label into v_label
          from public.channel_identities ci
         where ci.account_id = new.account_id
           and ci.channel = new.channel
           and ci.address = lower(btrim(new.to_address))
           and ci.party_type = v_type
           and ci.party_id = v_id
           and ci.superseded_at is null
           and ci.label is not null
         order by (ci.source = 'human_link') desc, ci.created_at desc, ci.id
         limit 1;
      end if;
    end if;
    new.recipient_snapshot := jsonb_build_array(jsonb_build_object(
      'address',    new.to_address,
      'party_type', coalesce(v_type, 'unknown'),
      'party_id',   v_id,
      'label',      coalesce(public._party_display_name(new.account_id, v_type, v_id), v_label),
      'resolution_source', coalesce(v_source, 'unknown')));
  end if;

  -- CC arm: identity-freeze each (already opt-out-scrubbed) CC address after
  -- the primary entries, through the same reordered tiers.
  if new.cc_addresses is not null then
    for r_cc in
      select ca.addr, ca.ord
        from unnest(new.cc_addresses) with ordinality ca(addr, ord)
       order by ca.ord
    loop
      v_type := null; v_id := null; v_label := null; v_source := null;

      -- Tier (PR 3): a caller cc_parties hint naming THIS address. Verified,
      -- then frozen as 'caller_intent'; an unverifiable hint RAISEs.
      if new.cc_parties is not null then
        select e->>'party_type', nullif(e->>'party_id', '')::uuid
          into v_hint_type, v_hint_id
          from jsonb_array_elements(new.cc_parties) e
         where lower(btrim(e->>'address')) = lower(btrim(r_cc.addr))
         limit 1;
        if v_hint_type is not null or v_hint_id is not null then
          if public._comm_party_intent_verdict(
               new.account_id, new.tenancy_id, v_hint_type, v_hint_id, r_cc.addr) <> 'ok' then
            raise exception 'comm_outbox cc_parties hint failed verification'
              using errcode = 'check_violation';
          end if;
          v_type := v_hint_type; v_id := v_hint_id; v_source := 'caller_intent';
        end if;
      end if;

      if v_type is null and new.thread_id is not null then
        select p.party_type, p.party_id
          into v_type, v_id
          from public.thread_channel_bindings b
          join public.comm_thread_participants p on p.id = b.participant_id
         where b.account_id = new.account_id
           and b.thread_id  = new.thread_id
           and b.participant_address = r_cc.addr
           and b.active
         limit 1;
        if v_type is not null then
          v_source := 'thread_participant';
        end if;
      end if;
      if v_type is null then
        select h.o_party_type, h.o_party_id
          into v_type, v_id
          from public._comm_resolve_context_party(
                 new.account_id, new.tenancy_id, new.channel, r_cc.addr) h;
        if v_type is not null then
          v_source := case when v_type = 'tenant'
                        then 'tenancy_member' else 'account_member' end;
        end if;
      end if;
      if v_type is null then
        select count(distinct (x.party_type, x.party_id)) into v_n
          from public._comm_resolve_identity_claims(
                 new.account_id, new.channel, r_cc.addr,
                 new.tenancy_id, new.thread_id) x;
        if v_n = 1 then
          select x.party_type, x.party_id, x.tier
            into v_type, v_id, v_source
            from public._comm_resolve_identity_claims(
                   new.account_id, new.channel, r_cc.addr,
                   new.tenancy_id, new.thread_id) x
           limit 1;
          select ci.label into v_label
            from public.channel_identities ci
           where ci.account_id = new.account_id
             and ci.channel = new.channel
             and ci.address = lower(btrim(r_cc.addr))
             and ci.party_type = v_type
             and ci.party_id = v_id
             and ci.superseded_at is null
             and ci.label is not null
           order by (ci.source = 'human_link') desc, ci.created_at desc, ci.id
           limit 1;
        end if;
      end if;
      new.recipient_snapshot := coalesce(new.recipient_snapshot, '[]'::jsonb)
        || jsonb_build_array(jsonb_build_object(
             'role',       'cc',
             'address',    r_cc.addr,
             'party_type', coalesce(v_type, 'unknown'),
             'party_id',   v_id,
             'label',      coalesce(public._party_display_name(new.account_id, v_type, v_id), v_label),
             'resolution_source', coalesce(v_source, 'unknown')));
    end loop;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."_comm_outbox_snapshot_recipients"() OWNER TO "postgres";

--
-- Name: _comm_party_intent_verdict("uuid", "uuid", "text", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_party_intent_verdict"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_party_type" "text", "p_party_id" "uuid", "p_address" "text") RETURNS "text"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_n    int;
  v_hit  boolean;
  v_tier text;
begin
  if p_party_type is null or p_party_id is null or p_address is null then
    return 'invalid';
  end if;
  if p_party_type not in ('tenant', 'vendor', 'landlord_user') then
    return 'invalid';
  end if;

  -- (1) The party is a live party of THIS account (a landlord_user must be an
  -- owner/manager member — the CC cast vocabulary the arm copies).
  if p_party_type = 'tenant' then
    if not exists (
      select 1 from public.tenants t
       where t.account_id = p_account_id and t.id = p_party_id and t.deleted_at is null
    ) then
      return 'wrong_account';
    end if;
  elsif p_party_type = 'vendor' then
    if not exists (
      select 1 from public.vendors v
       where v.account_id = p_account_id and v.id = p_party_id and v.deleted_at is null
    ) then
      return 'wrong_account';
    end if;
  else
    if not exists (
      select 1 from public.account_members m
       where m.account_id = p_account_id and m.user_id = p_party_id
         and m.role in ('owner', 'manager') and m.deleted_at is null
    ) then
      return 'wrong_account';
    end if;
  end if;

  -- (2) A tenant party must belong to the supplied tenancy.
  if p_party_type = 'tenant' and p_tenancy_id is not null and not exists (
    select 1 from public.tenancy_tenants tt
     where tt.account_id = p_account_id
       and tt.tenancy_id = p_tenancy_id
       and tt.tenant_id  = p_party_id
       and tt.deleted_at is null
  ) then
    return 'not_in_tenancy';
  end if;

  -- (3) The address resolves to THIS party, uniquely, at an authoritative tier.
  -- The resolver returns every distinct party at its single winning tier; the
  -- hint is honored only when that tier is authoritative, the hinted party is
  -- in the winner set, and there is exactly one winner (a tie is claim_conflict
  -- — the address is ambiguous and fails closed).
  select count(distinct (r.party_type, r.party_id)),
         bool_or(r.party_type = p_party_type and r.party_id = p_party_id),
         min(r.tier)
    into v_n, v_hit, v_tier
    from public._comm_resolve_identity_claims(
           p_account_id, 'email', p_address, p_tenancy_id, null) r;

  if coalesce(v_n, 0) <> 1
     or not coalesce(v_hit, false)
     or v_tier not in ('human_link', 'authoritative_record', 'verified_claim') then
    return 'address_unverified';
  end if;

  return 'ok';
end;
$$;


ALTER FUNCTION "public"."_comm_party_intent_verdict"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_party_type" "text", "p_party_id" "uuid", "p_address" "text") OWNER TO "postgres";

--
-- Name: _comm_resolve_context_party("uuid", "uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_resolve_context_party"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_channel" "text", "p_address" "text", OUT "o_party_type" "text", OUT "o_party_id" "uuid") RETURNS "record"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
begin
  -- Email-only: these tiers key on stored email addresses. SMS context
  -- resolution (tenants.phones) is a deliberate non-goal of this slice.
  if p_channel <> 'email' or p_address is null then
    return;
  end if;

  -- Tier: the intent's tenancy members. Scoped to the named tenancy (not the
  -- whole account) so one address shared across tenancies can't cross-link.
  if p_tenancy_id is not null then
    select 'tenant', t.id
      into o_party_type, o_party_id
      from public.tenancy_tenants tt
      join public.tenancies ty
        on ty.account_id = tt.account_id
       and ty.id         = tt.tenancy_id
      join public.tenants t
        on t.account_id = tt.account_id
       and t.id         = tt.tenant_id
     where tt.account_id = p_account_id
       and tt.tenancy_id = p_tenancy_id
       and tt.deleted_at is null
       and ty.deleted_at is null
       and t.deleted_at  is null
       and exists (
         select 1 from unnest(t.emails) e(addr)
          where lower(btrim(e.addr)) = lower(btrim(p_address)))
     order by (tt.role = 'primary') desc, t.id
     limit 1;
    if o_party_type is not null then
      return;
    end if;
  end if;

  -- Tier: the account's landlord users (owner/manager; never 'agent').
  select 'landlord_user', m.user_id
    into o_party_type, o_party_id
    from public.account_members m
    join auth.users u on u.id = m.user_id
   where m.account_id = p_account_id
     and m.deleted_at is null
     and m.role in ('owner', 'manager')
     and lower(btrim(u.email)) = lower(btrim(p_address))
   order by (m.role = 'owner') desc, m.user_id
   limit 1;
end;
$$;


ALTER FUNCTION "public"."_comm_resolve_context_party"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_channel" "text", "p_address" "text", OUT "o_party_type" "text", OUT "o_party_id" "uuid") OWNER TO "postgres";

--
-- Name: _comm_resolve_identity_claims("uuid", "text", "text", "uuid", "uuid", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_resolve_identity_claims"("p_account_id" "uuid", "p_channel" "text", "p_address" "text", "p_tenancy_id" "uuid" DEFAULT NULL::"uuid", "p_thread_id" "uuid" DEFAULT NULL::"uuid", "p_party_types" "text"[] DEFAULT NULL::"text"[]) RETURNS TABLE("party_type" "text", "party_id" "uuid", "tier" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with cand as (
    select ci.party_type, ci.party_id,
           case
             when ci.source = 'human_link' then 'human_link'
             when ci.verified_at is not null
               or ci.source in ('thread_rebind', 'parent_recipient', 'authoritative_import')
               then 'verified_claim'
             when ci.source = 'provider_learned' then 'provider_learned'
             else 'legacy'
           end as tier
      from public.channel_identities ci
     where ci.account_id = p_account_id
       and ci.channel = p_channel
       and ci.address = lower(btrim(p_address))
       and ci.superseded_at is null
       and (
         ci.scope_type is null
         or (ci.scope_type = 'tenancy' and ci.scope_id = p_tenancy_id)
         or (ci.scope_type = 'thread'  and ci.scope_id = p_thread_id)
       )
    union all
    -- The authoritative record books (email addresses only; tenants.emails is
    -- account-unique since 20260721000002 so the tenant arm yields <= 1 row).
    select 'tenant', t.id, 'authoritative_record'
      from public.tenants t
     where p_channel = 'email'
       and t.account_id = p_account_id
       and t.deleted_at is null
       and exists (
         select 1 from unnest(t.emails) e(addr)
          where lower(btrim(e.addr)) = lower(btrim(p_address))
       )
    union all
    select 'landlord_user', m.user_id, 'authoritative_record'
      from public.account_members m
      join auth.users u on u.id = m.user_id
     where p_channel = 'email'
       and m.account_id = p_account_id
       and m.deleted_at is null
       and m.role in ('owner', 'manager')
       and lower(btrim(u.email)) = lower(btrim(p_address))
  ),
  ranked as (
    select c.party_type, c.party_id, c.tier,
           array_position(
             array['human_link', 'authoritative_record', 'verified_claim',
                   'provider_learned', 'legacy'],
             c.tier) as rank
      from cand c
     where p_party_types is null or c.party_type = any (p_party_types)
  )
  select distinct r.party_type, r.party_id, r.tier
    from ranked r
   where r.rank = (select min(r2.rank) from ranked r2)
$$;


ALTER FUNCTION "public"."_comm_resolve_identity_claims"("p_account_id" "uuid", "p_channel" "text", "p_address" "text", "p_tenancy_id" "uuid", "p_thread_id" "uuid", "p_party_types" "text"[]) OWNER TO "postgres";

--
-- Name: _comm_resolve_parent_recipient("uuid", "uuid", "uuid", "jsonb", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_resolve_parent_recipient"("p_account_id" "uuid", "p_thread_id" "uuid", "p_tenancy_id" "uuid", "p_snapshot" "jsonb", "p_address" "text", OUT "o_party_type" "text", OUT "o_party_id" "uuid", OUT "o_tier" "text") RETURNS "record"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_pt      text;
  v_pid     uuid;
  v_src     text;
  v_claim_n int;
  v_claim_t text;
begin
  -- Tier: explicit thread participant on a thread-bound parent.
  if p_thread_id is not null then
    select p.party_type, p.party_id into o_party_type, o_party_id
      from public.thread_channel_bindings b
      join public.comm_thread_participants p on p.id = b.participant_id
     where b.account_id = p_account_id
       and b.thread_id  = p_thread_id
       and b.channel    = 'email'
       and b.participant_address = p_address
       and b.active
     limit 1;
    if o_party_type is not null then
      o_tier := 'thread_participant';
      return;
    end if;
  end if;

  -- Tier: authoritative context, RECOMPUTED from the physical parent row
  -- (its tenancy members, then the account's owner/manager users).
  select h.o_party_type, h.o_party_id into o_party_type, o_party_id
    from public._comm_resolve_context_party(
           p_account_id, p_tenancy_id, 'email', p_address) h;
  if o_party_type is not null then
    o_tier := case when o_party_type = 'tenant'
                then 'tenancy_member' else 'account_member' end;
    return;
  end if;

  -- The live claims verdict for this address in the parent's scope, computed
  -- once and consulted on both sides of the snapshot.
  select count(distinct (r.party_type, r.party_id)), min(r.tier)
    into v_claim_n, v_claim_t
    from public._comm_resolve_identity_claims(
           p_account_id, 'email', p_address, p_tenancy_id, p_thread_id) r;

  -- Tier: a human/authoritative/verified claim outranks the frozen snapshot.
  if v_claim_n > 0
     and v_claim_t in ('human_link', 'authoritative_record', 'verified_claim') then
    if v_claim_n > 1 then
      o_tier := 'claim_conflict';
      return;
    end if;
    select r.party_type, r.party_id into o_party_type, o_party_id
      from public._comm_resolve_identity_claims(
             p_account_id, 'email', p_address, p_tenancy_id, p_thread_id) r
     limit 1;
    o_tier := 'verified_identity';
    return;
  end if;

  -- The frozen snapshot entry for this address, if any.
  select e.entry->>'party_type',
         nullif(e.entry->>'party_id', '')::uuid,
         e.entry->>'resolution_source'
    into v_pt, v_pid, v_src
    from jsonb_array_elements(coalesce(p_snapshot, '[]'::jsonb)) e(entry)
   where e.entry->>'address' = p_address
     and e.entry->>'party_type' <> 'unknown'
     and nullif(e.entry->>'party_id', '') is not null
   limit 1;

  -- Tier: an authoritatively-sourced frozen snapshot (context, a human/
  -- authoritative claim, or an explicit caller-stated party that existed at
  -- intent time, even if it changed since).
  if v_pt is not null
     and v_src in ('thread_participant', 'tenancy_member', 'account_member',
                   'human_link', 'authoritative_record', 'caller_intent') then
    o_party_type := v_pt; o_party_id := v_pid; o_tier := 'snapshot_frozen';
    return;
  end if;

  -- Tier: legacy/learned snapshot — frozen belief, not authority.
  if v_pt is not null then
    o_party_type := v_pt; o_party_id := v_pid; o_tier := 'snapshot_learned';
    return;
  end if;

  -- Tier: live learned/legacy claims (the address book).
  if v_claim_n > 1 then
    o_tier := 'claim_conflict';
    return;
  end if;
  if v_claim_n = 1 then
    select r.party_type, r.party_id into o_party_type, o_party_id
      from public._comm_resolve_identity_claims(
             p_account_id, 'email', p_address, p_tenancy_id, p_thread_id) r
     limit 1;
    o_tier := 'learned_identity';
  end if;
end;
$$;


ALTER FUNCTION "public"."_comm_resolve_parent_recipient"("p_account_id" "uuid", "p_thread_id" "uuid", "p_tenancy_id" "uuid", "p_snapshot" "jsonb", "p_address" "text", OUT "o_party_type" "text", OUT "o_party_id" "uuid", OUT "o_tier" "text") OWNER TO "postgres";

--
-- Name: _comm_resolve_parent_sender("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_resolve_parent_sender"("p_account_id" "uuid", "p_parent_id" "uuid", "p_from_address" "text") RETURNS TABLE("recipient_role" "text", "address" "text", "party_type" "text", "party_id" "uuid", "tier" "text")
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_parent public.comm_outbox%rowtype;
  v_canon  text := lower(btrim(p_from_address));
  r        record;
begin
  select * into v_parent
    from public.comm_outbox o
   where o.id = p_parent_id
     and o.account_id = p_account_id;
  if not found then
    return;
  end if;

  for r in
    select 'to'::text as rcpt_role, v_parent.to_address as addr
     where v_parent.to_address is not null
    union all
    select 'cc', cc.addr
      from unnest(coalesce(v_parent.cc_addresses, '{}'::text[])) cc(addr)
  loop
    if lower(btrim(r.addr)) = v_canon then
      recipient_role := r.rcpt_role;
      address        := r.addr;
      select h.o_party_type, h.o_party_id, h.o_tier
        into party_type, party_id, tier
        from public._comm_resolve_parent_recipient(
               p_account_id, v_parent.thread_id, v_parent.tenancy_id,
               v_parent.recipient_snapshot, r.addr) h;
      return next;
    end if;
  end loop;
end;
$$;


ALTER FUNCTION "public"."_comm_resolve_parent_sender"("p_account_id" "uuid", "p_parent_id" "uuid", "p_from_address" "text") OWNER TO "postgres";

--
-- Name: _comm_resolve_persona_candidates("uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_resolve_persona_candidates"("p_account_id" "uuid", "p_from_address" "text") RETURNS TABLE("party_type" "text", "party_id" "uuid", "source" "text")
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select r.party_type, r.party_id, r.tier
    from public._comm_resolve_identity_claims(p_account_id, 'email', p_from_address) r
$$;


ALTER FUNCTION "public"."_comm_resolve_persona_candidates"("p_account_id" "uuid", "p_from_address" "text") OWNER TO "postgres";

--
-- Name: _comm_threads_guard_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_comm_threads_guard_update"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if new.mode is distinct from old.mode
     or new.group_routing_key is distinct from old.group_routing_key
     or new.channel is distinct from old.channel
     or new.subject is distinct from old.subject then
    raise exception 'comm_threads.mode, group_routing_key, channel and subject are immutable'
      using errcode = 'check_violation';
  end if;
  return new;
end;
$$;


