--
-- Name: _emit_event(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_emit_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_account_id   uuid;
  v_entity_type  text := TG_TABLE_NAME;
  v_entity_id    uuid;
  v_event_type   text;
  v_payload      jsonb;
  v_actor        text;
  v_authed_uid   uuid;
  v_occurred_at  timestamptz := clock_timestamp();
  v_prev_hash    bytea;
  v_account_seq  bigint;
  v_canonical    jsonb;
  v_hash         bytea;
  v_genesis      bytea := decode(repeat('00', 32), 'hex');
begin
  if TG_TABLE_NAME = 'accounts' then
    v_account_id := case TG_OP when 'DELETE' then OLD.id else NEW.id end;
  else
    v_account_id := case TG_OP when 'DELETE' then OLD.account_id else NEW.account_id end;
  end if;

  if TG_TABLE_NAME = 'unit_details' then
    v_entity_id := case TG_OP when 'DELETE' then OLD.area_id else NEW.area_id end;
  else
    v_entity_id := case TG_OP when 'DELETE' then OLD.id else NEW.id end;
  end if;

  if TG_OP = 'INSERT' then
    v_event_type := 'inserted';
    v_payload    := jsonb_build_object('after', to_jsonb(NEW));
  elsif TG_OP = 'UPDATE' then
    if (to_jsonb(OLD) ? 'deleted_at') and (to_jsonb(NEW) ? 'deleted_at') then
      if      (to_jsonb(OLD) ->> 'deleted_at') is null     and (to_jsonb(NEW) ->> 'deleted_at') is not null then
        v_event_type := 'deleted';
      elsif   (to_jsonb(OLD) ->> 'deleted_at') is not null and (to_jsonb(NEW) ->> 'deleted_at') is null     then
        v_event_type := 'restored';
      else
        v_event_type := 'updated';
      end if;
    else
      v_event_type := 'updated';
    end if;
    v_payload := jsonb_build_object('before', to_jsonb(OLD), 'after', to_jsonb(NEW));
  else
    v_event_type := 'hard_deleted';
    v_payload    := jsonb_build_object('before', to_jsonb(OLD));
  end if;

  v_authed_uid := auth.uid();
  if v_authed_uid is not null then
    v_actor := 'user:' || v_authed_uid::text;
  else
    begin
      v_actor := nullif(current_setting('audit.actor', true), '');
    exception when others then
      v_actor := null;
    end;
    v_actor := coalesce(v_actor, 'system');
  end if;

  perform pg_advisory_xact_lock(
    hashtextextended('events_chain:' || v_account_id::text, 0)
  );

  select event_hash, account_seq
  into v_prev_hash, v_account_seq
  from public.events
  where account_id = v_account_id
  order by account_seq desc
  limit 1;

  if v_account_seq is null then
    v_account_seq := 1;
    v_prev_hash   := v_genesis;
  else
    v_account_seq := v_account_seq + 1;
  end if;

  v_canonical := jsonb_build_object(
    'account_id',  v_account_id,
    'account_seq', v_account_seq,
    'entity_id',   v_entity_id,
    'entity_type', v_entity_type,
    'event_type',  v_event_type,
    'occurred_at', v_occurred_at,
    'payload',     v_payload,
    'prev',        encode(v_prev_hash, 'hex')
  );
  v_hash := digest(v_canonical::text, 'sha256');

  insert into public.events (
    account_id, account_seq, actor, entity_type, entity_id, event_type, payload,
    occurred_at, prev_event_hash, event_hash
  ) values (
    v_account_id, v_account_seq, v_actor, v_entity_type, v_entity_id, v_event_type, v_payload,
    v_occurred_at, v_prev_hash, v_hash
  );

  return null;
end;
$$;


ALTER FUNCTION "public"."_emit_event"() OWNER TO "postgres";

--
-- Name: _end_rent_schedules_on_tenancy_end(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_end_rent_schedules_on_tenancy_end"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_end date;
  v_kind text;
begin
  if NEW.status = 'ended' and OLD.status is distinct from NEW.status then
    v_end := coalesce(NEW.end_date, current_date);

    select te.kind
      into v_kind
      from public.tenancy_endings te
     where te.account_id = NEW.account_id
       and te.tenancy_id = NEW.id;

    if v_kind = 'cancelled_before_move_in' then
      update public.rent_schedules s
         set deleted_at = now(),
             updated_at = now()
       where s.account_id = NEW.account_id
         and s.tenancy_id = NEW.id
         and s.deleted_at is null
         and not exists (
           select 1
             from public.charges ch
            where ch.account_id = s.account_id
              and ch.source_schedule_id = s.id
              and ch.voided_at is null
              and ch.deleted_at is null
         );
    else
      update public.rent_schedules s
         set end_date = v_end,
             updated_at = now()
       where s.account_id = NEW.account_id
         and s.tenancy_id = NEW.id
         and s.deleted_at is null
         and s.start_date <= v_end
         and (s.end_date is null or s.end_date > v_end);

      update public.rent_schedules s
         set deleted_at = now(),
             updated_at = now()
       where s.account_id = NEW.account_id
         and s.tenancy_id = NEW.id
         and s.deleted_at is null
         and s.start_date > v_end
         and not exists (
           select 1
             from public.charges ch
            where ch.account_id = s.account_id
              and ch.source_schedule_id = s.id
              and ch.voided_at is null
              and ch.deleted_at is null
         );
    end if;
  end if;

  return NEW;
end;
$$;


ALTER FUNCTION "public"."_end_rent_schedules_on_tenancy_end"() OWNER TO "postgres";

--
-- Name: _enforce_agent_capacity(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_enforce_agent_capacity"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if auth.uid() is null then
    return new;
  end if;

  if coalesce(current_setting('comm.verified_write', true), '') = 'on' then
    return new;
  end if;

  if not exists (
    select 1
      from public.account_members m
     where m.user_id     = auth.uid()
       and m.account_id  = new.account_id
       and m.role        = 'agent'
       and m.deleted_at  is null
  ) then
    return new;
  end if;

  if new.author_type is distinct from 'agent' then
    raise exception 'agent principal must write author_type=agent'
      using errcode = 'check_violation';
  end if;

  if new.corrects_id is not null then
    raise exception 'agent principal may not correct or retract journal entries'
      using errcode = 'check_violation';
  end if;

  if new.kind = 'communication' then
    if new.external_ref is null then
      raise exception 'agent-authored communications require external_ref (verifiable message id)'
        using errcode = 'check_violation';
    end if;
    if new.approval_ref is null
       or (new.approved_by is null and new.approval_ref not like 'grant:%') then
      raise exception 'agent-authored communications require approval provenance (approved_by or a grant: approval_ref)'
        using errcode = 'check_violation';
    end if;
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."_enforce_agent_capacity"() OWNER TO "postgres";

--
-- Name: _enforce_attestation_provenance(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_enforce_attestation_provenance"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if new.attestation = 'provider_verified'
     and coalesce(current_setting('comm.verified_write', true), '') <> 'on' then
    raise exception 'attestation=provider_verified requires a verified comms write path'
      using errcode = 'check_violation';
  end if;
  -- Default-fill: after this migration, NULL strictly means "journaled
  -- before the column existed". Every new communication/note that doesn't
  -- state a tier gets the honest default for its shape — a human/system
  -- record of an event is testimony ('attested'), an import-channel row is
  -- 'imported'. agent_event rows stay null (the tier does not apply; the
  -- kind CHECK enforces it). The verified paths set their value explicitly
  -- before this fires.
  if new.attestation is null and new.kind <> 'agent_event' then
    new.attestation := case when new.channel = 'import' then 'imported' else 'attested' end;
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."_enforce_attestation_provenance"() OWNER TO "postgres";

--
-- Name: _enforce_comm_outbox_capacity(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_enforce_comm_outbox_capacity"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_thread_mode text;
begin
  -- Every intent is born 'queued' (outbox-first invariant). Applies to all
  -- inserters; the API never sets status on create, so this only bites a
  -- direct-PostgREST writer trying to birth a row mid-lifecycle.
  if new.status is distinct from 'queued' then
    raise exception 'a comm_outbox intent must be created with status=queued'
      using errcode = 'check_violation';
  end if;

  -- system:<flow> provenance is reserved for core's server tier. Any caller
  -- holding a JWT (auth.uid() set) is a member or agent reaching PostgREST /
  -- the API — never the core server, which writes with the service key.
  -- The comm_outbox_system_pairing CHECK already ties the ref to
  -- author_type='system'; this closes the WHO.
  if (new.approval_ref like 'system:%' or new.author_type = 'system')
     and auth.uid() is not null then
    raise exception 'system provenance is reserved for core-originated sends'
      using errcode = 'check_violation';
  end if;

  -- Group/1:1 shape vs the thread's mode (all inserters). A missing thread is
  -- left to the composite FK to reject.
  if new.thread_id is not null then
    select t.mode into v_thread_mode
      from public.comm_threads t
     where t.id = new.thread_id;
    if v_thread_mode = 'group' then
      if new.group_addresses is null then
        raise exception 'a send into a group thread must be a group send (group_addresses, no to_address)'
          using errcode = 'check_violation';
      end if;
      if new.participant_id is not null or new.relay_of_interaction_id is not null then
        raise exception 'group sends address the whole thread: no participant leg, no relay'
          using errcode = 'check_violation';
      end if;
    elsif new.group_addresses is not null then
      raise exception 'group_addresses requires a group-mode thread'
        using errcode = 'check_violation';
    end if;
  end if;

  -- Admin/service path (no JWT): unconstrained beyond the shape rules above.
  if auth.uid() is null then
    return new;
  end if;

  -- Only constrain agent-role members. Human members are trusted to author
  -- landlord communications (they can write the journal directly too); the
  -- agent is the principal the evidence-honesty shadow defends against.
  -- Mirrors _enforce_agent_capacity's principal test exactly.
  if not exists (
    select 1
      from public.account_members m
     where m.user_id     = auth.uid()
       and m.account_id   = new.account_id
       and m.role         = 'agent'
       and m.deleted_at   is null
  ) then
    return new;
  end if;

  -- An agent may only create AGENT-authored intents. Without this, an agent
  -- could forge a landlord-authored outbox row and launder it into the
  -- journal via complete_send (which trusts outbox.author_type and is exempt
  -- from _enforce_agent_capacity).
  if new.author_type is distinct from 'agent' then
    raise exception 'agent principal must create outbox intents with author_type=agent'
      using errcode = 'check_violation';
  end if;

  return new;
end;
$$;


ALTER FUNCTION "public"."_enforce_comm_outbox_capacity"() OWNER TO "postgres";

--
-- Name: _freeze_attachment_provenance(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_freeze_attachment_provenance"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if TG_OP = 'DELETE' then
    raise exception 'attachments are soft-deleted; hard delete is forbidden'
      using errcode = 'check_violation';
  end if;

  if NEW.id is distinct from OLD.id
     or NEW.account_id is distinct from OLD.account_id
     or NEW.entity_type is distinct from OLD.entity_type
     or NEW.entity_id is distinct from OLD.entity_id
     or NEW.storage_path is distinct from OLD.storage_path
     or NEW.content_hash is distinct from OLD.content_hash
     or NEW.mime_type is distinct from OLD.mime_type
     or NEW.size_bytes is distinct from OLD.size_bytes
     or NEW.filename is distinct from OLD.filename
     or NEW.uploaded_by is distinct from OLD.uploaded_by
     or NEW.derived_from is distinct from OLD.derived_from
     or NEW.received_at is distinct from OLD.received_at
     or NEW.created_at is distinct from OLD.created_at then
    raise exception 'attachment evidence identity is immutable'
      using errcode = 'check_violation';
  end if;
  -- Only updated_at + deleted_at may advance together through a soft delete.
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_freeze_attachment_provenance"() OWNER TO "postgres";

