  if coalesce(current_setting('app.tenancy_end_workflow', true), '') <> '1' then
    raise exception 'tenancy endings must be created through end_tenancy()'
      using errcode = 'check_violation';
  end if;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_guard_tenancy_ending_insert"() OWNER TO "postgres";

--
-- Name: _inbound_provenance_guard_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_inbound_provenance_guard_update"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if new.account_id          is distinct from old.account_id
     or new.provider            is distinct from old.provider
     or new.provider_msg_id     is distinct from old.provider_msg_id
     or new.body_sha256         is distinct from old.body_sha256
     or new.signature           is distinct from old.signature
     or new.signature_timestamp is distinct from old.signature_timestamp
     or new.storage_path        is distinct from old.storage_path
     or new.received_at         is distinct from old.received_at
     or new.created_at          is distinct from old.created_at then
    raise exception 'inbound_provenance rows are write-once (only purged_at may be set)'
      using errcode = 'check_violation';
  end if;
  if new.purged_at is distinct from old.purged_at
     and (old.purged_at is not null or new.purged_at is null) then
    raise exception 'inbound_provenance.purged_at may only transition null -> timestamp'
      using errcode = 'check_violation';
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."_inbound_provenance_guard_update"() OWNER TO "postgres";

