--
-- Name: _persona_find_or_create_thread("uuid", "text", "uuid", "text", "text", "text", "uuid", "text", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_persona_find_or_create_thread"("p_account_id" "uuid", "p_cp_type" "text", "p_cp_id" "uuid", "p_cp_address" "text", "p_subject" "text", "p_reply_domain" "text", "p_landlord_user_id" "uuid" DEFAULT NULL::"uuid", "p_landlord_address" "text" DEFAULT NULL::"text", "p_parent_thread_id" "uuid" DEFAULT NULL::"uuid", "p_parent_tenancy_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("thread_id" "uuid", "cp_participant_id" "uuid", "tenancy_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_thread_id  uuid;
  v_part_id    uuid;
  v_tenancy_id uuid;
  v_ll_id      uuid;
  v_ll_email   text;
  v_ll_part_id uuid;
begin
  -- (a) Parent-named thread: reuse only while active with the party aboard.
  if p_parent_thread_id is not null then
    select t.id, t.tenancy_id into v_thread_id, v_tenancy_id
      from public.comm_threads t
     where t.account_id = p_account_id
       and t.id = p_parent_thread_id
       and t.status = 'active';
    if v_thread_id is not null then
      select p.id into v_part_id
        from public.comm_thread_participants p
       where p.account_id = p_account_id
         and p.thread_id = p_parent_thread_id
         and p.party_type = p_cp_type
         and p.party_id = p_cp_id
         and p.left_at is null
       order by p.created_at
       limit 1;
      if v_part_id is not null then
        thread_id := v_thread_id; cp_participant_id := v_part_id; tenancy_id := v_tenancy_id;
        return next;
        return;
      end if;
    end if;
    v_thread_id := null; v_tenancy_id := null;
    -- Closed thread / departed participant: fall through, but only into the
    -- parent's own tenancy (below) — never an unrelated conversation.
  end if;

  -- A tenant with parent context but no usable tenancy is unroutable here:
  -- the caller triages instead of guessing.
  if p_cp_type = 'tenant'
     and p_parent_thread_id is not null
     and p_parent_tenancy_id is null then
    return;
  end if;

  select b.thread_id, b.participant_id into v_thread_id, v_part_id
    from public.thread_channel_bindings b
    join public.comm_threads t
      on t.account_id = b.account_id and t.id = b.thread_id
    join public.comm_thread_participants p
      on p.id = b.participant_id
   where b.account_id = p_account_id
     and b.channel = 'email'
     and b.active
     and b.participant_address = p_cp_address
     and t.status = 'active'
     and t.mode = 'bridged'
     and p.party_type = p_cp_type
     and p.party_id = p_cp_id
     and p.left_at is null
     and (p_parent_tenancy_id is null or t.tenancy_id = p_parent_tenancy_id)
   order by t.updated_at desc
   limit 1;

  if v_thread_id is not null then
    select t.tenancy_id into v_tenancy_id
      from public.comm_threads t
     where t.account_id = p_account_id and t.id = v_thread_id;
    thread_id := v_thread_id; cp_participant_id := v_part_id; tenancy_id := v_tenancy_id;
    return next;
    return;
  end if;

  if p_reply_domain is null or length(p_reply_domain) < 3 then
    raise exception 'p_reply_domain is required to create a thread'
      using errcode = '22023';
  end if;

  if p_cp_type = 'tenant' then
    if p_parent_tenancy_id is not null then
      -- The parent's tenancy IS the conversation scope. No inference.
      v_tenancy_id := p_parent_tenancy_id;
    else
      select tn.id into v_tenancy_id
        from public.tenancy_tenants tt
        join public.tenancies tn
          on tn.account_id = tt.account_id and tn.id = tt.tenancy_id
       where tt.account_id = p_account_id
         and tt.tenant_id = p_cp_id
         and tt.deleted_at is null
         and tn.deleted_at is null
         and tn.status in ('active', 'holdover')
       order by (tn.status = 'active') desc, tn.start_date desc
       limit 1;
    end if;
  end if;

  insert into public.comm_threads (account_id, kind, mode, channel, subject, tenancy_id)
  values (
    p_account_id,
    case when p_cp_type = 'vendor' then 'vendor' else 'bridged_tenant' end,
    'bridged',
    'email',
    nullif(left(coalesce(p_subject, ''), 998), ''),
    v_tenancy_id
  )
  returning id into v_thread_id;

  insert into public.comm_thread_participants (account_id, thread_id, party_type, party_id)
  values (p_account_id, v_thread_id, p_cp_type, p_cp_id)
  returning id into v_part_id;

  insert into public.thread_channel_bindings
    (account_id, thread_id, participant_id, participant_address, reply_address)
  values (
    p_account_id, v_thread_id, v_part_id, p_cp_address,
    't-' || encode(extensions.gen_random_bytes(16), 'hex') || '@' || lower(p_reply_domain)
  );

  -- Landlord participant: the initiating landlord when known, else the owner.
  v_ll_id := p_landlord_user_id;
  if v_ll_id is null then
    select m.user_id into v_ll_id
      from public.account_members m
     where m.account_id = p_account_id
       and m.role = 'owner'
       and m.deleted_at is null
     order by m.created_at
     limit 1;
  end if;

  if v_ll_id is not null then
    insert into public.comm_thread_participants (account_id, thread_id, party_type, party_id)
    values (p_account_id, v_thread_id, 'landlord_user', v_ll_id)
    returning id into v_ll_part_id;

    v_ll_email := p_landlord_address;
    if v_ll_email is null then
      -- Live claims only; prefer human_link, then verified, then newest.
      select ci.address into v_ll_email
        from public.channel_identities ci
       where ci.account_id = p_account_id
         and ci.channel = 'email'
         and ci.party_type = 'landlord_user'
         and ci.party_id = v_ll_id
         and ci.superseded_at is null
       order by (ci.source = 'human_link') desc,
                (ci.verified_at is not null
                  or ci.source in ('thread_rebind', 'parent_recipient', 'authoritative_import')) desc,
                ci.created_at desc, ci.id
       limit 1;
    end if;

    if v_ll_email is not null then
      insert into public.thread_channel_bindings
        (account_id, thread_id, participant_id, participant_address, reply_address)
      values (
        p_account_id, v_thread_id, v_ll_part_id, v_ll_email,
        't-' || encode(extensions.gen_random_bytes(16), 'hex') || '@' || lower(p_reply_domain)
      );
    end if;
  end if;

  thread_id := v_thread_id; cp_participant_id := v_part_id; tenancy_id := v_tenancy_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."_persona_find_or_create_thread"("p_account_id" "uuid", "p_cp_type" "text", "p_cp_id" "uuid", "p_cp_address" "text", "p_subject" "text", "p_reply_domain" "text", "p_landlord_user_id" "uuid", "p_landlord_address" "text", "p_parent_thread_id" "uuid", "p_parent_tenancy_id" "uuid") OWNER TO "postgres";

--
-- Name: _persona_record_unmatched("uuid", "text", "text", "text", "text", "text", "text"[], "text"[], "text", "text", "jsonb", "text", "text", "text", "text", timestamp with time zone, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_persona_record_unmatched"("p_account_id" "uuid", "p_provider" "text", "p_provider_msg_id" "text", "p_persona_address" "text", "p_from_address" "text", "p_from_display_name" "text", "p_to_addresses" "text"[], "p_cc_addresses" "text"[], "p_subject" "text", "p_body" "text", "p_media" "jsonb", "p_rfc822_message_id" "text", "p_spf" "text", "p_dkim" "text", "p_dmarc" "text", "p_received_at" timestamp with time zone, "p_reason" "text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_id uuid;
begin
  insert into public.comm_unmatched_inbound (
    account_id, provider, provider_msg_id, rfc822_message_id,
    persona_address, from_address, from_display_name,
    to_addresses, cc_addresses, subject, body, media,
    spf, dkim, dmarc, reason, received_at
  ) values (
    p_account_id, p_provider, p_provider_msg_id, p_rfc822_message_id,
    p_persona_address, p_from_address, p_from_display_name,
    coalesce(p_to_addresses, '{}'), coalesce(p_cc_addresses, '{}'),
    nullif(left(coalesce(p_subject, ''), 998), ''),
    left(p_body, 20000),
    coalesce(p_media, '[]'::jsonb),
    p_spf, p_dkim, p_dmarc, p_reason, p_received_at
  )
  on conflict (account_id, provider_msg_id) do nothing
  returning id into v_id;

  if v_id is null then
    select u.id into v_id
      from public.comm_unmatched_inbound u
     where u.account_id = p_account_id
       and u.provider_msg_id = p_provider_msg_id;
  end if;
  return v_id;
end;
$$;


ALTER FUNCTION "public"."_persona_record_unmatched"("p_account_id" "uuid", "p_provider" "text", "p_provider_msg_id" "text", "p_persona_address" "text", "p_from_address" "text", "p_from_display_name" "text", "p_to_addresses" "text"[], "p_cc_addresses" "text"[], "p_subject" "text", "p_body" "text", "p_media" "jsonb", "p_rfc822_message_id" "text", "p_spf" "text", "p_dkim" "text", "p_dmarc" "text", "p_received_at" timestamp with time zone, "p_reason" "text") OWNER TO "postgres";

--
-- Name: _reject_anchored_lease_mutation(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_anchored_lease_mutation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  -- F9: superseded is terminal -- no reactivation. All leases.
  if OLD.status = 'superseded' and NEW.status = 'active' then
    raise exception 'a superseded lease is a historical record; create a new lease instead'
      using errcode = 'check_violation';
  end if;

  -- F7: an anchored lease cannot be soft-deleted.
  if OLD.deleted_at is null and NEW.deleted_at is not null
     and exists (
       select 1
         from public.rent_schedules s
        where s.account_id      = OLD.account_id
          and s.source_lease_id = OLD.id
          and s.deleted_at is null
     )
  then
    raise exception 'lease % is anchored to a rent schedule and cannot be deleted', OLD.id
      using errcode = 'check_violation';
  end if;

  return NEW;
end;
$$;


ALTER FUNCTION "public"."_reject_anchored_lease_mutation"() OWNER TO "postgres";

--
-- Name: _reject_anchored_notice_mutation(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_anchored_notice_mutation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if exists (
    select 1
      from public.rent_schedules s
     where s.account_id       = OLD.account_id
       and s.source_notice_id = OLD.id
       and s.deleted_at is null
  ) then
    if (OLD.deleted_at is null and NEW.deleted_at is not null)
       or NEW.served_at     is distinct from OLD.served_at
       or NEW.served_method is distinct from OLD.served_method
       or NEW.body          is distinct from OLD.body
       or NEW.document      is distinct from OLD.document
       or NEW.notice_type   is distinct from OLD.notice_type
    then
      raise exception 'notice % is anchored to a rent schedule and cannot be modified', OLD.id
        using errcode = 'check_violation';
    end if;
  end if;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_reject_anchored_notice_mutation"() OWNER TO "postgres";

--
-- Name: _reject_attachment_on_completed_inspection(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_attachment_on_completed_inspection"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_completed timestamptz;
begin
  if NEW.entity_type = 'inspections' then
    select completed_at into v_completed
      from public.inspections
      where account_id = NEW.account_id and id = NEW.entity_id;
  elsif NEW.entity_type = 'inspection_items' then
    select i.completed_at into v_completed
      from public.inspection_items it
      join public.inspections i
        on i.account_id = it.account_id and i.id = it.inspection_id
      where it.account_id = NEW.account_id and it.id = NEW.entity_id;
  else
    -- not an inspection-capture attachment (incl. 'inspection_report'): unaffected.
    return NEW;
  end if;

  if v_completed is not null then
    raise exception 'parent inspection is completed; attachments are immutable (%, %)',
      NEW.entity_type, NEW.entity_id
      using errcode = 'check_violation';
  end if;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_reject_attachment_on_completed_inspection"() OWNER TO "postgres";

--
-- Name: _reject_check_update_on_completed_inspection(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_check_update_on_completed_inspection"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
declare
  v_inspection_id uuid;
  v_completed     timestamptz;
begin
  v_inspection_id := case TG_OP when 'DELETE' then OLD.inspection_id else NEW.inspection_id end;
  select completed_at into v_completed
    from public.inspections where id = v_inspection_id;
  if v_completed is not null then
    raise exception 'parent inspection % is completed; checks are immutable', v_inspection_id
      using errcode = 'check_violation';
  end if;
  return case TG_OP when 'DELETE' then OLD else NEW end;
end;
$$;


ALTER FUNCTION "public"."_reject_check_update_on_completed_inspection"() OWNER TO "postgres";

--
-- Name: _reject_classify_overwrite(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_classify_overwrite"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  orig public.interactions;
begin
  if NEW.correction_kind is distinct from 'classify' then
    return NEW;
  end if;

  select * into orig from public.interactions where id = NEW.corrects_id;
  if not found then
    -- The composite FK guarantees the target exists in-account; nothing to
    -- compare against if it somehow does not.
    return NEW;
  end if;

  -- body + occurred_at are inherited, never changed.
  if NEW.body is distinct from orig.body then
    raise exception 'classify cannot change body (use amend)' using errcode = 'check_violation';
  end if;
  if NEW.occurred_at is distinct from orig.occurred_at then
    raise exception 'classify cannot change occurred_at (use amend)' using errcode = 'check_violation';
  end if;

  -- nullable context fields: fill an empty original, never overwrite a set one.
  if orig.party_id is not null and NEW.party_id is distinct from orig.party_id then
    raise exception 'classify cannot overwrite party_id (use amend)' using errcode = 'check_violation';
  end if;
  if orig.party_label is not null and NEW.party_label is distinct from orig.party_label then
    raise exception 'classify cannot overwrite party_label (use amend)' using errcode = 'check_violation';
  end if;
  if orig.tenancy_id is not null and NEW.tenancy_id is distinct from orig.tenancy_id then
    raise exception 'classify cannot overwrite tenancy_id (use amend)' using errcode = 'check_violation';
  end if;
  if orig.maintenance_request_id is not null and NEW.maintenance_request_id is distinct from orig.maintenance_request_id then
    raise exception 'classify cannot overwrite maintenance_request_id (use amend)' using errcode = 'check_violation';
  end if;
  if orig.area_id is not null and NEW.area_id is distinct from orig.area_id then
    raise exception 'classify cannot overwrite area_id (use amend)' using errcode = 'check_violation';
  end if;
  if orig.work_order_id is not null and NEW.work_order_id is distinct from orig.work_order_id then
    raise exception 'classify cannot overwrite work_order_id (use amend)' using errcode = 'check_violation';
  end if;
  if orig.vendor_id is not null and NEW.vendor_id is distinct from orig.vendor_id then
    raise exception 'classify cannot overwrite vendor_id (use amend)' using errcode = 'check_violation';
  end if;
  if orig.references_interaction_id is not null and NEW.references_interaction_id is distinct from orig.references_interaction_id then
    raise exception 'classify cannot overwrite references_interaction_id (use amend)' using errcode = 'check_violation';
  end if;

  -- party_type: 'unspecified'/'none' are empty (fillable); a concrete role is locked.
  if orig.party_type not in ('unspecified', 'none') and NEW.party_type is distinct from orig.party_type then
    raise exception 'classify cannot overwrite party_type (use amend)' using errcode = 'check_violation';
  end if;
  -- direction: 'unspecified'/'none' are empty (fillable); a stated direction is locked.
  if orig.direction not in ('unspecified', 'none') and NEW.direction is distinct from orig.direction then
    raise exception 'classify cannot overwrite direction (use amend)' using errcode = 'check_violation';
  end if;
  -- channel is never empty on a communication => effectively immutable here.
  if NEW.channel is distinct from orig.channel then
    raise exception 'classify cannot change channel (use amend)' using errcode = 'check_violation';
  end if;

  -- atomic resolve: naming a party_id requires resolving the role too
  -- (the table CHECK backstops the inverse: unspecified => party_id IS NULL).
  if NEW.party_id is not null and NEW.party_type = 'unspecified' then
    raise exception 'classify must resolve party_type when setting party_id' using errcode = 'check_violation';
  end if;

  return NEW;
end;
$$;


ALTER FUNCTION "public"."_reject_classify_overwrite"() OWNER TO "postgres";

--
-- Name: _reject_completed_inspection_update(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_completed_inspection_update"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
begin
  if OLD.completed_at is not null then
    if NEW.completed_at               =                  OLD.completed_at
       and NEW.area_id                =                  OLD.area_id
       and NEW.kind                   =                  OLD.kind
       and NEW.capture_mode           =                  OLD.capture_mode
       and NEW.tenancy_id             is not distinct from OLD.tenancy_id
       and NEW.baseline_inspection_id is not distinct from OLD.baseline_inspection_id
       and NEW.template_id            is not distinct from OLD.template_id
       and NEW.performed_by           is not distinct from OLD.performed_by
       and NEW.performed_at           is not distinct from OLD.performed_at
       and NEW.notes                  is not distinct from OLD.notes
       and NEW.template_snapshot      is not distinct from OLD.template_snapshot
       and NEW.subject_snapshot       is not distinct from OLD.subject_snapshot
       and NEW.status                 in ('completed', 'voided')
    then
      -- Only deleted_at / status->voided / voided_at / void_reason /
      -- supersedes_inspection_id / updated_at may differ.
      return NEW;
    end if;
    raise exception 'inspection % is completed and cannot be modified', OLD.id
      using errcode = 'check_violation';
  end if;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_reject_completed_inspection_update"() OWNER TO "postgres";

