--
-- Name: _reject_pinned_inspection_template_change(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_pinned_inspection_template_change"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if TG_OP = 'UPDATE' then
    if OLD.template_snapshot is not null then
      if NEW.template_snapshot is distinct from OLD.template_snapshot then
        raise exception 'inspection % has a pinned template snapshot; template_snapshot cannot be changed', OLD.id
          using errcode = 'check_violation';
      end if;
      if NEW.template_id is distinct from OLD.template_id then
        raise exception 'inspection % has a pinned template snapshot; template_id cannot be changed', OLD.id
          using errcode = 'check_violation';
      end if;
      return NEW;
    end if;
  end if;

  -- Applies to INSERTs that already carry evidence and to the one permitted
  -- null -> nonnull UPDATE. Compare as text so malformed JSON is rejected as a
  -- domain check_violation instead of leaking a UUID-cast error.
  if NEW.template_snapshot is not null
     and (
       jsonb_typeof(NEW.template_snapshot) is distinct from 'object'
       or jsonb_typeof(NEW.template_snapshot->'id') is distinct from 'string'
       or NEW.template_snapshot->>'id' is distinct from NEW.template_id::text
     )
  then
    raise exception 'inspection % template_snapshot.id must match template_id', NEW.id
      using errcode = 'check_violation';
  end if;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_reject_pinned_inspection_template_change"() OWNER TO "postgres";

--
-- Name: _reject_reserved_email_subdomain(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_reserved_email_subdomain"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
begin
  if NEW.email_subdomain ~ '^em[0-9]+$'
     or exists (
       select 1
         from public.reserved_subdomain_labels r
        where r.label = NEW.email_subdomain
     )
  then
    raise exception 'email_subdomain "%" is a reserved label', NEW.email_subdomain
      using errcode = '23514';
  end if;
  return NEW;
end;
$_$;


ALTER FUNCTION "public"."_reject_reserved_email_subdomain"() OWNER TO "postgres";

--
-- Name: _reject_schedule_delete_with_live_charges(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_schedule_delete_with_live_charges"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  -- Only the soft-delete transition is guarded. end_date edits, re-opens
  -- (end_date -> null), amount-preserving column writes and the RPC's own era
  -- rotation all pass through untouched.
  if OLD.deleted_at is null and NEW.deleted_at is not null then
    if exists (
      select 1
        from public.charges ch
       where ch.account_id         = OLD.account_id
         and ch.source_schedule_id = OLD.id
         and ch.voided_at is null
         and ch.deleted_at is null
    ) then
      raise exception 'rent schedule % has live charges and cannot be deleted; void them first', OLD.id
        using errcode = 'check_violation';
    end if;
  end if;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_reject_schedule_delete_with_live_charges"() OWNER TO "postgres";

--
-- Name: _reject_tenancy_ending_mutation(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_reject_tenancy_ending_mutation"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  raise exception 'tenancy ending facts are immutable'
    using errcode = 'check_violation';
end;
$$;


ALTER FUNCTION "public"."_reject_tenancy_ending_mutation"() OWNER TO "postgres";

--
-- Name: _rent_schedules_guard(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_rent_schedules_guard"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  -- (1) serialize every schedule write for this tenancy with the RPC.
  perform pg_advisory_xact_lock(hashtextextended('rent_change:' || NEW.tenancy_id::text, 0));

  -- (2a) lease anchor must belong to the SAME tenancy (composite FK only proves
  --      same account). check_violation -> route maps to 400 invalid_request.
  if NEW.source_lease_id is not null then
    if not exists (
      select 1
        from public.leases l
       where l.account_id = NEW.account_id
         and l.id         = NEW.source_lease_id
         and l.tenancy_id = NEW.tenancy_id
         and l.deleted_at is null
    ) then
      raise exception 'source_lease_id must reference a lease of the same tenancy'
        using errcode = 'check_violation';
    end if;
  end if;

  -- (2b) notice anchor must belong to the SAME tenancy.
  if NEW.source_notice_id is not null then
    if not exists (
      select 1
        from public.notices n
       where n.account_id = NEW.account_id
         and n.id         = NEW.source_notice_id
         and n.tenancy_id = NEW.tenancy_id
         and n.deleted_at is null
    ) then
      raise exception 'source_notice_id must reference a notice of the same tenancy'
        using errcode = 'check_violation';
    end if;
  end if;

  return NEW;
end;
$$;


ALTER FUNCTION "public"."_rent_schedules_guard"() OWNER TO "postgres";

--
-- Name: _revoke_intake_on_tenancy_end(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_revoke_intake_on_tenancy_end"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  if TG_OP = 'UPDATE' and (
        (NEW.status = 'ended' and OLD.status is distinct from 'ended')
     or (NEW.deleted_at is not null and OLD.deleted_at is null)
  ) then
    update public.intake_tokens
       set revoked_at = now(),
           updated_at = now()
     where tenancy_id = NEW.id
       and revoked_at is null;
  end if;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_revoke_intake_on_tenancy_end"() OWNER TO "postgres";

--
-- Name: _stamp_inspection_link_delivered(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_stamp_inspection_link_delivered"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
begin
  update public.inspections
     set link_delivered_at = NEW.created_at, updated_at = now()
   where account_id = NEW.account_id and id = NEW.inspection_id
     and link_delivered_at is null and completed_at is null;
  return NEW;
end;
$$;


ALTER FUNCTION "public"."_stamp_inspection_link_delivered"() OWNER TO "postgres";

--
-- Name: _storage_path_account_id("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_storage_path_account_id"("p_name" "text") RETURNS "uuid"
    LANGUAGE "sql" IMMUTABLE
    AS $_$
  select
    case
      when length(p_name) >= 37 and substr(p_name, 37, 1) = '/'
      then (
        case
          when substr(p_name, 1, 36) ~* '^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$'
          then substr(p_name, 1, 36)::uuid
          else null
        end
      )
      else null
    end;
$_$;


ALTER FUNCTION "public"."_storage_path_account_id"("p_name" "text") OWNER TO "postgres";

--
-- Name: _tenant_email_conflicts("uuid", "text"[], "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_tenant_email_conflicts"("p_account_id" "uuid", "p_emails" "text"[], "p_exclude_tenant_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("email" "text", "holder_kind" "text", "holder_id" "uuid", "holder_name" "text")
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with wanted as (
    select distinct lower(btrim(e)) as norm
      from unnest(p_emails) as e
     where btrim(e) <> ''
  )
  -- Tier 1: other live tenants in the same account (grandfathered dupes still
  -- count — a persisting duplicate row IS a live holder).
  select distinct
         w.norm            as email,
         'tenant'::text    as holder_kind,
         t.id              as holder_id,
         t.full_name       as holder_name
    from public.tenants t
    cross join lateral unnest(t.emails) as te(addr)
    join wanted w on w.norm = lower(btrim(te.addr))
   where t.account_id = p_account_id
     and t.deleted_at is null
     and (p_exclude_tenant_id is null or t.id <> p_exclude_tenant_id)

  union all

  -- Tier 2: owner/manager login emails (never 'agent' — an agent principal is
  -- not a landlord identity the comms layer maps to landlord_user).
  select distinct
         w.norm                 as email,
         'account_user'::text   as holder_kind,
         m.user_id              as holder_id,
         coalesce(nullif(btrim(pu.display_name), ''), au.email) as holder_name
    from public.account_members m
    join auth.users au on au.id = m.user_id
    join wanted    w  on w.norm = lower(btrim(au.email))
    left join public.users pu on pu.id = m.user_id
   where m.account_id = p_account_id
     and m.deleted_at is null
     and m.role in ('owner', 'manager')
$$;


ALTER FUNCTION "public"."_tenant_email_conflicts"("p_account_id" "uuid", "p_emails" "text"[], "p_exclude_tenant_id" "uuid") OWNER TO "postgres";

--
-- Name: _tenant_stamp_form_started("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

