     set form_started_at = now(), updated_at = now()
   where account_id = p_account_id and id = p_inspection_id
     and form_started_at is null and completed_at is null;
end;
$$;


ALTER FUNCTION "public"."_tenant_stamp_form_started"("p_account_id" "uuid", "p_inspection_id" "uuid") OWNER TO "postgres";

--
-- Name: _tenants_email_uniqueness_guard(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_tenants_email_uniqueness_guard"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_dup      text;
  v_conflict record;
begin
  -- (1) Intra-array duplicate after normalization.
  select lower(btrim(e))
    into v_dup
    from unnest(NEW.emails) as e
   where btrim(e) <> ''
   group by lower(btrim(e))
  having count(*) > 1
   limit 1;
  if v_dup is not null then
    raise exception 'tenant emails contains duplicate address "%"', v_dup
      using errcode = '23505';
  end if;

  -- (2) Tenant-holder conflict (account_user collisions are API-level only).
  select c.email,
         string_agg(distinct c.holder_name, ', ') as holders
    into v_conflict
    from public._tenant_email_conflicts(NEW.account_id, NEW.emails, NEW.id) c
   where c.holder_kind = 'tenant'
   group by c.email
   order by c.email
   limit 1;

  if v_conflict.email is not null then
    raise exception 'email "%" already belongs to %', v_conflict.email, v_conflict.holders
      using errcode = '23505';
  end if;

  return NEW;
end;
$$;


ALTER FUNCTION "public"."_tenants_email_uniqueness_guard"() OWNER TO "postgres";

--
-- Name: _thread_binding_stamp_mode(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."_thread_binding_stamp_mode"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_mode    text;
  v_channel text;
begin
  if tg_op = 'UPDATE' then
    if new.thread_mode is distinct from old.thread_mode
       or new.channel is distinct from old.channel
       or new.reply_address is distinct from old.reply_address then
      raise exception 'thread_channel_bindings.thread_mode, channel and reply_address are immutable'
        using errcode = 'check_violation';
    end if;
    return new;
  end if;
  select t.mode, t.channel into v_mode, v_channel
    from public.comm_threads t
   where t.id = new.thread_id and t.account_id = new.account_id;
  new.thread_mode := coalesce(v_mode, 'bridged');
  new.channel     := coalesce(v_channel, 'sms');
  return new;
end;
$$;


ALTER FUNCTION "public"."_thread_binding_stamp_mode"() OWNER TO "postgres";

--
-- Name: advance_tenancy_statuses(timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."advance_tenancy_statuses"("p_as_of" timestamp with time zone DEFAULT "now"()) RETURNS TABLE("o_tenancy_id" "uuid", "o_account_id" "uuid", "o_start_date" "date")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor text := 'system:cron:tenancy';
begin
  perform set_config('audit.actor', v_actor, true);

  return query
    update public.tenancies t
       set status = 'active',
           updated_at = now()
     where t.status = 'upcoming'
       and t.deleted_at is null
       and t.start_date <= p_as_of::date
    returning t.id, t.account_id, t.start_date;
end;
$$;


ALTER FUNCTION "public"."advance_tenancy_statuses"("p_as_of" timestamp with time zone) OWNER TO "postgres";

--
-- Name: bump_ip_rate_bucket("text", "text", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."bump_ip_rate_bucket"("p_ip" "text", "p_scope" "text", "p_window_sec" integer) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_count int;
begin
  insert into public.ip_rate_buckets (ip, scope, count, window_start)
    values (p_ip, p_scope, 1, now())
  on conflict (ip, scope) do update
    set count = case
                  when now() - public.ip_rate_buckets.window_start > make_interval(secs => p_window_sec)
                  then 1
                  else public.ip_rate_buckets.count + 1
                end,
        window_start = case
                  when now() - public.ip_rate_buckets.window_start > make_interval(secs => p_window_sec)
                  then now()
                  else public.ip_rate_buckets.window_start
                end,
        updated_at = now()
  returning count into v_count;
  return v_count;
end;
$$;


ALTER FUNCTION "public"."bump_ip_rate_bucket"("p_ip" "text", "p_scope" "text", "p_window_sec" integer) OWNER TO "postgres";

--
-- Name: capture_inbound("uuid", "text", "text", "text", "text", "text", "text", "jsonb", timestamp with time zone, "text"[], "text", "text", "text", "text"[], "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."capture_inbound"("p_account_id" "uuid", "p_provider" "text", "p_provider_msg_id" "text", "p_to_number" "text", "p_from_address" "text", "p_channel" "text", "p_body" "text", "p_media" "jsonb", "p_received_at" timestamp with time zone, "p_cc" "text"[] DEFAULT NULL::"text"[], "p_subject" "text" DEFAULT NULL::"text", "p_rfc822_message_id" "text" DEFAULT NULL::"text", "p_in_reply_to" "text" DEFAULT NULL::"text", "p_references" "text"[] DEFAULT NULL::"text"[], "p_auth_results" "jsonb" DEFAULT NULL::"jsonb") RETURNS TABLE("disposition" "text", "interaction_id" "uuid", "thread_id" "uuid", "participant_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_raw          public.inbound_raw%rowtype;
  v_binding      record;
  v_rebound      record;
  v_participant  public.comm_thread_participants%rowtype;
  v_interaction  public.interactions%rowtype;
  v_disposition  text;
  v_party_type   text;
  v_party_id     uuid;
  v_party_label  text;
  v_author_type  text;
  v_group_thread uuid;
  v_matched      boolean := false;
  v_mismatch     boolean := false;
  -- Self-enforcing (defense in depth): the header fields are email-only. Only
  -- normalize/keep the Message-ID on an email capture so a direct PostgREST
  -- caller cannot smuggle one onto an sms/group message past the API tier.
  v_msgid        text := case when p_channel = 'email'
                              then public._comm_normalize_msgid(p_rfc822_message_id)
                              else null end;
  v_dup_id       uuid;
  r              record;
begin
  -- Self-defense: transport (agent-role member of this account) only.
  if auth.uid() is null or not exists (
    select 1 from public.account_members m
     where m.user_id = auth.uid()
       and m.account_id = p_account_id
       and m.role = 'agent'
       and m.deleted_at is null
  ) then
    raise exception 'not authorized to capture inbound messages for this account'
      using errcode = '42501';
  end if;

  -- Idempotent replay: answered from the cached match result, PINNED to the
  -- calling account so one account can never read another's cached ids.
  select * into v_raw
    from public.inbound_raw
   where provider_msg_id = p_provider_msg_id
     and matched_account_id = p_account_id;
  if found then
    disposition    := v_raw.disposition;
    interaction_id := v_raw.matched_interaction_id;
    thread_id      := v_raw.matched_thread_id;
    participant_id := v_raw.matched_participant_id;
    return next;
    return;
  end if;

  -- Capture first. matched_account_id is stamped at birth so the replay/dedupe
  -- is account-scoped from the outset. provider_msg_id is globally UNIQUE, so
  -- a collision means the message was already captured — by this account (a
  -- race → return the committed result) or another (a misroute/probe →
  -- refuse, never leak).
  begin
    insert into public.inbound_raw (
      provider, provider_msg_id, payload, received_at, matched_account_id,
      rfc822_message_id
    )
    values (
      p_provider,
      p_provider_msg_id,
      jsonb_build_object(
        'to_number', p_to_number, 'from_address', p_from_address,
        'channel', p_channel, 'body', p_body, 'media', coalesce(p_media, '[]'::jsonb),
        'cc', coalesce(to_jsonb(p_cc), '[]'::jsonb),
        'account_id', p_account_id,
        -- Header fields are email-only: null them on non-email channels so a
        -- direct PostgREST caller can't attach headers past the API tier.
        'subject', case when p_channel = 'email' then p_subject else null end,
        'rfc822_message_id', v_msgid,
        'in_reply_to', case when p_channel = 'email'
                            then public._comm_normalize_msgid(p_in_reply_to)
                            else null end,
        'references', case when p_channel = 'email' then coalesce(
          (select jsonb_agg(public._comm_normalize_msgid(x))
             from unnest(p_references) x
            where public._comm_normalize_msgid(x) is not null),
          '[]'::jsonb) else '[]'::jsonb end,
        'auth_results', case when p_channel = 'email'
                             then coalesce(p_auth_results, 'null'::jsonb)
                             else 'null'::jsonb end
      ),
      p_received_at,
      p_account_id,
      v_msgid
    )
    returning * into v_raw;
  exception when unique_violation then
    select * into v_raw
      from public.inbound_raw
     where provider_msg_id = p_provider_msg_id;
    if v_raw.matched_account_id is distinct from p_account_id then
      raise exception 'provider_msg_id already captured for another account'
        using errcode = 'P0003';
    end if;
    disposition    := v_raw.disposition;
    interaction_id := v_raw.matched_interaction_id;
    thread_id      := v_raw.matched_thread_id;
    participant_id := v_raw.matched_participant_id;
    return next;
    return;
  end;

  if p_channel = 'email' then
    -- Email: the to-address IS the minted reply token (handler lowercases).
    -- cc has no email semantics in v1 and is ignored for routing.
    select b.thread_id as b_thread_id, b.participant_id as b_participant_id,
           b.participant_address as b_participant_address
      into v_binding
      from public.thread_channel_bindings b
     where b.reply_address = p_to_number
       and b.channel = 'email'
       and b.active
       and b.account_id = p_account_id;
    v_matched := found;
    -- The token is the routing key; the sender address is a verification.
    -- Bound participant addresses are stored trim+lowercased at creation.
    if v_matched and lower(btrim(p_from_address)) is distinct from v_binding.b_participant_address then
      v_mismatch := true;
      -- Cross-participant re-attribution (landlord CC arm — see the section
      -- header): the sender may be ANOTHER participant of this same thread
      -- replying to a copy addressed to someone else's token. Verify the
      -- sender address against the thread's other ACTIVE email bindings whose
      -- participant is still present; on a hit, the message is THAT
      -- participant's — re-attribute and proceed as matched.
      select b.thread_id as b_thread_id, b.participant_id as b_participant_id,
             b.participant_address as b_participant_address
        into v_rebound
        from public.thread_channel_bindings b
        join public.comm_thread_participants p
          on p.id = b.participant_id
         and p.left_at is null
       where b.account_id = p_account_id
         and b.thread_id = v_binding.b_thread_id
         and b.channel = 'email'
         and b.active
         and b.participant_address = lower(btrim(p_from_address))
       limit 1;
      if found then
        v_binding  := v_rebound;
        v_mismatch := false;
      end if;
    end if;
  elsif p_cc is not null and array_length(p_cc, 1) > 0 then
    -- Group message: resolve by participant-set match, pinned to the calling
    -- account (a foreign account's identical set can never leak a thread).
    select t.id into v_group_thread
      from public.comm_threads t
     where t.account_id = p_account_id
       and t.mode = 'group'
       and t.status = 'active'
       and t.group_routing_key = public._comm_group_routing_key(
             p_to_number, array_append(p_cc, p_from_address));

    if v_group_thread is not null then
      select b.thread_id as b_thread_id, b.participant_id as b_participant_id
        into v_binding
        from public.thread_channel_bindings b
       where b.account_id = p_account_id
         and b.thread_id = v_group_thread
         and b.participant_address = p_from_address
         and b.active;
      v_matched := found;
    end if;
  else
    -- 1:1 sms: the active BRIDGED binding for (platform number, counterparty
    -- address), pinned to the calling account.
    select b.thread_id as b_thread_id, b.participant_id as b_participant_id
      into v_binding
      from public.thread_channel_bindings b
     where b.platform_number = p_to_number
       and b.participant_address = p_from_address
       and b.active
       and b.thread_mode = 'bridged'
       and b.account_id = p_account_id;
    v_matched := found;
  end if;

  if not v_matched then
    update public.inbound_raw
       set disposition = 'orphan'
     where id = v_raw.id;
    disposition    := 'orphan';
    interaction_id := null;
    thread_id      := null;
    participant_id := null;
    return next;
    return;
  end if;

  -- Same-thread duplicate: this email (by its own Message-ID, not the
  -- provider receipt id) already journaled into the thread this binding
  -- routes to — the "two-door" delivery (token + persona/CC copies of one
  -- send). Cache the ORIGINAL ids on the raw row so replays answer
  -- identically; write nothing else.
  --
  -- Gated on a VERIFIED sender (not v_mismatch): a mismatched sender must
  -- ALWAYS journal as sender_mismatch, even when citing an already-journaled
  -- Message-ID — otherwise an attacker replying from a wrong address with a
  -- known thread Message-ID gets 'duplicate' and the durable sender_mismatch
  -- row the unresolved-sender queue depends on is never written. Evidence
  -- beats dedupe.
  if v_msgid is not null and not v_mismatch then
    select i.id into v_dup_id
      from public.interactions i
     where i.account_id = p_account_id
       and i.rfc822_message_id = v_msgid
       and i.thread_id = v_binding.b_thread_id
     limit 1;
    if v_dup_id is not null then
      update public.inbound_raw
         set disposition            = 'duplicate',
             matched_account_id     = p_account_id,
             matched_thread_id      = v_binding.b_thread_id,
             matched_participant_id = v_binding.b_participant_id,
             matched_interaction_id = v_dup_id
       where id = v_raw.id;
      disposition    := 'duplicate';
      interaction_id := v_dup_id;
      thread_id      := v_binding.b_thread_id;
      participant_id := v_binding.b_participant_id;
      return next;
      return;
    end if;
  end if;

  select * into v_participant
    from public.comm_thread_participants p
   where p.id = v_binding.b_participant_id;

  -- Capacity attribution follows the CHANNEL SLOT the message arrived on
  -- (the participant's minted token / bound address); identity attribution
  -- (the party fields) is downgraded to 'unspecified' + the actual sender
  -- when the sender address does not verify.
  v_author_type := case v_participant.party_type
    when 'tenant' then 'tenant'
    when 'vendor' then 'vendor'
    when 'landlord_user' then 'landlord'
    else 'system'
  end;
  if v_mismatch then
    v_party_type  := 'unspecified';
    v_party_id    := null;
    v_party_label := p_from_address;
  else
    v_party_type := case v_participant.party_type
      when 'tenant' then 'tenant'
      when 'vendor' then 'vendor'
      else 'other'
    end;
    v_party_id    := v_participant.party_id;
    -- Headline label for legacy-vocab 'other' rows (landlord_user/agent
    -- participants): the person's display name, not their role string.
    v_party_label := case
      when v_party_type = 'other' then
        coalesce(
          public._party_display_name(p_account_id, v_participant.party_type, v_participant.party_id),
          v_participant.party_type)
      else null
    end;
  end if;

  v_disposition := case
    when v_mismatch then 'sender_mismatch'
    when exists (
      select 1 from public.comm_opt_outs oo
       where oo.channel = p_channel and oo.address = p_from_address
    ) then 'opted_out'
    else 'matched'
  end;

  -- Journal the contact (it happened, verified or not, opted-out or not).
  -- Mechanical writer attribution follows the intake pattern: audit.actor is
  -- only consulted when auth.uid() is null, so the chain records the true
  -- transport caller; the row's actor states the capture path.
  perform set_config('comm.verified_write', 'on', true);

  insert into public.interactions (
    account_id, actor, author_type, approved_by, approval_ref,
    entry_type, external_ref, kind, channel, direction,
    party_type, party_id, party_label, body, occurred_at,
    corrects_id, correction_kind, thread_id, attestation,
    tenancy_id, maintenance_request_id, area_id, work_order_id, vendor_id,
    rfc822_message_id
  ) values (
    p_account_id,
    'system:comm-inbound',
    v_author_type,
    null,
    null,
    null,
    p_provider_msg_id,
    'communication',
    public._comm_journal_channel(p_channel),
    'inbound',
    v_party_type,
    v_party_id,
    v_party_label,
    p_body,
    p_received_at,
    null,
    null,
    v_binding.b_thread_id,
    -- This IS the verified path: the provider confirmed this delivery and
    -- the raw body is archived (EV-B). The GUC above satisfies the gate.
    'provider_verified',
    null, null, null, null,
    case when v_party_type = 'vendor' then v_party_id else null end,
    v_msgid
  )
  returning * into v_interaction;

  -- The cast: who was on THIS delivery, frozen. Wire fact (address), our
  -- resolution (party_id) and the name snapshot (label) live side by side.
  if v_mismatch then
    -- Identity doubt stated honestly: the address is fact, the person is not.
    insert into public.interaction_participants
      (account_id, interaction_id, role, party_type, party_id, address, label, source)
    values
      (p_account_id, v_interaction.id, 'sender', 'unknown', null,
       p_from_address, null, 'comms');
  else
    insert into public.interaction_participants
      (account_id, interaction_id, role, party_type, party_id, address, label, source)
    values
      (p_account_id, v_interaction.id, 'sender', v_participant.party_type,
       v_participant.party_id, p_from_address,
       left(public._party_display_name(p_account_id, v_participant.party_type, v_participant.party_id), 200),
       'comms');
  end if;

  -- The receiving platform address (our number / the minted reply token).
  insert into public.interaction_participants
    (account_id, interaction_id, role, party_type, party_id, address, label, source)
  values
    (p_account_id, v_interaction.id, 'recipient', 'platform', null,
     p_to_number, null, 'comms');

  -- Group MMS co-recipients, resolved through this thread's bindings.
  if p_channel <> 'email' and p_cc is not null then
    for r in
      select distinct cc.addr,
             p.party_type as p_party_type,
             p.party_id   as p_party_id
        from unnest(p_cc) cc(addr)
        left join public.thread_channel_bindings b
          on b.account_id = p_account_id
         and b.thread_id = v_binding.b_thread_id
         and b.participant_address = cc.addr
         and b.active
        left join public.comm_thread_participants p
          on p.id = b.participant_id
       where cc.addr is not null
         and length(cc.addr) between 3 and 320
         and cc.addr <> p_to_number
    loop
      insert into public.interaction_participants
        (account_id, interaction_id, role, party_type, party_id, address, label, source)
      values
        (p_account_id, v_interaction.id, 'cc',
         coalesce(r.p_party_type, 'unknown'),
         r.p_party_id,
         r.addr,
         left(public._party_display_name(p_account_id, r.p_party_type, r.p_party_id), 200),
         'comms');
    end loop;
  end if;

  update public.inbound_raw
     set disposition            = v_disposition,
         matched_account_id     = p_account_id,
         matched_thread_id      = v_binding.b_thread_id,
         matched_participant_id = v_binding.b_participant_id,
         matched_interaction_id = v_interaction.id
   where id = v_raw.id;

  disposition    := v_disposition;
  interaction_id := v_interaction.id;
  thread_id      := v_binding.b_thread_id;
  participant_id := v_binding.b_participant_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."capture_inbound"("p_account_id" "uuid", "p_provider" "text", "p_provider_msg_id" "text", "p_to_number" "text", "p_from_address" "text", "p_channel" "text", "p_body" "text", "p_media" "jsonb", "p_received_at" timestamp with time zone, "p_cc" "text"[], "p_subject" "text", "p_rfc822_message_id" "text", "p_in_reply_to" "text", "p_references" "text"[], "p_auth_results" "jsonb") OWNER TO "postgres";

--
-- Name: capture_persona_inbound("uuid", "text", "text", "text", "text", "text", "text"[], "text"[], "text", "text", "jsonb", "text", "text", "text"[], "text", "text", "text", timestamp with time zone, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."capture_persona_inbound"("p_account_id" "uuid", "p_provider" "text", "p_provider_msg_id" "text", "p_persona_address" "text", "p_from_address" "text", "p_from_display_name" "text", "p_to_addresses" "text"[], "p_cc_addresses" "text"[], "p_subject" "text", "p_body" "text", "p_media" "jsonb", "p_rfc822_message_id" "text", "p_in_reply_to" "text", "p_references" "text"[], "p_spf" "text", "p_dkim" "text", "p_dmarc" "text", "p_received_at" timestamp with time zone, "p_reply_domain" "text") RETURNS TABLE("disposition" "text", "interaction_id" "uuid", "thread_id" "uuid", "participant_id" "uuid", "unmatched_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_raw          public.inbound_raw%rowtype;
  v_interaction  public.interactions%rowtype;
  v_msgid        text := public._comm_normalize_msgid(p_rfc822_message_id);
  v_parent       public.comm_outbox%rowtype;
  v_parent_match text := 'none';
  v_parent_id    uuid;
  v_ctx_tenancy  uuid;
  v_outcome      text;
  v_party_type   text;
  v_party_id     uuid;
  v_party_source text;
  v_cand_count   int := 0;
  v_conflict_pt  text;
  v_conflict_pid uuid;
  v_reason       text;            -- non-null => triage
  v_cc_arm       boolean := false;
  v_unverified   boolean := false; -- 20260723000003: unverified-journal arm
  v_cp_on_mail   boolean := true;  -- 20260723000004: counterparty on the inbound To/Cc
  v_pr_matched   int := 0;
  v_ll_id        uuid;
  v_cp_type      text;
  v_cp_id        uuid;
  v_cp_tier      text;
  v_cp_address   text;
  v_thread_id    uuid;
  v_part_id      uuid;
  v_tenancy_id   uuid;
  v_dup_id       uuid;
  v_disposition  text;
  v_decision     jsonb;
  v_addr         text;
  v_cc_pt        text;
  v_cc_pid       uuid;
  v_cc_n         int;
  r              record;
begin
  unmatched_id := null;

  -- Self-defense: transport (agent-role member of this account) only.
  if auth.uid() is null or not exists (
    select 1 from public.account_members m
     where m.user_id = auth.uid()
       and m.account_id = p_account_id
       and m.role = 'agent'
       and m.deleted_at is null
  ) then
    raise exception 'not authorized to capture inbound messages for this account'
      using errcode = '42501';
  end if;

  -- The transaction lock closes the concurrent replay gap: after the first
  -- caller records inbound_raw, later callers return its frozen result
  -- without reconsidering changed sender/auth/reference inputs. (Key
  -- unchanged from the previous chain; the account pins the replay read.)
  perform pg_advisory_xact_lock(
    hashtextextended('capture_persona_inbound:' || p_provider_msg_id, 0)
  );

  -- Idempotent replay from the shared raw tier, account-pinned. The frozen
  -- payload (routing_decision included) is never touched on replay.
  select * into v_raw
    from public.inbound_raw
   where provider_msg_id = p_provider_msg_id
     and matched_account_id = p_account_id;
  if found then
    disposition    := v_raw.disposition;
    interaction_id := v_raw.matched_interaction_id;
    thread_id      := v_raw.matched_thread_id;
    participant_id := v_raw.matched_participant_id;
    if v_raw.disposition = 'triaged' then
      select u.id into unmatched_id
        from public.comm_unmatched_inbound u
       where u.account_id = p_account_id
         and u.provider_msg_id = p_provider_msg_id;
    end if;
    return next;
    return;
  end if;

  -- Raw-first capture (same shape and collision semantics as capture_inbound).
  begin
    insert into public.inbound_raw (
      provider, provider_msg_id, payload, received_at, matched_account_id,
      rfc822_message_id
    )
    values (
      p_provider,
      p_provider_msg_id,
      jsonb_build_object(
        'persona_address', p_persona_address,
        'from_address', p_from_address,
        'from_display_name', p_from_display_name,
        'to_addresses', coalesce(to_jsonb(p_to_addresses), '[]'::jsonb),
        'cc_addresses', coalesce(to_jsonb(p_cc_addresses), '[]'::jsonb),
        'channel', 'email',
        'subject', p_subject,
        'body', p_body,
        'media', coalesce(p_media, '[]'::jsonb),
        'rfc822_message_id', v_msgid,
        'in_reply_to', public._comm_normalize_msgid(p_in_reply_to),
        'references', coalesce(
          (select jsonb_agg(public._comm_normalize_msgid(x))
             from unnest(p_references) x
            where public._comm_normalize_msgid(x) is not null),
          '[]'::jsonb),
        'auth_results', jsonb_build_object('spf', p_spf, 'dkim', p_dkim, 'dmarc', p_dmarc),
        'account_id', p_account_id
      ),
      p_received_at,
      p_account_id,
      v_msgid
    )
    returning * into v_raw;
  exception when unique_violation then
    select * into v_raw
      from public.inbound_raw
     where provider_msg_id = p_provider_msg_id;
    if v_raw.matched_account_id is distinct from p_account_id then
      raise exception 'provider_msg_id already captured for another account'
        using errcode = 'P0003';
    end if;
    disposition    := v_raw.disposition;
    interaction_id := v_raw.matched_interaction_id;
    thread_id      := v_raw.matched_thread_id;
    participant_id := v_raw.matched_participant_id;
    if v_raw.disposition = 'triaged' then
      select u.id into unmatched_id
        from public.comm_unmatched_inbound u
       where u.account_id = p_account_id
         and u.provider_msg_id = p_provider_msg_id;
    end if;
    return next;
    return;
  end;

  -- ---------------------------------------------------------------------
  -- Classification. The parent probe runs for EVERY capture: it never
  -- substitutes for authentication (§6.3), but it makes the auth-fail triage
  -- reason honest and rides the routing decision.
  -- ---------------------------------------------------------------------
  select f.o_match, f.o_parent_id into v_parent_match, v_parent_id
    from public._comm_find_parent_outbox(p_account_id, p_in_reply_to, p_references) f;

  if p_dmarc is distinct from 'pass' then
    -- -------------------------------------------------------------------
    -- Unverified-journal tier (20260723000003; header). Receipt is the
    -- operative fact: mail claiming to come from EXACTLY ONE known
    -- tenant/vendor journals into that party's conversation, marked
    -- attestation='unverified' — claimed, never asserted. No learning, no
    -- ack, no relay. Everything else keeps today's triage.
    -- -------------------------------------------------------------------
    if v_parent_match = 'multiple' then
      -- A Message-ID collision is contradictory evidence regardless of
      -- authentication: conflict, EXACTLY like the pass path, before any
      -- candidate resolution — the fail path must never be more permissive
      -- than the pass path.
      v_reason := 'identity_conflict';
    else
      if v_parent_match = 'unique' then
        select * into v_parent
          from public.comm_outbox o
         where o.id = v_parent_id
           and o.account_id = p_account_id;
        -- Does the unauthenticated From at least name a PHYSICAL recipient
        -- of the parent? (Lowercase compare, same as the pass path.)
        -- Gates whether parent context may scope the conversation below.
        select count(*) into v_pr_matched
          from public._comm_resolve_parent_sender(p_account_id, v_parent_id, p_from_address);
      end if;

      -- The SAME no-parent candidate resolution the pass path uses (account
      -- scope), plus a unique parent's tier-1 thread-participant match: a
      -- parent-named recipient is a candidate even when the address carries
      -- no live claim (e.g. a rebound address whose learned claim was
      -- superseded).
      select count(distinct (x.party_type, x.party_id)) into v_cand_count
        from (
          select c.party_type, c.party_id
            from public._comm_resolve_persona_candidates(p_account_id, p_from_address) c
          union
          select s.party_type, s.party_id
            from public._comm_resolve_parent_sender(p_account_id, v_parent_id, p_from_address) s
           where v_parent_match = 'unique'
             and s.tier = 'thread_participant'
             and s.party_id is not null
        ) x;

      if v_cand_count = 1 then
        -- The single candidate; when both arms name it, report the parent's
        -- thread_participant tier (the stronger evidence, matching the
        -- ladder).
        select x.party_type, x.party_id, x.source
          into v_party_type, v_party_id, v_party_source
          from (
            select s.party_type, s.party_id, s.tier as source, 1 as pref
              from public._comm_resolve_parent_sender(p_account_id, v_parent_id, p_from_address) s
             where v_parent_match = 'unique'
               and s.tier = 'thread_participant'
               and s.party_id is not null
            union all
            select c.party_type, c.party_id, c.source, 2
              from public._comm_resolve_persona_candidates(p_account_id, p_from_address) c
          ) x
         order by x.pref
         limit 1;
      end if;

      if v_cand_count = 1 and v_party_type in ('tenant', 'vendor') then
        v_unverified := true;
        v_cp_type    := v_party_type;
        v_cp_id      := v_party_id;
        v_cp_address := p_from_address;
        if v_parent_match = 'unique' and v_pr_matched > 0 then
          -- Parent context honored exactly as the matched path — its
          -- tenancy, else its thread's — but only when the sender IS a
          -- parent recipient: an unrelated claimed sender citing someone
          -- else's parent must not be pulled into that conversation's scope.
          v_ctx_tenancy := v_parent.tenancy_id;
          if v_ctx_tenancy is null and v_parent.thread_id is not null then
            select t.tenancy_id into v_ctx_tenancy
              from public.comm_threads t
             where t.account_id = p_account_id and t.id = v_parent.thread_id;
          end if;
          select f.thread_id, f.cp_participant_id, f.tenancy_id
            into v_thread_id, v_part_id, v_tenancy_id
            from public._persona_find_or_create_thread(
              p_account_id, v_cp_type, v_cp_id, v_cp_address,
              p_subject, p_reply_domain, null, null,
              v_parent.thread_id, v_ctx_tenancy) f;
        else
          select f.thread_id, f.cp_participant_id, f.tenancy_id
            into v_thread_id, v_part_id, v_tenancy_id
            from public._persona_find_or_create_thread(
              p_account_id, v_cp_type, v_cp_id, v_cp_address,
              p_subject, p_reply_domain, null, null) f;
        end if;
        if v_thread_id is null then
          -- Known party but no safely selectable conversation — the same
          -- honest triage the matched path uses.
          v_unverified := false;
          v_reason := 'unknown_sender';
        end if;
      elsif v_cand_count > 1 then
        -- Contradictory identity evidence stays a human problem,
        -- authenticated or not.
        v_reason := 'identity_conflict';
      elsif v_cand_count = 1 then
        -- A single landlord_user claimant keeps today's behavior: triage —
        -- never an unverified OUTBOUND-authored journal row.
        v_reason := 'auth_failed';
      else
        -- Nobody recognizes the address; a valid parent reference still
        -- makes the triage reason honest.
        v_reason := case when v_parent_match <> 'none'
          then 'auth_failed' else 'unknown_sender' end;
      end if;
    end if;

  elsif v_parent_match = 'multiple' then
    -- A Message-ID collision produced multiple parents: conflict, not
    -- "pick the newest".
    v_reason := 'identity_conflict';

  elsif v_parent_match = 'unique' then
    select * into v_parent
      from public.comm_outbox o
     where o.id = v_parent_id
       and o.account_id = p_account_id;

    select c.o_outcome, c.o_party_type, c.o_party_id, c.o_party_source,
           c.o_candidate_count, c.o_conflict_party_type, c.o_conflict_party_id
      into v_outcome, v_party_type, v_party_id, v_party_source,
           v_cand_count, v_conflict_pt, v_conflict_pid
      from public._comm_choose_persona_route(p_account_id, v_parent_id, p_from_address) c;

    if v_outcome = 'parent_sender_mismatch' then
      v_reason := 'parent_sender_mismatch';
    elsif v_outcome = 'identity_conflict' then
      v_reason := 'identity_conflict';
    elsif v_outcome = 'unknown' then
      v_reason := 'unknown_sender';
    else
      -- The parent's conversation scope: its own tenancy, else its thread's.
      v_ctx_tenancy := v_parent.tenancy_id;
      if v_ctx_tenancy is null and v_parent.thread_id is not null then
        select t.tenancy_id into v_ctx_tenancy
          from public.comm_threads t
         where t.account_id = p_account_id and t.id = v_parent.thread_id;
      end if;

      if v_outcome = 'cc_journaled' then
        -- The landlord replied from a parent Cc leg: journal into the
        -- parent's PRIMARY recipient's conversation. Whether the transport
        -- also DELIVERS the reply is decided by the shared-tail split
        -- (20260723000004): counterparty on the inbound To/Cc ->
        -- 'cc_journaled'; absent -> 'cc_relayed'.
        v_cc_arm := true;
        v_ll_id  := v_party_id;
        select h.o_party_type, h.o_party_id, h.o_tier into v_cp_type, v_cp_id, v_cp_tier
          from public._comm_resolve_parent_recipient(
                 p_account_id, v_parent.thread_id, v_parent.tenancy_id,
                 v_parent.recipient_snapshot, v_parent.to_address) h;
        v_cp_address := v_parent.to_address;
        if v_cp_tier = 'claim_conflict' then
          -- The primary recipient's claims tie between parties: fail closed.
          v_reason := 'identity_conflict';
        elsif v_cp_id is null or v_cp_type not in ('tenant', 'vendor') then
          -- The landlord replied about someone core cannot place.
          v_reason := 'unknown_sender';
        end if;
      else
        v_cp_type    := v_party_type;
        v_cp_id      := v_party_id;
        v_cp_address := p_from_address;
      end if;

      if v_reason is null then
        select f.thread_id, f.cp_participant_id, f.tenancy_id
          into v_thread_id, v_part_id, v_tenancy_id
          from public._persona_find_or_create_thread(
            p_account_id, v_cp_type, v_cp_id, v_cp_address,
            p_subject, p_reply_domain,
            case when v_cc_arm then v_ll_id else null end,
            case when v_cc_arm then p_from_address else null end,
            v_parent.thread_id, v_ctx_tenancy) f;
        if v_thread_id is null then
          -- Known party, but no conversation can be selected safely (closed
          -- parent thread without a usable tenancy). The triage queue's
          -- human-link path is the honest resolution.
          v_reason := 'unknown_sender';
        end if;
      end if;
    end if;

  else
    -- -------------------------------------------------------------------
    -- No parent (§6.5): scoped candidates for the authenticated sender —
    -- live claims + record books through the tiered resolver, so a human
    -- claim hides the learned tiers and superseded claims are invisible.
    -- -------------------------------------------------------------------
    select count(distinct (c.party_type, c.party_id)) into v_cand_count
      from public._comm_resolve_persona_candidates(p_account_id, p_from_address) c;

    if v_cand_count = 0 then
      v_reason := 'unknown_sender';
    elsif v_cand_count > 1 then
      -- Two live claims at the same winning tier and nothing to select a
      -- role: honest conflict.
      v_reason := 'identity_conflict';
    else
      select c.party_type, c.party_id, c.source
        into v_party_type, v_party_id, v_party_source
        from public._comm_resolve_persona_candidates(p_account_id, p_from_address) c
       limit 1;

      if v_party_type = 'landlord_user' then
        -- The landlord CC arm (unchanged from the previous chain): the
        -- conversation comes from a To/Cc address bound in an active email
        -- thread, else a To/Cc address resolving to a known counterparty
        -- (outbound-cold create), else triage.
        v_cc_arm := true;
        v_ll_id  := v_party_id;

        select b.thread_id, b.participant_id, b.participant_address,
               p.party_type, p.party_id
          into v_thread_id, v_part_id, v_cp_address, v_cp_type, v_cp_id
          from unnest(coalesce(p_to_addresses, '{}') || coalesce(p_cc_addresses, '{}')) cand(addr)
          join public.thread_channel_bindings b
            on b.account_id = p_account_id
           and b.channel = 'email'
           and b.active
           and b.participant_address = cand.addr
          join public.comm_threads t
            on t.account_id = b.account_id and t.id = b.thread_id
          join public.comm_thread_participants p
            on p.id = b.participant_id
         where cand.addr <> p_persona_address
           and cand.addr <> p_from_address
           and t.status = 'active'
           and t.mode = 'bridged'
           and p.party_type in ('tenant', 'vendor')
           and p.left_at is null
         order by t.updated_at desc
         limit 1;

        if v_thread_id is not null then
          select t.tenancy_id into v_tenancy_id
            from public.comm_threads t
           where t.account_id = p_account_id and t.id = v_thread_id;
        else
          for r in
            select cand.addr
              from unnest(coalesce(p_to_addresses, '{}') || coalesce(p_cc_addresses, '{}')) cand(addr)
             where cand.addr <> p_persona_address
               and cand.addr <> p_from_address
          loop
            -- Counterparty candidates only (a landlord claim on the same
            -- address must not mask a tenant claim below it): exactly one
            -- tenant/vendor party at its winning tier, else next address.
            select count(distinct (x.party_type, x.party_id)) into v_cc_n
              from public._comm_resolve_identity_claims(
                     p_account_id, 'email', r.addr, null, null,
                     array['tenant', 'vendor']) x;
            if v_cc_n = 1 then
              select x.party_type, x.party_id into v_cp_type, v_cp_id
                from public._comm_resolve_identity_claims(
                       p_account_id, 'email', r.addr, null, null,
                       array['tenant', 'vendor']) x
               limit 1;
              v_cp_address := r.addr;
              -- Additive learning for the record-book hit; DO NOTHING against
              -- an existing same-party claim (any source) at account scope.
              insert into public.channel_identities
                (account_id, party_type, party_id, channel, address, source)
              values (p_account_id, v_cp_type, v_cp_id, 'email', r.addr, 'provider_learned')
              on conflict (account_id, channel, address, party_type, party_id, scope_type, scope_id)
              do nothing;
              exit;
            end if;
          end loop;

          if v_cp_id is not null then
            select f.thread_id, f.cp_participant_id, f.tenancy_id
              into v_thread_id, v_part_id, v_tenancy_id
              from public._persona_find_or_create_thread(
                p_account_id, v_cp_type, v_cp_id, v_cp_address,
                p_subject, p_reply_domain, v_ll_id, p_from_address) f;
          end if;
        end if;

        if v_thread_id is null then
          v_reason := 'unknown_sender';
        end if;
      else
        -- Counterparty arm: one tenant/vendor claim.
        v_cp_type    := v_party_type;
        v_cp_id      := v_party_id;
        v_cp_address := p_from_address;
        select f.thread_id, f.cp_participant_id, f.tenancy_id
          into v_thread_id, v_part_id, v_tenancy_id
          from public._persona_find_or_create_thread(
            p_account_id, v_cp_type, v_cp_id, v_cp_address,
            p_subject, p_reply_domain, null, null) f;
        if v_thread_id is null then
          v_reason := 'unknown_sender';
        end if;
      end if;
    end if;
  end if;

  -- ---------------------------------------------------------------------
  -- Triage exit (single writer).
  -- ---------------------------------------------------------------------
  if v_reason is not null then
    unmatched_id := public._persona_record_unmatched(
      p_account_id, p_provider, p_provider_msg_id, p_persona_address,
      p_from_address, p_from_display_name, p_to_addresses, p_cc_addresses,
      p_subject, p_body, p_media, v_msgid, p_spf, p_dkim, p_dmarc,
      p_received_at, v_reason);
    v_decision := jsonb_build_object(
      'version', 2,
      'account_source', 'persona_subdomain',
      'auth', coalesce(p_dmarc, 'none'),
      'parent_match', v_parent_match,
      'parent_outbox_id', v_parent_id,
      'party_source', v_party_source,
      'candidate_count', v_cand_count,
      'selected_party_type', null,
      'selected_party_id', null,
      'selected_thread_id', null,
      'selected_tenancy_id', null,
      'disposition', 'triaged',
      'reason', v_reason,
      'conflict_party_type', v_conflict_pt,
      'conflict_party_id', v_conflict_pid
    );
    update public.inbound_raw
       set disposition = 'triaged',
           payload     = jsonb_set(payload, '{routing_decision}', v_decision, true)
     where id = v_raw.id;
    disposition    := 'triaged';
    interaction_id := null;
    thread_id      := null;
    participant_id := null;
    return next;
    return;
  end if;

  -- Same-thread duplicate (the two-door delivery), all arms — the unverified
  -- tier included (invariant d).
  if v_msgid is not null then
    select i.id into v_dup_id
      from public.interactions i
     where i.account_id = p_account_id
       and i.rfc822_message_id = v_msgid
       and i.thread_id = v_thread_id
     limit 1;
    if v_dup_id is not null then
      v_decision := jsonb_build_object(
        'version', 2,
        'account_source', 'persona_subdomain',
        'auth', coalesce(p_dmarc, 'none'),
        'parent_match', v_parent_match,
        'parent_outbox_id', v_parent_id,
        'party_source', v_party_source,
        'candidate_count', v_cand_count,
        'selected_party_type', case when v_cc_arm then 'landlord_user' else v_cp_type end,
        'selected_party_id',   case when v_cc_arm then v_ll_id else v_cp_id end,
        'selected_thread_id', v_thread_id,
        'selected_tenancy_id', v_tenancy_id,
        'disposition', 'duplicate',
        'reason', 'duplicate_rfc822_message_id',
        'conflict_party_type', v_conflict_pt,
        'conflict_party_id', v_conflict_pid
      );
      update public.inbound_raw
         set disposition            = 'duplicate',
             matched_thread_id      = v_thread_id,
             matched_participant_id = v_part_id,
             matched_interaction_id = v_dup_id,
             payload = jsonb_set(payload, '{routing_decision}', v_decision, true)
       where id = v_raw.id;
      disposition    := 'duplicate';
      interaction_id := v_dup_id;
      thread_id      := v_thread_id;
      participant_id := v_part_id;
      return next;
      return;
    end if;
  end if;

  -- The reply-all completion split (20260723000004, header): with the journal
  -- decision already made, is the resolved counterparty PHYSICALLY on this
  -- email? Lowercase compare on both sides; a different spelling of the same
  -- mailbox does NOT count as present. Only the cc arms consult the flag; in
  -- the no-parent arm the counterparty comes FROM the inbound To/Cc, so it is
  -- always present there.
  -- A null counterparty address (parent to_address null; party resolved from
  -- the frozen snapshot alone) names no deliverable recipient: skip the
  -- split — the default TRUE keeps 'cc_journaled', never a relay toward a
  -- null address.
  if v_cc_arm and v_cp_address is not null then
    select exists (
      select 1
        from unnest(coalesce(p_to_addresses, '{}'::text[])
                    || coalesce(p_cc_addresses, '{}'::text[])) a(addr)
       where lower(btrim(a.addr))
             = lower(btrim(v_cp_address))
    ) into v_cp_on_mail;
  end if;

  v_disposition := case
    when v_unverified then 'journaled_unverified'
    when v_cc_arm and v_cp_on_mail then 'cc_journaled'
    when v_cc_arm then 'cc_relayed'
    when exists (
      select 1 from public.comm_opt_outs oo
       where oo.channel = 'email' and oo.address = p_from_address
    ) then 'opted_out'
    else 'matched'
  end;

  -- Additive learning: the authenticated sender's exact address, bound to the
  -- party the route selected, as a provider_learned claim. Landlord aliases
  -- are account-wide; counterparty learning is scoped to the resolved tenancy
  -- when there is one (a shared inbox must not be captured account-wide by
  -- one tenancy's conversation). Capture NEVER supersedes: a claim for a
  -- different party simply coexists (the tiers rank them at read time); a
  -- same-party claim of any source collides on the claim key and stays as it
  -- was.
  -- CRITICAL INVARIANT (a): the unverified tier NEVER learns — a forged From
  -- must not teach the address book anything.
  if not v_unverified then
    insert into public.channel_identities
      (account_id, party_type, party_id, channel, address, source, scope_type, scope_id)
    values (
      p_account_id,
      case when v_cc_arm then 'landlord_user' else v_cp_type end,
      case when v_cc_arm then v_ll_id else v_cp_id end,
      'email',
      p_from_address,
      'provider_learned',
      case when not v_cc_arm and v_tenancy_id is not null then 'tenancy' end,
      case when not v_cc_arm and v_tenancy_id is not null then v_tenancy_id end
    )
    on conflict (account_id, channel, address, party_type, party_id, scope_type, scope_id)
    do nothing;
  end if;

  -- Journal + cast (unchanged contract). The CC arm inverts direction and
  -- authorship; the party slot is the counterparty in BOTH arms. The
  -- unverified arm journals inbound with attestation='unverified' — the
  -- claimed-not-asserted marker.
  perform set_config('comm.verified_write', 'on', true);

  insert into public.interactions (
    account_id, actor, author_type, approved_by, approval_ref,
    entry_type, external_ref, kind, channel, direction,
    party_type, party_id, party_label, body, occurred_at,
    corrects_id, correction_kind, thread_id, attestation,
    tenancy_id, maintenance_request_id, area_id, work_order_id, vendor_id,
    rfc822_message_id
  ) values (
    p_account_id,
    case when v_cc_arm then 'system:comm-persona-cc' else 'system:comm-persona' end,
    case
      when v_cc_arm then 'landlord'
      when v_cp_type = 'vendor' then 'vendor'
      else 'tenant'
    end,
    null,
    null,
    null,
    p_provider_msg_id,
    'communication',
    public._comm_journal_channel('email'),
    case when v_cc_arm then 'outbound' else 'inbound' end,
    v_cp_type,
    v_cp_id,
    null,
    p_body,
    p_received_at,
    null,
    null,
    v_thread_id,
    case when v_unverified then 'unverified' else 'provider_verified' end,
    v_tenancy_id,
    null, null, null,
    case when v_cp_type = 'vendor' then v_cp_id else null end,
    v_msgid
  )
  returning * into v_interaction;

  if v_cc_arm then
    insert into public.interaction_participants
      (account_id, interaction_id, role, party_type, party_id, address, label, source)
    values
      (p_account_id, v_interaction.id, 'sender', 'landlord_user', v_ll_id, p_from_address,
       left(coalesce(public._party_display_name(p_account_id, 'landlord_user', v_ll_id),
                     p_from_display_name), 200),
       'comms'),
      (p_account_id, v_interaction.id, 'recipient', v_cp_type, v_cp_id, v_cp_address,
       left(public._party_display_name(p_account_id, v_cp_type, v_cp_id), 200),
       'comms'),
      (p_account_id, v_interaction.id, 'cc', 'platform', null, p_persona_address, null, 'comms');
  else
    -- Unverified arm: the sender label is the ADDRESS, not the party's
    -- display name — the label must state the physical fact, not assert the
    -- identity this tier explicitly refuses to assert.
    insert into public.interaction_participants
      (account_id, interaction_id, role, party_type, party_id, address, label, source)
    values
      (p_account_id, v_interaction.id, 'sender', v_cp_type, v_cp_id, p_from_address,
       case when v_unverified then left(p_from_address, 200)
            else left(coalesce(public._party_display_name(p_account_id, v_cp_type, v_cp_id),
                               p_from_display_name), 200) end,
       'comms'),
      (p_account_id, v_interaction.id, 'recipient', 'platform', null, p_persona_address, null, 'comms');
  end if;

  for v_addr in
    select distinct x.addr
      from (
        select unnest(coalesce(p_to_addresses, '{}')) as addr
        union all
        select unnest(coalesce(p_cc_addresses, '{}'))
      ) x
     where x.addr is not null
       and length(x.addr) between 3 and 320
       and x.addr <> p_persona_address
       and x.addr <> p_from_address
       and (v_cp_address is null or x.addr <> v_cp_address or not v_cc_arm)
  loop
    -- Cc cast attribution through the resolver: a single live winner names
    -- the party; anything else (no claim, or a tie) is honestly 'unknown'.
    -- The old raw left-join would duplicate cast rows under multi-claim.
    v_cc_pt := null; v_cc_pid := null;
    select count(distinct (x.party_type, x.party_id)) into v_cc_n
      from public._comm_resolve_identity_claims(
             p_account_id, 'email', v_addr, v_tenancy_id, v_thread_id) x;
    if v_cc_n = 1 then
      select x.party_type, x.party_id into v_cc_pt, v_cc_pid
        from public._comm_resolve_identity_claims(
               p_account_id, 'email', v_addr, v_tenancy_id, v_thread_id) x
       limit 1;
    end if;
    insert into public.interaction_participants
      (account_id, interaction_id, role, party_type, party_id, address, label, source)
    values
      (p_account_id, v_interaction.id, 'cc',
       coalesce(v_cc_pt, 'unknown'),
       v_cc_pid,
       v_addr,
       case when v_unverified then left(v_addr, 200)
            else left(public._party_display_name(p_account_id, v_cc_pt, v_cc_pid), 200) end,
       'comms');
  end loop;

  v_decision := jsonb_build_object(
    'version', 2,
    'account_source', 'persona_subdomain',
    'auth', coalesce(p_dmarc, 'none'),
    'parent_match', v_parent_match,
    'parent_outbox_id', v_parent_id,
    'party_source', v_party_source,
    'candidate_count', v_cand_count,
    'selected_party_type', case when v_cc_arm then 'landlord_user' else v_cp_type end,
    'selected_party_id',   case when v_cc_arm then v_ll_id else v_cp_id end,
    'selected_thread_id', v_thread_id,
    'selected_tenancy_id', v_tenancy_id,
    'disposition', v_disposition,
    'reason', case
      when v_unverified then 'unverified_single_claim'
      when v_disposition = 'cc_relayed' then 'cc_counterparty_not_addressed'
      when v_parent_match = 'unique' then 'parent_unique_match'
      else 'sender_unique_claim' end,
    'conflict_party_type', v_conflict_pt,
    'conflict_party_id', v_conflict_pid
  );

  update public.inbound_raw
     set disposition            = v_disposition,
         matched_thread_id      = v_thread_id,
         matched_participant_id = v_part_id,
         matched_interaction_id = v_interaction.id,
         payload = jsonb_set(payload, '{routing_decision}', v_decision, true)
   where id = v_raw.id;

  disposition    := v_disposition;
  interaction_id := v_interaction.id;
  thread_id      := v_thread_id;
  participant_id := v_part_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."capture_persona_inbound"("p_account_id" "uuid", "p_provider" "text", "p_provider_msg_id" "text", "p_persona_address" "text", "p_from_address" "text", "p_from_display_name" "text", "p_to_addresses" "text"[], "p_cc_addresses" "text"[], "p_subject" "text", "p_body" "text", "p_media" "jsonb", "p_rfc822_message_id" "text", "p_in_reply_to" "text", "p_references" "text"[], "p_spf" "text", "p_dkim" "text", "p_dmarc" "text", "p_received_at" timestamp with time zone, "p_reply_domain" "text") OWNER TO "postgres";

--
-- Name: change_tenancy_rent("uuid", "uuid", bigint, "text", "date", integer, "uuid", "uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."change_tenancy_rent"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_amount_cents" bigint, "p_currency" "text", "p_effective_date" "date", "p_due_day" integer DEFAULT NULL::integer, "p_source_lease_id" "uuid" DEFAULT NULL::"uuid", "p_source_notice_id" "uuid" DEFAULT NULL::"uuid", "p_change_reason" "text" DEFAULT NULL::"text", "p_kind" "text" DEFAULT 'rent'::"text") RETURNS TABLE("o_schedule_id" "uuid", "o_ended_schedule_ids" "uuid"[], "o_superseded_lease_ids" "uuid"[], "o_voided_charge_ids" "uuid"[])
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_tenancy     record;
  v_lease       record;
  v_notice      record;
  v_rec         record;
  v_ended       uuid[] := '{}';
  v_superseded  uuid[] := '{}';
  v_voided      uuid[] := '{}';
  v_inherit_due int;
  v_inherit_end date;
  v_due_day     int;
  v_schedule_id uuid;
begin
  -- 1. Serialize concurrent rent changes for this tenancy. Two racing changes
  --    would otherwise both read the same "open" schedule set and each end it /
  --    insert a successor, producing overlapping eras.
  perform pg_advisory_xact_lock(hashtextextended('rent_change:' || p_tenancy_id::text, 0));

  -- 2. Input validation (stable `invalid:` prefix).
  if p_amount_cents is null or p_amount_cents < 0 then
    raise exception 'invalid: amount_cents must be >= 0';
  end if;
  if p_currency is null or length(p_currency) <> 3 then
    raise exception 'invalid: currency must be a 3-letter code';
  end if;
  if p_kind is null or length(p_kind) = 0 or length(p_kind) > 50 then
    raise exception 'invalid: kind must be a non-empty string of at most 50 characters';
  end if;
  if p_effective_date is null then
    raise exception 'invalid: effective_date is required';
  end if;

  -- 3. Tenancy must exist (account match, not soft-deleted) and not be ended.
  select id, status
    into v_tenancy
    from public.tenancies
   where account_id = p_account_id
     and id         = p_tenancy_id
     and deleted_at is null;
  if v_tenancy.id is null then
    raise exception 'not_found: tenancy';
  end if;
  if v_tenancy.status = 'ended' then
    raise exception 'conflict: tenancy already ended';
  end if;

  -- 4. A rent change must be anchored to an instrument. Both non-null is
  --    allowed (a renewal lease following a rent-increase notice).
  if p_source_lease_id is null and p_source_notice_id is null then
    raise exception 'invalid: a rent change must be anchored to a lease (source_lease_id) or a served notice (source_notice_id)';
  end if;

  -- 5. Lease anchor: must belong to this account AND this tenancy, not deleted.
  --    A draft lease is ACTIVATED by this call (the change is what puts a
  --    pre-created renewal into force). An expired/superseded lease cannot
  --    anchor a new change.
  if p_source_lease_id is not null then
    select id, status
      into v_lease
      from public.leases
     where account_id = p_account_id
       and id         = p_source_lease_id
       and tenancy_id = p_tenancy_id
       and deleted_at is null;
    if v_lease.id is null then
      raise exception 'not_found: source lease';
    end if;
    if v_lease.status in ('expired', 'superseded') then
      raise exception 'conflict: source lease is %', v_lease.status;
    end if;
    if v_lease.status = 'draft' then
      update public.leases
         set status     = 'active',
             updated_at = now()
       where account_id = p_account_id
         and id         = p_source_lease_id;
    end if;
  end if;

  -- 6. Notice anchor: must belong to this account AND this tenancy, not deleted,
  --    AND be SERVED. An unserved (draft) notice is not yet a legal instrument,
  --    so it cannot authorize a rent change -- served_at must be set first. The
  --    not_found path still covers a missing / cross-tenancy / deleted notice.
  if p_source_notice_id is not null then
    select id, served_at
      into v_notice
      from public.notices
     where account_id = p_account_id
       and id         = p_source_notice_id
       and tenancy_id = p_tenancy_id
       and deleted_at is null;
    if v_notice.id is null then
      raise exception 'not_found: source notice';
    end if;
    if v_notice.served_at is null then
      raise exception 'conflict: source notice has not been served (set served_at first)';
    end if;
  end if;

  -- 7. End the open same-kind schedule era(s). "Open" = kind matches, not
  --    deleted, and still covering periods on/after effective_date. We iterate
  --    most-recently-started first so the FIRST row we see is the one whose
  --    due_day the successor inherits when none is passed (step 8).
  --
  --    A schedule that STARTS on/after effective_date cannot simply be ended at
  --    effective_date-1 (that would invert its date range); it signals an
  --    already-planned future change that must be resolved by a human first.
  for v_rec in
    select id, start_date, due_day, end_date
      from public.rent_schedules
     where account_id = p_account_id
       and tenancy_id = p_tenancy_id
       and kind       = p_kind
       and deleted_at is null
       and (end_date is null or end_date >= p_effective_date)
     order by start_date desc, created_at desc
  loop
    if v_rec.start_date >= p_effective_date then
      raise exception 'conflict: a schedule of kind % starting % conflicts with effective_date %; resolve it first',
        p_kind, v_rec.start_date, p_effective_date;
    end if;
    update public.rent_schedules
       set end_date   = p_effective_date - 1,
           updated_at = now()
     where account_id = p_account_id
       and id         = v_rec.id;
    v_ended := v_ended || v_rec.id;
    if v_inherit_due is null then
      -- Inherit both due_day AND the (possibly bounded) end_date from the SAME
      -- most-recently-started ended schedule -- captured from v_rec here BEFORE
      -- the update above overwrites the row's end_date. Inheriting end_date
      -- keeps a bounded predecessor's planned end (e.g. a fixed-term move-out)
      -- from silently becoming open-ended on the successor. The open-set filter
      -- above guarantees v_inherit_end is null or >= p_effective_date, so the
      -- successor's [effective_date, v_inherit_end] range is always valid.
      v_inherit_due := v_rec.due_day;
      v_inherit_end := v_rec.end_date;
    end if;
  end loop;

  -- 8. due_day for the successor: explicit override, else inherited from the
  --    schedule we just ended. If neither exists there is nothing to inherit.
  v_due_day := coalesce(p_due_day, v_inherit_due);
  if v_due_day is null then
    raise exception 'invalid: due_day is required when no open schedule exists to inherit it from';
  end if;

  -- 9. Append the successor schedule (start_date = effective_date). end_date is
  --    v_inherit_end: the predecessor's planned end when one was inherited (F2),
  --    else null (open-ended) for a fresh era with an explicit due_day.
  --    currency is stored EXACTLY as passed -- the table only length-checks it
  --    and existing rows come from the API un-folded, so we do not case-fold.
  insert into public.rent_schedules
    (account_id, tenancy_id, kind, amount_cents, currency, due_day,
     start_date, end_date, source_lease_id, source_notice_id, change_reason)
  values
    (p_account_id, p_tenancy_id, p_kind, p_amount_cents, p_currency, v_due_day,
     p_effective_date, v_inherit_end, p_source_lease_id, p_source_notice_id, p_change_reason)
  returning id into v_schedule_id;

  -- 9b. Close the advance-generation double-bill hole across the era seam (see
  --     the GENERATOR COMPATIBILITY note in the header). generate_rent_charges
  --     bills IN ADVANCE, so periods on/after effective_date may already have a
  --     charge under one of the just-ended schedules' ids. Those charges belong
  --     to the OLD amount for a period the successor now owns, and ON CONFLICT
  --     cannot dedupe them (different source_schedule_id). VOID them (never
  --     delete -- the house rule; a voided charge with allocations falls its
  --     payment back to unapplied credit, per test:ledger) so the next generator
  --     run re-emits exactly one open charge per period at the new amount.
  --     Nothing is voided when no schedule was ended (v_ended is empty).
  with voided as (
    update public.charges
       set voided_at   = now(),
           void_reason = 'superseded by rent change (schedule ' || v_schedule_id || ')',
           updated_at  = now()
     where account_id         = p_account_id
       and source_schedule_id = any(v_ended)
       and period_start      >= p_effective_date
       and voided_at is null
       and deleted_at is null
    returning id
  )
  select coalesce(array_agg(id), '{}') into v_voided from voided;

  -- 10. Lease-anchored change supersedes the OTHER active leases of this
  --     tenancy (the one we anchored to is the new contract of record).
  --     Notice-only changes touch no leases -- v_superseded stays empty.
  if p_source_lease_id is not null then
    with superseded as (
      update public.leases
         set status     = 'superseded',
             updated_at = now()
       where account_id = p_account_id
         and tenancy_id = p_tenancy_id
         and status     = 'active'
         and deleted_at is null
         and id <> p_source_lease_id
      returning id
    )
    select coalesce(array_agg(id), '{}') into v_superseded from superseded;
  end if;

  -- 11. Deliberately NO set_config('audit.actor', ...): this runs inside the
  --     caller's own transaction, so the audit trigger attributes every write
  --     to the calling user's JWT (same rationale as the end-cascade trigger in
  --     20260704000002). Stamping a synthetic actor would misattribute a human
  --     action.

  -- 12. Return exactly one summary row.
  return query select v_schedule_id, v_ended, v_superseded, v_voided;
end;
$$;


ALTER FUNCTION "public"."change_tenancy_rent"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_amount_cents" bigint, "p_currency" "text", "p_effective_date" "date", "p_due_day" integer, "p_source_lease_id" "uuid", "p_source_notice_id" "uuid", "p_change_reason" "text", "p_kind" "text") OWNER TO "postgres";

--
-- Name: check_outbox_party_intent("uuid", "uuid", "text", "uuid", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."check_outbox_party_intent"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_to_party_type" "text", "p_to_party_id" "uuid", "p_to_address" "text", "p_cc_parties" "jsonb") RETURNS TABLE("slot" "text", "hint_address" "text", "verdict" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  cc record;
begin
  -- Same roles as the send path (outbox POST): a viewer may not use this as a
  -- within-account address→party confirm-oracle (it can resolve owner/manager
  -- emails via the resolver, which reads auth.users under definer rights).
  if auth.uid() is null or not exists (
    select 1 from public.account_members m
     where m.user_id = auth.uid()
       and m.account_id = p_account_id
       and m.role in ('owner', 'manager', 'agent')
       and m.deleted_at is null
  ) then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  if p_to_party_type is not null or p_to_party_id is not null then
    slot := 'to';
    hint_address := p_to_address;
    verdict := public._comm_party_intent_verdict(
      p_account_id, p_tenancy_id, p_to_party_type, p_to_party_id, p_to_address);
    return next;
  end if;

  if p_cc_parties is not null then
    for cc in
      select e->>'address'                    as address,
             e->>'party_type'                  as party_type,
             nullif(e->>'party_id', '')::uuid  as party_id
        from jsonb_array_elements(p_cc_parties) e
    loop
      slot := 'cc';
      hint_address := cc.address;
      verdict := public._comm_party_intent_verdict(
        p_account_id, p_tenancy_id, cc.party_type, cc.party_id, cc.address);
      return next;
    end loop;
  end if;
end;
$$;


ALTER FUNCTION "public"."check_outbox_party_intent"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_to_party_type" "text", "p_to_party_id" "uuid", "p_to_address" "text", "p_cc_parties" "jsonb") OWNER TO "postgres";

--
-- Name: claim_idempotency_key("uuid", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."claim_idempotency_key"("p_account_id" "uuid", "p_key" "text", "p_fingerprint" "text") RETURNS TABLE("claimed" boolean, "fingerprint_matches" boolean, "in_flight" boolean, "status_code" integer, "body" "jsonb")
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_row record;
begin
  -- (1) Fresh claim: insert the placeholder. The winner runs the handler.
  insert into public.idempotency_keys (account_id, key, request_fingerprint)
  values (p_account_id, p_key, p_fingerprint)
  on conflict (account_id, key) do nothing;
  if found then
    claimed := true; fingerprint_matches := true; in_flight := false;
    status_code := null; body := null;
    return next; return;
  end if;

  -- (2) Conflict -> try to RECLAIM an abandoned in-flight placeholder. A row
  -- still in-flight 90s+ after it was created cannot be a live request (the app
  -- caps requests at 25s), so a retry may take it over and re-execute. Race-safe:
  -- the predicate + single UPDATE means only one concurrent retry can win.
  update public.idempotency_keys
     set request_fingerprint = p_fingerprint,
         status_code         = null,
         body                = null,
         completed_at        = null,
         created_at          = now(),
         expires_at          = now() + interval '30 days'
   where account_id = p_account_id
     and key        = p_key
     and completed_at is null
     and created_at < now() - interval '90 seconds';
  if found then
    claimed := true; fingerprint_matches := true; in_flight := false;
    status_code := null; body := null;
    return next; return;
  end if;

  -- (3) A live row owns the key: inspect it (replay / in-flight / mismatch).
  select k.request_fingerprint, k.status_code, k.body, k.completed_at
    into v_row
    from public.idempotency_keys k
   where k.account_id = p_account_id and k.key = p_key;
  if v_row is null then
    -- Vanished between the conflicting insert and this read (e.g. janitor
    -- prune, or a concurrent reclaim that then completed). Surface as in-flight;
    -- the client retry will claim cleanly.
    claimed := false; fingerprint_matches := true; in_flight := true;
    status_code := null; body := null;
    return next; return;
  end if;

  claimed := false;
  fingerprint_matches := (v_row.request_fingerprint = p_fingerprint);
  in_flight := (v_row.completed_at is null);
  status_code := v_row.status_code;
  body := v_row.body;
  return next;
end;
$$;


ALTER FUNCTION "public"."claim_idempotency_key"("p_account_id" "uuid", "p_key" "text", "p_fingerprint" "text") OWNER TO "postgres";

