-- Name: comm_persona_routing_version(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."comm_persona_routing_version"() RETURNS integer
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
