--
-- Name: complete_evidence_export("uuid", "uuid", "text", "text", bigint, timestamp with time zone, boolean, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."complete_evidence_export"("p_evidence_export_id" "uuid", "p_attachment_id" "uuid", "p_storage_path" "text", "p_content_hash" "text", "p_size_bytes" bigint, "p_generated_at" timestamp with time zone, "p_chain_verified" boolean, "p_chain_message" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
declare
  v_account  uuid;
  v_exporter uuid;
begin
  select account_id, exporter into v_account, v_exporter
  from public.evidence_exports
  where id = p_evidence_export_id and deleted_at is null
  for update;
  if v_account is null then
    raise exception 'evidence export % not found', p_evidence_export_id;
  end if;

  perform set_config(
    'audit.actor',
    case when v_exporter is not null then 'user:' || v_exporter::text else 'system' end,
    true
  );

  -- Attachment first; its entity_id points at the export row (polymorphic,
  -- not a FK), and the export row's composite FK on attachment_id is then
  -- satisfiable within the same txn.
  insert into public.attachments
    (id, account_id, entity_type, entity_id, storage_path, content_hash,
     mime_type, size_bytes, uploaded_by)
  values
    (p_attachment_id, v_account, 'evidence_export', p_evidence_export_id,
     p_storage_path, p_content_hash, 'application/pdf', p_size_bytes, v_exporter);

  update public.evidence_exports
     set attachment_id  = p_attachment_id,
         generated_at   = p_generated_at,
         chain_verified = p_chain_verified,
         chain_message  = p_chain_message,
         status         = 'done',
         error          = null,
         updated_at     = now()
   where id = p_evidence_export_id;
end;
$$;


ALTER FUNCTION "public"."complete_evidence_export"("p_evidence_export_id" "uuid", "p_attachment_id" "uuid", "p_storage_path" "text", "p_content_hash" "text", "p_size_bytes" bigint, "p_generated_at" timestamp with time zone, "p_chain_verified" boolean, "p_chain_message" "text") OWNER TO "postgres";

--
-- Name: complete_idempotency_key("uuid", "text", integer, "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."complete_idempotency_key"("p_account_id" "uuid", "p_key" "text", "p_status" integer, "p_body" "jsonb") RETURNS "void"
    LANGUAGE "sql"
    SET "search_path" TO 'public'
    AS $$
  update public.idempotency_keys
     set status_code  = p_status,
         body         = p_body,
         completed_at = now()
   where account_id = p_account_id and key = p_key;
$$;


ALTER FUNCTION "public"."complete_idempotency_key"("p_account_id" "uuid", "p_key" "text", "p_status" integer, "p_body" "jsonb") OWNER TO "postgres";

--
-- Name: complete_send("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."complete_send"("p_outbox_id" "uuid", "p_provider" "text", "p_provider_sid" "text", "p_rfc822_message_id" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_outbox         public.comm_outbox%rowtype;
  v_interaction    public.interactions%rowtype;
  v_party_type     text;
  v_party_id       uuid;
  v_party_label    text;
  v_author_type    text;
  v_cast_type      text;
  v_sender_address text;
  v_area_id        uuid;
  v_cast           jsonb := '[]'::jsonb;
  v_names          text[] := '{}';
  v_name           text;
  v_journal_body   text;
  v_msgid          text := public._comm_normalize_msgid(p_rfc822_message_id);
  v_dup_outbox_id  uuid;
  r                record;
begin
  select * into v_outbox
    from public.comm_outbox
   where id = p_outbox_id
  for update;

  if not found then
    raise exception 'outbox row not found' using errcode = 'P0002';
  end if;

  -- Self-defense (DEFINER bypasses RLS): live membership in the row's account.
  if auth.uid() is null or not exists (
    select 1 from public.account_members m
     where m.user_id = auth.uid()
       and m.account_id = v_outbox.account_id
       and m.deleted_at is null
  ) then
    raise exception 'outbox row not found' using errcode = 'P0002';
  end if;

  -- Idempotent replay: same sid, already completed -> return the journal id
  -- (the linked interaction, which for a relay leg IS the original).
  if v_outbox.status in ('sent', 'delivered') and v_outbox.provider_sid = p_provider_sid then
    return v_outbox.interaction_id;
  end if;

  if v_outbox.status not in ('queued', 'sending', 'needs_reconcile') then
    raise exception 'outbox row is not completable (status=%)', v_outbox.status
      using errcode = 'P0003';
  end if;

  -- Graceful duplicate-Message-ID handling (PR 6, the one addition): a
  -- DIFFERENT email row of the same account already holding this normalized
  -- Message-ID means a provider retry/reconcile echo re-reported an id that
  -- is already evidence elsewhere. Never fail the completion: stamp NULL on
  -- this row (it simply opts out of parent-probe dedupe) and say so loudly.
  -- This is what lets §C below make the msgid index UNIQUE.
  if v_msgid is not null and v_outbox.channel = 'email' then
    select o.id into v_dup_outbox_id
      from public.comm_outbox o
     where o.account_id = v_outbox.account_id
       and o.channel = 'email'
       and o.id <> v_outbox.id
       and o.rfc822_message_id is not null
       and public._comm_normalize_msgid(o.rfc822_message_id) = v_msgid
     limit 1;
    if v_dup_outbox_id is not null then
      raise warning
        'duplicate rfc822_message_id — evidence kept on the first row (first=%, completing=%)',
        v_dup_outbox_id, v_outbox.id;
      v_msgid := null;
    end if;
  end if;

  -- Relay leg: link to the original interaction, do NOT mint a copy.
  if v_outbox.relay_of_interaction_id is not null then
    update public.comm_outbox
       set status            = 'sent',
           provider          = p_provider,
           provider_sid      = p_provider_sid,
           rfc822_message_id = v_msgid,
           interaction_id    = v_outbox.relay_of_interaction_id,
           updated_at        = now()
     where id = p_outbox_id;
    return v_outbox.relay_of_interaction_id;
  end if;

  -- Party attribution + cast assembly. The identities were snapshotted at
  -- INTENT time (recipient_snapshot, stamped by trigger, frozen) — the cast
  -- copies that snapshot so identity edits between approval and completion
  -- can never rewrite who the send is recorded as reaching. The resolution
  -- fallbacks below exist only for legacy queued rows that predate the
  -- snapshot column (none in prod: comms are dormant).
  if v_outbox.group_addresses is not null then
    v_party_type := 'unspecified';
    v_party_id   := null;
    if v_outbox.recipient_snapshot is not null then
      for r in
        select e->>'address'                    as addr,
               e->>'party_type'                 as p_party_type,
               nullif(e->>'party_id', '')::uuid as p_party_id,
               e->>'label'                      as p_label
          from jsonb_array_elements(v_outbox.recipient_snapshot) e
      loop
        v_names := v_names || coalesce(r.p_label, r.addr);
        v_cast := v_cast || jsonb_build_array(jsonb_build_object(
          'role', 'recipient',
          'party_type', r.p_party_type,
          'party_id', r.p_party_id,
          'address', r.addr,
          'label', r.p_label));
      end loop;
    else
      for r in
        select ga.addr,
               ga.ord,
               p.party_type as p_party_type,
               p.party_id   as p_party_id
          from unnest(v_outbox.group_addresses) with ordinality ga(addr, ord)
          left join public.thread_channel_bindings b
            on b.account_id = v_outbox.account_id
           and b.thread_id = v_outbox.thread_id
           and b.participant_address = ga.addr
           and b.active
          left join public.comm_thread_participants p
            on p.id = b.participant_id
         order by ga.ord
      loop
        v_name := public._party_display_name(v_outbox.account_id, r.p_party_type, r.p_party_id);
        v_names := v_names || coalesce(v_name, r.addr);
        v_cast := v_cast || jsonb_build_array(jsonb_build_object(
          'role', 'recipient',
          'party_type', coalesce(r.p_party_type, 'unknown'),
          'party_id', r.p_party_id,
          'address', r.addr,
          'label', v_name));
      end loop;
    end if;
    v_party_label := left(array_to_string(v_names, ', '), 200);
  else
    if v_outbox.recipient_snapshot is not null then
      -- Attribution: the PRIMARY entry — the first without role='cc'. A copied
      -- party must never become who the journal row is "with".
      select t.e->>'party_type',
             nullif(t.e->>'party_id', '')::uuid,
             t.e->>'label'
        into v_cast_type, v_party_id, v_name
        from jsonb_array_elements(v_outbox.recipient_snapshot) with ordinality t(e, ord)
       where coalesce(t.e->>'role', 'recipient') <> 'cc'
       order by t.ord
       limit 1;
      v_party_type := case v_cast_type
        when 'tenant' then 'tenant'
        when 'vendor' then 'vendor'
        when 'unknown' then 'unspecified'
        else 'other'
      end;
      if v_party_type = 'unspecified' then
        v_party_id    := null;
        v_party_label := v_outbox.to_address;
      end if;
      -- Cast: EVERY snapshot entry, in order — primary as 'recipient', copied
      -- parties as 'cc'. Entry addresses come from the snapshot itself (the
      -- primary entry's address IS to_address, stamped at intent).
      select coalesce(jsonb_agg(jsonb_build_object(
               'role',       coalesce(t.e->>'role', 'recipient'),
               'party_type', t.e->>'party_type',
               'party_id',   nullif(t.e->>'party_id', '')::uuid,
               'address',    coalesce(t.e->>'address', v_outbox.to_address),
               'label',      t.e->>'label') order by t.ord), '[]'::jsonb)
        into v_cast
        from jsonb_array_elements(v_outbox.recipient_snapshot) with ordinality t(e, ord);
    else
      if v_outbox.participant_id is not null then
        select case p.party_type
                 when 'tenant' then 'tenant'
                 when 'vendor' then 'vendor'
                 else 'other'
               end,
               p.party_id,
               p.party_type
          into v_party_type, v_party_id, v_cast_type
          from public.comm_thread_participants p
         where p.id = v_outbox.participant_id;
        if v_party_type is not null then
          v_name := public._party_display_name(v_outbox.account_id, v_cast_type, v_party_id);
          v_cast := jsonb_build_array(jsonb_build_object(
            'role', 'recipient',
            'party_type', v_cast_type,
            'party_id', v_party_id,
            'address', v_outbox.to_address,
            'label', v_name));
        end if;
      end if;
      if v_party_type is null then
        -- Claims-aware fallback (PR 2 review fix): consult LIVE, scope-
        -- applicable claims through the one resolver. Exactly one party wins;
        -- a multi-claim conflict or a superseded-only address degrades to the
        -- 'unspecified' sentinel below instead of casting an arbitrary row.
        if (select count(*)
              from public._comm_resolve_identity_claims(
                     v_outbox.account_id, v_outbox.channel, v_outbox.to_address,
                     v_outbox.tenancy_id, v_outbox.thread_id)) = 1 then
          select case r.party_type
                   when 'tenant' then 'tenant'
                   when 'vendor' then 'vendor'
                   else 'other'
                 end,
                 r.party_id,
                 r.party_type,
                 public._party_display_name(v_outbox.account_id, r.party_type, r.party_id)
            into v_party_type, v_party_id, v_cast_type, v_name
            from public._comm_resolve_identity_claims(
                   v_outbox.account_id, v_outbox.channel, v_outbox.to_address,
                   v_outbox.tenancy_id, v_outbox.thread_id) r;
        end if;
        if v_party_type is not null then
          v_cast := jsonb_build_array(jsonb_build_object(
            'role', 'recipient',
            'party_type', v_cast_type,
            'party_id', v_party_id,
            'address', v_outbox.to_address,
            'label', v_name));
        end if;
      end if;
      if v_party_type is null then
        v_party_type  := 'unspecified';
        v_party_id    := null;
        v_party_label := v_outbox.to_address;
        v_cast := jsonb_build_array(jsonb_build_object(
          'role', 'recipient',
          'party_type', 'unknown',
          'party_id', null,
          'address', v_outbox.to_address,
          'label', null));
      end if;
    end if;
  end if;

  -- The platform leg that dialed: the thread's platform number (sms), or the
  -- recipient's minted reply token (email — the From that recipient sees).
  --
  -- For sms the FROZEN value on the row wins. It is the number the transport
  -- was told to dial from, so recording it makes the journal name what the
  -- carrier actually saw. Re-deriving from the binding at completion time
  -- could name a different number than the one dialed (a rebind between intent
  -- and completion, or an account that has come to hold more than one active
  -- number), and evidence that disagrees with the wire is worse than none.
  -- The binding read stays as the fallback for rows created before
  -- comm_outbox.platform_number existed.
  if v_outbox.channel = 'email' and v_outbox.participant_id is not null then
    select b.reply_address into v_sender_address
      from public.thread_channel_bindings b
     where b.account_id = v_outbox.account_id
       and b.thread_id = v_outbox.thread_id
       and b.participant_id = v_outbox.participant_id
       and b.active;
  elsif v_outbox.platform_number is not null then
    v_sender_address := v_outbox.platform_number;
  elsif v_outbox.thread_id is not null then
    select b.platform_number into v_sender_address
      from public.thread_channel_bindings b
     where b.account_id = v_outbox.account_id
       and b.thread_id = v_outbox.thread_id
       and b.platform_number is not null
     limit 1;
  end if;

  -- Filing scope: the intent's tenancy names the unit (tenancies.area_id is a
  -- NOT NULL unit FK), so the journal row files under its place and the
  -- view-derived property_id (20260718000003) lights up. Derived here — not
  -- frozen in the snapshot — because it is context, not an evidentiary claim
  -- about who was reached.
  if v_outbox.tenancy_id is not null then
    select t.area_id
      into v_area_id
      from public.tenancies t
     where t.account_id = v_outbox.account_id
       and t.id         = v_outbox.tenancy_id
       and t.deleted_at is null;
  end if;

  v_author_type := v_outbox.author_type;

  -- Journal body (20260703000001, regression caught by CI): an email send
  -- with a subject journals 'Subject: <subject>' + blank line + body — the
  -- documented shape the transport's rendering and the journal share. The
  -- superseded audience rework of this migration was rebuilt from the
  -- group-MMS body and silently dropped this; restored here.
  v_journal_body := case
    when v_outbox.channel = 'email' and v_outbox.subject is not null
      then 'Subject: ' || v_outbox.subject || e'\n\n' || v_outbox.body
    else v_outbox.body
  end;

  -- The capacity trigger would (rightly) reject e.g. the agent transport
  -- writing author_type='landlord'; this is the verified completion path,
  -- so exempt this transaction AFTER the checks above.
  perform set_config('comm.verified_write', 'on', true);

  insert into public.interactions (
    account_id, actor, author_type, approved_by, approval_ref,
    entry_type, external_ref, kind, channel, direction,
    party_type, party_id, party_label, body, occurred_at,
    corrects_id, correction_kind, thread_id, attestation,
    tenancy_id, maintenance_request_id, area_id, work_order_id, vendor_id,
    rfc822_message_id
  ) values (
    v_outbox.account_id,
    'user:' || auth.uid(),
    v_author_type,
    v_outbox.approved_by,
    v_outbox.approval_ref,
    null,
    p_provider_sid,
    'communication',
    public._comm_journal_channel(v_outbox.channel),
    'outbound',
    v_party_type,
    v_party_id,
    v_party_label,
    v_journal_body,
    now(),
    null,
    null,
    v_outbox.thread_id,
    -- Verified path: provider confirmed the send (sid above); GUC set.
    'provider_verified',
    -- carry the outbox's context onto the journal so the send shows up in
    -- the tenancy / maintenance-request activity feed.
    v_outbox.tenancy_id,
    v_outbox.maintenance_request_id,
    v_area_id,
    null,
    case when v_party_type = 'vendor' then v_party_id else null end,
    v_msgid
  )
  returning * into v_interaction;

  -- The cast: the platform leg that dialed + each dialed human, frozen from
  -- the intent. (No cast rows for relay legs: they never reach this point.)
  insert into public.interaction_participants
    (account_id, interaction_id, role, party_type, party_id, address, label, source)
  values
    (v_outbox.account_id, v_interaction.id, 'sender', 'platform', null,
     v_sender_address,
     case when v_sender_address is null then 'platform' else null end,
     'comms');

  insert into public.interaction_participants
    (account_id, interaction_id, role, party_type, party_id, address, label, source)
  select v_outbox.account_id, v_interaction.id,
         c.role, c.party_type, c.party_id, c.address, left(c.label, 200), 'comms'
    from jsonb_to_recordset(v_cast)
      as c(role text, party_type text, party_id uuid, address text, label text);

  update public.comm_outbox
     set status            = 'sent',
         provider          = p_provider,
         provider_sid      = p_provider_sid,
         rfc822_message_id = v_msgid,
         interaction_id    = v_interaction.id,
         updated_at        = now()
   where id = p_outbox_id;

  return v_interaction.id;
end;
$$;


ALTER FUNCTION "public"."complete_send"("p_outbox_id" "uuid", "p_provider" "text", "p_provider_sid" "text", "p_rfc822_message_id" "text") OWNER TO "postgres";

--
-- Name: confirm_unverified_sender("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."confirm_unverified_sender"("p_account_id" "uuid", "p_interaction_id" "uuid") RETURNS TABLE("id" "uuid", "attestation" "text", "party_type" "text", "party_id" "uuid", "address" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role text;
  v_row  public.interactions%rowtype;
  v_addr text;
begin
  select m.role into v_role
    from public.account_members m
   where m.user_id = auth.uid()
     and m.account_id = p_account_id
     and m.deleted_at is null;
  if v_role is null or v_role not in ('owner', 'manager') then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  -- A retracted row is gone from every member surface: uniform not-found.
  select * into v_row
    from public.interactions i
   where i.account_id = p_account_id
     and i.id = p_interaction_id
     and i.deleted_at is null
  for update;
  if not found then
    raise exception 'interaction not found' using errcode = 'P0002';
  end if;
  if v_row.attestation is distinct from 'unverified' then
    raise exception 'only unverified journal entries can be confirmed (attestation=%)',
      coalesce(v_row.attestation, 'null') using errcode = 'P0003';
  end if;
  if v_row.party_type not in ('tenant', 'vendor') or v_row.party_id is null then
    raise exception 'the entry names no confirmable tenant/vendor party'
      using errcode = 'P0003';
  end if;

  -- The claimed sender address, from the row's own cast (capture always
  -- writes the sender leg with the physical From).
  select ip.address into v_addr
    from public.interaction_participants ip
   where ip.account_id = p_account_id
     and ip.interaction_id = p_interaction_id
     and ip.role = 'sender'
     and ip.address is not null
   order by ip.created_at
   limit 1;
  if v_addr is null then
    raise exception 'the entry records no sender address to confirm'
      using errcode = 'P0003';
  end if;
  v_addr := lower(btrim(v_addr));

  -- A different party's live HUMAN claim is a hard stop, checked before any
  -- write so the confirm fails whole (two humans who disagree are reconciled
  -- by humans, not write order).
  if exists (
    select 1 from public.channel_identities ci
     where ci.account_id = p_account_id
       and ci.channel = 'email'
       and ci.address = v_addr
       and ci.superseded_at is null
       and ci.source = 'human_link'
       and (ci.party_type, ci.party_id) is distinct from (v_row.party_type, v_row.party_id)
  ) then
    raise exception 'conflicting human claim: % is already human-linked to another party',
      v_addr using errcode = 'P0003';
  end if;

  -- The learning step, human edition (link_unmatched_inbound semantics).
  update public.channel_identities ci
     set superseded_at = now(),
         updated_at    = now()
   where ci.account_id = p_account_id
     and ci.channel = 'email'
     and ci.address = v_addr
     and ci.superseded_at is null
     and ci.source in ('provider_learned', 'legacy')
     and (ci.party_type, ci.party_id) is distinct from (v_row.party_type, v_row.party_id);

  -- ON CONSTRAINT (not a column list): the conflict-target columns would be
  -- ambiguous against this function's OUT parameters under plpgsql variable
  -- substitution.
  insert into public.channel_identities
    (account_id, party_type, party_id, channel, address, source, created_by)
  values (p_account_id, v_row.party_type, v_row.party_id, 'email', v_addr,
          'human_link', auth.uid())
  on conflict on constraint channel_identities_claim_key
  do update set source        = 'human_link',
                superseded_at = null,
                created_by    = excluded.created_by,
                updated_at    = now();

  -- The one legal attestation transition, announced to the immutability
  -- guard (§B).
  perform set_config('comm.attestation_upgrade', 'on', true);
  update public.interactions i
     set attestation  = 'attested',
         confirmed_by = auth.uid(),
         confirmed_at = now(),
         updated_at   = now()
   where i.account_id = p_account_id
     and i.id = p_interaction_id;

  id          := p_interaction_id;
  attestation := 'attested';
  party_type  := v_row.party_type;
  party_id    := v_row.party_id;
  address     := v_addr;
  return next;
end;
$$;


ALTER FUNCTION "public"."confirm_unverified_sender"("p_account_id" "uuid", "p_interaction_id" "uuid") OWNER TO "postgres";

--
-- Name: create_account_for_new_user("text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_account_for_new_user"("p_account_name" "text", "p_display_name" "text" DEFAULT NULL::"text") RETURNS TABLE("account_id" "uuid", "role" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
declare
  v_user_id uuid := auth.uid();
  v_account_id uuid;
begin
  if v_user_id is null then
    raise exception 'no authenticated user' using errcode = '28000';
  end if;
  if p_account_name is null or length(trim(p_account_name)) = 0 then
    raise exception 'account_name is required' using errcode = '22023';
  end if;

  -- One-shot: refuse if the caller already has any membership. A future
  -- "create another account" endpoint will live elsewhere with different
  -- semantics (e.g., does the caller have permission to create accounts).
  if exists (select 1 from public.account_members where user_id = v_user_id) then
    raise exception 'user already has account memberships'
      using errcode = 'unique_violation';
  end if;

  -- (1) profile mirror. Idempotent so a retried call after a partial failure
  -- elsewhere doesn't trip a duplicate-key error.
  insert into public.users (id, display_name)
       values (v_user_id, p_display_name)
  on conflict (id) do nothing;

  -- (2) new account. sender_display_name defaults to the account name
  -- (C0/DEL/C1 control chars stripped — the same set the API validator
  -- rejects, so the default is always re-submittable through PATCH;
  -- landlords tune it via /email-branding).
  insert into public.accounts (name, sender_display_name)
       values (
         trim(p_account_name),
         nullif(
           left(regexp_replace(trim(p_account_name), E'[\\x01-\\x1F\\x7F\\u0080-\\u009F]', '', 'g'), 120),
           ''
         )
       )
    returning id into v_account_id;

  -- (3) owner membership. The audit trigger on account_members fires here
  -- and records actor = 'user:<v_user_id>' (the Phase-4 actor-integrity fix
  -- means audit.actor cannot override auth.uid()).
  insert into public.account_members (account_id, user_id, role)
       values (v_account_id, v_user_id, 'owner');

  account_id := v_account_id;
  role       := 'owner';
  return next;
end;
$$;


ALTER FUNCTION "public"."create_account_for_new_user"("p_account_name" "text", "p_display_name" "text") OWNER TO "postgres";

--
-- Name: create_inspection_from_template("uuid", "text", "text", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."create_inspection_from_template"("p_account_id" "uuid", "p_idempotency_key" "text", "p_request_fingerprint" "text", "p_payload" "jsonb") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $_$
declare
  v_idempotency       record;
  v_template_id       uuid;
  v_template_hash     text;
  v_template_schema   jsonb;
  v_template_snapshot jsonb;
  v_setup             jsonb;
  v_setup_mode        text;
  v_items             jsonb;
  v_checks            jsonb;
  v_section           jsonb;
  v_item              jsonb;
  v_section_key       text;
  v_item_key          text;
  v_item_key_base     text;
  v_item_key_suffix   int;
  v_item_key_suffix_text text;
  v_used_item_keys    text[] := array[]::text[];
  v_inspection        public.inspections;
  v_rooms_done        int := 0;
  v_rooms_total       int := 0;
  v_result            jsonb;
begin
  -- The HTTP idempotency middleware must have won the claim before calling
  -- this RPC. Lock that exact placeholder through the domain transaction so a
  -- same-key operation can neither reclaim nor complete it concurrently.
  select k.request_fingerprint, k.status_code, k.body, k.completed_at
    into v_idempotency
    from public.idempotency_keys k
   where k.account_id = p_account_id
     and k.key = p_idempotency_key
   for update;

  if not found then
    raise exception 'idempotency_key_not_claimed' using errcode = 'P0002';
  end if;
  if v_idempotency.request_fingerprint is distinct from p_request_fingerprint then
    raise exception 'idempotency_fingerprint_mismatch' using errcode = 'check_violation';
  end if;
  if v_idempotency.completed_at is not null
     or v_idempotency.status_code is not null
     or v_idempotency.body is not null
  then
    raise exception 'idempotency_key_not_in_flight' using errcode = 'check_violation';
  end if;

  if p_payload is null or jsonb_typeof(p_payload) is distinct from 'object' then
    raise exception 'payload must be a JSON object' using errcode = 'check_violation';
  end if;
  if p_payload - array[
    'area_id', 'tenancy_id', 'kind', 'capture_mode', 'template_id',
    'template_schema_hash', 'performed_at', 'notes', 'setup'
  ] <> '{}'::jsonb then
    raise exception 'payload contains unsupported fields' using errcode = 'check_violation';
  end if;
  if jsonb_typeof(p_payload->'area_id') is distinct from 'string'
     or jsonb_typeof(p_payload->'template_id') is distinct from 'string'
     or jsonb_typeof(p_payload->'template_schema_hash') is distinct from 'string'
     or (p_payload->>'template_schema_hash') !~ '^[a-f0-9]{32}$'
     or jsonb_typeof(p_payload->'kind') is distinct from 'string'
     or jsonb_typeof(p_payload->'capture_mode') is distinct from 'string'
  then
    raise exception 'area_id, template_id, template_schema_hash, kind and capture_mode are required'
      using errcode = 'check_violation';
  end if;
  if (p_payload->>'kind') not in ('move_in', 'move_out', 'periodic', 'general')
     or (p_payload->>'capture_mode') not in ('landlord', 'tenant', 'collaborative')
     or (p_payload ? 'tenancy_id' and jsonb_typeof(p_payload->'tenancy_id') is distinct from 'string')
     or (p_payload ? 'performed_at' and jsonb_typeof(p_payload->'performed_at') is distinct from 'string')
     or (p_payload ? 'notes' and jsonb_typeof(p_payload->'notes') is distinct from 'string')
     or char_length(coalesce(p_payload->>'notes', '')) > 20000
  then
    raise exception 'invalid inspection metadata' using errcode = 'check_violation';
  end if;

  v_template_id := nullif(p_payload->>'template_id', '')::uuid;
  select
      t.schema_hash,
      t.schema,
      jsonb_build_object(
        'id', t.id,
        'name', t.name,
        'jurisdiction', t.jurisdiction,
        'version', t.version,
        'catalog_id', t.catalog_id,
        'schema_hash', t.schema_hash,
        'schema', t.schema
      )
    into v_template_hash, v_template_schema, v_template_snapshot
    from public.inspection_templates t
   where t.account_id = p_account_id
     and t.id = v_template_id
     and t.deleted_at is null
   for share of t;

  if not found then
    raise exception 'template_not_found' using errcode = 'P0002';
  end if;
  -- A scratchpad is based on one exact schema revision. Refuse to reinterpret
  -- it against an edited template; the caller can reload and rebuild instead.
  if nullif(p_payload->>'template_schema_hash', '') is distinct from v_template_hash then
    raise exception 'template_schema_mismatch' using errcode = 'check_violation';
  end if;

  v_setup := p_payload->'setup';
  if v_setup is null or jsonb_typeof(v_setup) is distinct from 'object' then
    raise exception 'setup must be a JSON object' using errcode = 'check_violation';
  end if;
  v_setup_mode := v_setup->>'mode';
  if v_setup_mode not in ('final', 'template') or v_setup_mode is null then
    raise exception 'setup.mode must be final or template' using errcode = 'check_violation';
  end if;

  if v_setup_mode = 'final' then
    if v_setup - array['mode', 'items', 'checks'] <> '{}'::jsonb then
      raise exception 'final setup contains unsupported fields' using errcode = 'check_violation';
    end if;
    v_items  := v_setup->'items';
    v_checks := v_setup->'checks';
    if jsonb_typeof(v_items) is distinct from 'array'
       or jsonb_typeof(v_checks) is distinct from 'array'
    then
      raise exception 'final setup requires items and checks arrays'
        using errcode = 'check_violation';
    end if;
  elsif v_setup - 'mode' <> '{}'::jsonb then
    raise exception 'template setup contains unsupported fields' using errcode = 'check_violation';
  else
    -- Stored schemas are intentionally opaque at the template CRUD boundary,
    -- but the seeder only understands sections. Validate that expansion here so
    -- template mode cannot bypass the final-mode row limits or leak a database
    -- constraint error for malformed keys/types.
    if jsonb_typeof(v_template_schema) is distinct from 'object'
       or jsonb_typeof(v_template_schema->'sections') is distinct from 'array'
       or exists (
         select 1
           from jsonb_array_elements(v_template_schema->'sections') section
          where jsonb_typeof(section) is distinct from 'object'
             or jsonb_typeof(section->'key') is distinct from 'string'
             or coalesce(section->>'key', '') = ''
             or (section ? 'label'
                 and jsonb_typeof(section->'label') not in ('string', 'null'))
             or (section ? 'label'
                 and jsonb_typeof(section->'label') = 'string'
                 and (coalesce(section->>'label', '') = ''
                      or char_length(section->>'label') > 200))
             or (section ? 'items'
                 and jsonb_typeof(section->'items') is distinct from 'array')
             or (section ? 'checks'
                 and jsonb_typeof(section->'checks') is distinct from 'array')
       )
    then
      raise exception 'invalid template inspection section' using errcode = 'check_violation';
    end if;

    if exists (
      select 1
        from jsonb_array_elements(v_template_schema->'sections') section
        cross join lateral jsonb_array_elements(
          case when jsonb_typeof(section->'items') = 'array'
            then section->'items' else '[]'::jsonb end
        ) item
       where jsonb_typeof(item) is distinct from 'object'
          or (item ? 'key' and jsonb_typeof(item->'key') not in ('string', 'null'))
    ) then
      raise exception 'invalid template inspection item' using errcode = 'check_violation';
    end if;

    -- Reserve every explicit namespaced key up front. Duplicate explicit keys
    -- stay duplicated and are rejected by the shared validator below; only
    -- keyless rows receive generated identities.
    select coalesce(array_agg(
      (section->>'key') || '/' || (item->>'key') order by section_ord, item_ord
    ), array[]::text[])
      into v_used_item_keys
      from jsonb_array_elements(v_template_schema->'sections')
           with ordinality as sections(section, section_ord)
      cross join lateral jsonb_array_elements(
        case when jsonb_typeof(section->'items') = 'array'
          then section->'items' else '[]'::jsonb end
      ) with ordinality as items(item, item_ord)
     where jsonb_typeof(item->'key') = 'string'
       and coalesce(item->>'key', '') <> '';

    v_items := '[]'::jsonb;
    for v_section in
      select section
        from jsonb_array_elements(v_template_schema->'sections')
             with ordinality as sections(section, section_ord)
       order by section_ord
    loop
      v_section_key := v_section->>'key';
      for v_item in
        select item
          from jsonb_array_elements(
            case when jsonb_typeof(v_section->'items') = 'array'
              then v_section->'items' else '[]'::jsonb end
          ) with ordinality as items(item, item_ord)
         order by item_ord
      loop
        if jsonb_typeof(v_item->'key') = 'string'
           and coalesce(v_item->>'key', '') <> ''
        then
          v_item_key := v_section_key || '/' || (v_item->>'key');
        else
          -- Match the Create scratchpad's deterministic key minting:
          -- slugify(label, 'item'), then suffix _2, _3, ... on collision.
          -- Truncation keeps every generated key inside the API/DB 200-char
          -- bound, including its suffix.
          v_item_key_base := trim(both '_' from regexp_replace(
            lower(coalesce(nullif(v_item->>'label', ''), 'Untitled item')),
            '[^a-z0-9]+', '_', 'g'
          ));
          if v_item_key_base = '' then
            v_item_key_base := 'item';
          end if;
          v_item_key := left(v_item_key_base, 200);
          v_item_key_suffix := 1;
          while v_item_key = any(v_used_item_keys)
          loop
            v_item_key_suffix := v_item_key_suffix + 1;
            v_item_key_suffix_text := '_' || v_item_key_suffix::text;
            v_item_key := left(
              v_item_key_base,
              200 - char_length(v_item_key_suffix_text)
            ) || v_item_key_suffix_text;
          end loop;
          v_used_item_keys := array_append(v_used_item_keys, v_item_key);
        end if;

        v_items := v_items || jsonb_build_array(jsonb_strip_nulls(jsonb_build_object(
          'item_key', v_item_key,
          'label', case
            when v_item ? 'label'
                 and jsonb_typeof(v_item->'label') not in ('string', 'null')
              then v_item->'label'
            when jsonb_typeof(v_item->'label') = 'string'
                 and coalesce(v_item->>'label', '') <> ''
              then v_item->'label'
            when jsonb_typeof(v_item->'key') = 'string'
                 and coalesce(v_item->>'key', '') <> ''
              then v_item->'key'
            else to_jsonb('Untitled item'::text)
          end,
          'group_label', case when jsonb_typeof(v_section->'label') = 'string'
            then v_section->'label' else null end,
          'sort_order', case when v_item ? 'sort' then v_item->'sort' else null end
        )));
      end loop;
    end loop;

    select coalesce(jsonb_agg(
      jsonb_strip_nulls(jsonb_build_object(
        'field_key', case
          when jsonb_typeof(section->'key') = 'string'
           and coalesce(section->>'key', '') <> ''
           and jsonb_typeof(check_row->'key') = 'string'
           and coalesce(check_row->>'key', '') <> ''
          then to_jsonb((section->>'key') || '/' || (check_row->>'key'))
          else 'null'::jsonb
        end,
        'label', case when check_row ? 'label' and jsonb_typeof(check_row->'label') <> 'null'
          then check_row->'label' else check_row->'key' end,
        'group_label', case when jsonb_typeof(section->'label') = 'string'
          then section->'label' else null end,
        'sort_order', case when check_row ? 'sort' then check_row->'sort' else null end,
        'input_kind', case when check_row ? 'input_kind'
          then check_row->'input_kind' else null end
      )) order by section_ord, check_ord
    ), '[]'::jsonb)
      into v_checks
      from jsonb_array_elements(v_template_schema->'sections')
           with ordinality as sections(section, section_ord)
      cross join lateral jsonb_array_elements(
        case when jsonb_typeof(section->'checks') = 'array'
          then section->'checks' else '[]'::jsonb end
      ) with ordinality as checks(check_row, check_ord);
  end if;

  if jsonb_array_length(v_items) not between 1 and 1000
     or jsonb_array_length(v_checks) > 1000
  then
    raise exception 'setup requires 1-1000 items and at most 1000 checks'
      using errcode = 'check_violation';
  end if;

  -- Stable keys and labels are required. Reject hidden answer/evidence fields,
  -- invalid scalar types, out-of-range integers, and duplicate live keys so
  -- direct RPC callers receive the same setup-only contract as HTTP callers.
  if exists (
    select 1
      from jsonb_array_elements(v_items) item
     where jsonb_typeof(item) is distinct from 'object'
        or item - array['item_key', 'label', 'group_label', 'sort_order'] <> '{}'::jsonb
        or jsonb_typeof(item->'item_key') is distinct from 'string'
        or jsonb_typeof(item->'label') is distinct from 'string'
        or coalesce(item->>'item_key', '') = ''
        or coalesce(item->>'label', '') = ''
        or char_length(item->>'item_key') > 200
        or char_length(item->>'label') > 200
        or (item ? 'group_label' and jsonb_typeof(item->'group_label') is distinct from 'string')
        or (item ? 'group_label' and coalesce(item->>'group_label', '') = '')
        or char_length(coalesce(item->>'group_label', '')) > 200
        or (item ? 'sort_order' and not case
          when jsonb_typeof(item->'sort_order') = 'number'
           and (item->>'sort_order') ~ '^-?[0-9]+$'
          then (item->>'sort_order')::numeric between -2147483648 and 2147483647
          else false
        end)
  ) then
    raise exception 'invalid inspection item' using errcode = 'check_violation';
  end if;
  if exists (
    select 1 from jsonb_array_elements(v_items) item
     group by item->>'item_key' having count(*) > 1
  ) then
    raise exception 'duplicate inspection item key' using errcode = 'check_violation';
  end if;

  if exists (
    select 1
      from jsonb_array_elements(v_checks) check_row
     where jsonb_typeof(check_row) is distinct from 'object'
        or check_row - array['field_key', 'label', 'group_label', 'sort_order', 'input_kind'] <> '{}'::jsonb
        or jsonb_typeof(check_row->'field_key') is distinct from 'string'
        or jsonb_typeof(check_row->'label') is distinct from 'string'
        or coalesce(check_row->>'field_key', '') = ''
        or coalesce(check_row->>'label', '') = ''
        or char_length(check_row->>'field_key') > 200
        or char_length(check_row->>'label') > 200
        or (check_row ? 'group_label' and jsonb_typeof(check_row->'group_label') is distinct from 'string')
        or (check_row ? 'group_label' and coalesce(check_row->>'group_label', '') = '')
        or char_length(coalesce(check_row->>'group_label', '')) > 200
        or (check_row ? 'sort_order' and not case
          when jsonb_typeof(check_row->'sort_order') = 'number'
           and (check_row->>'sort_order') ~ '^-?[0-9]+$'
          then (check_row->>'sort_order')::numeric between -2147483648 and 2147483647
          else false
        end)
        or (check_row ? 'input_kind' and jsonb_typeof(check_row->'input_kind') is distinct from 'string')
        or (check_row->>'input_kind' is not null and check_row->>'input_kind' not in ('boolean', 'count', 'text'))
  ) then
    raise exception 'invalid inspection check' using errcode = 'check_violation';
  end if;
  if exists (
    select 1 from jsonb_array_elements(v_checks) check_row
     group by check_row->>'field_key' having count(*) > 1
  ) then
    raise exception 'duplicate inspection check key' using errcode = 'check_violation';
  end if;

  insert into public.inspections (
    account_id, area_id, template_id, kind, tenancy_id,
    capture_mode, performed_by, performed_at, notes, template_snapshot
  ) values (
    p_account_id,
    nullif(p_payload->>'area_id', '')::uuid,
    v_template_id,
    coalesce(nullif(p_payload->>'kind', ''), 'general'),
    nullif(p_payload->>'tenancy_id', '')::uuid,
    coalesce(nullif(p_payload->>'capture_mode', ''), 'landlord'),
    (select auth.uid()),
    nullif(p_payload->>'performed_at', '')::timestamptz,
    p_payload->>'notes',
    v_template_snapshot
  )
  returning * into v_inspection;

  -- Both final and stored-template modes now converge on one validated shape.
  -- Triggers still emit one truthful audit event per domain row, while each
  -- table is populated with one set-wise INSERT.
  insert into public.inspection_items (
    account_id, inspection_id, item_key, label, group_label, sort_order
  )
  select
    p_account_id,
    v_inspection.id,
    item->>'item_key',
    item->>'label',
    item->>'group_label',
    nullif(item->>'sort_order', '')::int
  from jsonb_array_elements(v_items) item;

  insert into public.inspection_checks (
    account_id, inspection_id, field_key, label, group_label,
    sort_order, input_kind
  )
  select
    p_account_id,
    v_inspection.id,
    check_row->>'field_key',
    check_row->>'label',
    check_row->>'group_label',
    nullif(check_row->>'sort_order', '')::int,
    check_row->>'input_kind'
  from jsonb_array_elements(v_checks) check_row;

  -- Match GET /inspections/:id exactly: null/empty group labels share the one
  -- ungrouped room, and a room is done when any live item has a condition.
  select count(*)::int,
         count(*) filter (where room.has_content)::int
    into v_rooms_total, v_rooms_done
    from (
      select nullif(it.group_label, '') as group_label,
             bool_or(it.condition is not null) as has_content
        from public.inspection_items it
       where it.account_id = p_account_id
         and it.inspection_id = v_inspection.id
         and it.deleted_at is null
       group by nullif(it.group_label, '')
    ) room;

  v_result := to_jsonb(v_inspection) || jsonb_build_object(
    'engagement', jsonb_build_object(
      'link_delivered_at', v_inspection.link_delivered_at,
      'form_opened_at', v_inspection.form_opened_at,
      'form_started_at', v_inspection.form_started_at,
      'submitted_at', v_inspection.submitted_at,
      'rooms_done', v_rooms_done,
      'rooms_total', v_rooms_total
    )
  );

  -- This completion is part of the same commit as the domain rows. Therefore
  -- a process crash after commit but before the HTTP response cannot leave a
  -- reclaimable in-flight key that would create a second inspection.
  update public.idempotency_keys
     set status_code = 201,
         body = v_result,
         completed_at = now()
   where account_id = p_account_id
     and key = p_idempotency_key
     and request_fingerprint = p_request_fingerprint
     and completed_at is null;
  if not found then
    raise exception 'idempotency_completion_lost' using errcode = 'check_violation';
  end if;

  return v_result;
end;
$_$;


