-- Name: comm_unmatched_inbound; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."comm_unmatched_inbound" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "provider" "text" NOT NULL,
    "provider_msg_id" "text" NOT NULL,
    "rfc822_message_id" "text",
    "persona_address" "text" NOT NULL,
    "from_address" "text" NOT NULL,
    "from_display_name" "text",
    "to_addresses" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "cc_addresses" "text"[] DEFAULT '{}'::"text"[] NOT NULL,
    "subject" "text",
    "body" "text",
    "media" "jsonb" DEFAULT '[]'::"jsonb" NOT NULL,
    "spf" "text",
    "dkim" "text",
    "dmarc" "text",
    "reason" "text" DEFAULT 'unknown_sender'::"text" NOT NULL,
    "received_at" timestamp with time zone NOT NULL,
    "status" "text" DEFAULT 'pending'::"text" NOT NULL,
    "resolved_by" "uuid",
    "resolved_at" timestamp with time zone,
    "linked_thread_id" "uuid",
    "linked_interaction_id" "uuid",
    "linked_party_type" "text",
    "linked_party_id" "uuid",
    "auto_acked_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "comm_unmatched_inbound_body_check" CHECK ((("body" IS NULL) OR ("length"("body") <= 20000))),
    CONSTRAINT "comm_unmatched_inbound_check" CHECK ((("status" = 'pending'::"text") = (("resolved_by" IS NULL) AND ("resolved_at" IS NULL)))),
    CONSTRAINT "comm_unmatched_inbound_check1" CHECK ((("status" = 'linked'::"text") = ("linked_interaction_id" IS NOT NULL))),
    CONSTRAINT "comm_unmatched_inbound_from_address_check" CHECK ((("length"("from_address") >= 3) AND ("length"("from_address") <= 320))),
    CONSTRAINT "comm_unmatched_inbound_from_display_name_check" CHECK ((("from_display_name" IS NULL) OR ("length"("from_display_name") <= 200))),
    CONSTRAINT "comm_unmatched_inbound_linked_party_type_check" CHECK ((("linked_party_type" IS NULL) OR ("linked_party_type" = ANY (ARRAY['tenant'::"text", 'vendor'::"text"])))),
    CONSTRAINT "comm_unmatched_inbound_persona_address_check" CHECK ((("length"("persona_address") >= 5) AND ("length"("persona_address") <= 320))),
    CONSTRAINT "comm_unmatched_inbound_provider_check" CHECK ((("length"("provider") >= 1) AND ("length"("provider") <= 100))),
    CONSTRAINT "comm_unmatched_inbound_provider_msg_id_check" CHECK ((("length"("provider_msg_id") >= 1) AND ("length"("provider_msg_id") <= 200))),
    CONSTRAINT "comm_unmatched_inbound_reason_check" CHECK (("reason" = ANY (ARRAY['unknown_sender'::"text", 'auth_failed'::"text", 'identity_conflict'::"text", 'parent_sender_mismatch'::"text"]))),
    CONSTRAINT "comm_unmatched_inbound_rfc822_message_id_check" CHECK ((("rfc822_message_id" IS NULL) OR (("length"("rfc822_message_id") >= 3) AND ("length"("rfc822_message_id") <= 998)))),
    CONSTRAINT "comm_unmatched_inbound_status_check" CHECK (("status" = ANY (ARRAY['pending'::"text", 'linked'::"text", 'dismissed'::"text"]))),
    CONSTRAINT "comm_unmatched_inbound_subject_check" CHECK ((("subject" IS NULL) OR ("length"("subject") <= 998)))
);

