--
-- Name: dismiss_unmatched_inbound("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."dismiss_unmatched_inbound"("p_account_id" "uuid", "p_unmatched_id" "uuid") RETURNS "public"."comm_unmatched_inbound"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role text;
  v_row  public.comm_unmatched_inbound%rowtype;
begin
  select m.role into v_role
    from public.account_members m
   where m.user_id = auth.uid()
     and m.account_id = p_account_id
     and m.deleted_at is null;
  if v_role is null or v_role not in ('owner', 'manager') then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  select * into v_row
    from public.comm_unmatched_inbound u
   where u.account_id = p_account_id
     and u.id = p_unmatched_id
  for update;
  if not found then
    raise exception 'unmatched row not found' using errcode = 'P0002';
  end if;
  -- Replay-friendly: dismissing a dismissed row returns it unchanged.
  if v_row.status = 'dismissed' then
    return v_row;
  end if;
  if v_row.status <> 'pending' then
    raise exception 'already resolved (%)', v_row.status using errcode = 'P0003';
  end if;

  update public.comm_unmatched_inbound
     set status      = 'dismissed',
         resolved_by = auth.uid(),
         resolved_at = now(),
         updated_at  = now()
   where account_id = p_account_id
     and id = p_unmatched_id
  returning * into v_row;
  return v_row;
end;
$$;


ALTER FUNCTION "public"."dismiss_unmatched_inbound"("p_account_id" "uuid", "p_unmatched_id" "uuid") OWNER TO "postgres";

--
-- Name: emit_inspection_report_document("uuid", "uuid", "uuid", "text", bigint, "text", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."emit_inspection_report_document"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_attachment_id" "uuid", "p_content_hash" "text", "p_size_bytes" bigint, "p_title" "text", "p_requires_ack" boolean DEFAULT true) RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_kind          text;
  v_tenancy       uuid;
  v_completed     timestamptz;
  v_doc           public.documents;
  v_ver           public.document_versions;
  v_existing_doc  uuid;
  v_next_ver      int;
begin
  select kind, tenancy_id, completed_at into v_kind, v_tenancy, v_completed
    from public.inspections
   where account_id = p_account_id
     and id = p_inspection_id
     and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_completed is null then
    raise exception 'inspection_not_completed' using errcode = 'P0002';
  end if;
  if v_kind not in ('move_in', 'move_out') then
    raise exception 'kind % does not emit a tenant document', v_kind
      using errcode = 'check_violation';
  end if;
  if v_tenancy is null then
    raise exception 'inspection has no tenancy' using errcode = 'check_violation';
  end if;

  select id into v_existing_doc
    from public.documents
   where account_id = p_account_id
     and inspection_id = p_inspection_id
     and deleted_at is null;

  if v_existing_doc is not null then
    select * into v_ver
      from public.document_versions
     where account_id = p_account_id
       and document_id = v_existing_doc
       and content_hash = p_content_hash
       and deleted_at is null
     order by version_no desc limit 1;
    if found then
      select * into v_doc from public.documents where id = v_existing_doc;
      return jsonb_build_object('document', to_jsonb(v_doc), 'version', to_jsonb(v_ver));
    end if;

    select coalesce(max(version_no), 0) + 1 into v_next_ver
      from public.document_versions
     where account_id = p_account_id and document_id = v_existing_doc;
    insert into internal.document_version_writer (
      account_id, document_id, version_no, source, attachment_id,
      content_hash, mime_type, size_bytes
    ) values (
      p_account_id, v_existing_doc, v_next_ver, 'inspection_report',
      p_attachment_id, p_content_hash, 'application/pdf', p_size_bytes
    ) returning * into v_ver;
    select * into v_doc from public.documents where id = v_existing_doc;
    return jsonb_build_object('document', to_jsonb(v_doc), 'version', to_jsonb(v_ver));
  end if;

  insert into public.documents (
    account_id, tenancy_id, document_type, title, requires_ack,
    published_at, created_by, inspection_id
  ) values (
    p_account_id, v_tenancy, v_kind, p_title, coalesce(p_requires_ack, true),
    now(), auth.uid(), p_inspection_id
  ) returning * into v_doc;

  insert into internal.document_version_writer (
    account_id, document_id, version_no, source, attachment_id,
    content_hash, mime_type, size_bytes
  ) values (
    p_account_id, v_doc.id, 1, 'inspection_report', p_attachment_id,
    p_content_hash, 'application/pdf', p_size_bytes
  ) returning * into v_ver;

  return jsonb_build_object('document', to_jsonb(v_doc), 'version', to_jsonb(v_ver));
end;
$$;


ALTER FUNCTION "public"."emit_inspection_report_document"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_attachment_id" "uuid", "p_content_hash" "text", "p_size_bytes" bigint, "p_title" "text", "p_requires_ack" boolean) OWNER TO "postgres";

--
-- Name: end_tenancy("uuid", "uuid", "text", "date", "text", "text", "text", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."end_tenancy"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_kind" "text", "p_effective_date" "date", "p_initiated_by" "text" DEFAULT 'unknown'::"text", "p_reason_code" "text" DEFAULT 'other'::"text", "p_reason_note" "text" DEFAULT NULL::"text", "p_source_notice_id" "uuid" DEFAULT NULL::"uuid", "p_source_interaction_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_tenancy public.tenancies%rowtype;
  v_ending public.tenancy_endings%rowtype;
  v_tenancy_end date;
begin
  perform pg_advisory_xact_lock(hashtextextended('tenancy_end:' || p_tenancy_id::text, 0));

  select *
    into v_tenancy
    from public.tenancies
   where account_id = p_account_id
     and id = p_tenancy_id
     and deleted_at is null
   for update;

  if v_tenancy.id is null then
    raise exception 'not_found: tenancy';
  end if;
  if v_tenancy.status = 'ended' then
    raise exception 'conflict: tenancy already ended';
  end if;
  if p_effective_date is null then
    raise exception 'invalid: effective_date is required';
  end if;
  if p_kind not in ('ended', 'cancelled_before_move_in') then
    raise exception 'invalid: kind must be ended or cancelled_before_move_in';
  end if;
  if p_initiated_by not in ('tenant', 'landlord', 'mutual', 'unknown') then
    raise exception 'invalid: initiated_by is not recognized';
  end if;

  if p_kind = 'cancelled_before_move_in' then
    if v_tenancy.status <> 'upcoming' then
      raise exception 'conflict: cancellation before move-in requires an upcoming tenancy';
    end if;
    if p_effective_date > v_tenancy.start_date then
      raise exception 'invalid: cancellation effective_date must be on or before start_date';
    end if;
    if p_reason_code not in ('applicant_withdrew', 'landlord_withdrew', 'other') then
      raise exception 'invalid: reason_code is not valid for cancelled_before_move_in';
    end if;
    v_tenancy_end := v_tenancy.start_date;
  else
    if v_tenancy.status not in ('active', 'holdover') then
      raise exception 'conflict: ending requires an active or holdover tenancy';
    end if;
    if p_effective_date < v_tenancy.start_date then
      raise exception 'invalid: ending effective_date cannot be before start_date';
    end if;
    -- Use an explicit UTC calendar date so a caller-controlled session
    -- timezone cannot turn tomorrow into today for this integrity check.
    if p_effective_date > (statement_timestamp() at time zone 'UTC')::date then
      raise exception 'invalid: ending effective_date cannot be in the future';
    end if;
    if p_reason_code not in (
      'notice', 'abandonment', 'fixed_term_completed', 'mutual_surrender', 'other'
    ) then
      raise exception 'invalid: reason_code is not valid for ended';
    end if;
    v_tenancy_end := p_effective_date;
  end if;

  if p_source_notice_id is not null and not exists (
    select 1
      from public.notices n
     where n.account_id = p_account_id
       and n.id = p_source_notice_id
       and n.tenancy_id = p_tenancy_id
       and n.deleted_at is null
  ) then
    raise exception 'not_found: source notice';
  end if;

  if p_source_interaction_id is not null and not exists (
    select 1
      from public.interactions i
     where i.account_id = p_account_id
       and i.id = p_source_interaction_id
       and i.tenancy_id = p_tenancy_id
       and i.deleted_at is null
  ) then
    raise exception 'not_found: source interaction';
  end if;

  perform set_config('app.tenancy_end_workflow', '1', true);

  insert into public.tenancy_endings (
    account_id, tenancy_id, kind, effective_date, initiated_by, reason_code,
    reason_note, source_notice_id, source_interaction_id
  ) values (
    p_account_id, p_tenancy_id, p_kind, p_effective_date, p_initiated_by,
    p_reason_code, p_reason_note, p_source_notice_id, p_source_interaction_id
  )
  returning * into v_ending;

  update public.tenancies
     set status = 'ended',
         end_date = v_tenancy_end,
         updated_at = now()
   where account_id = p_account_id
     and id = p_tenancy_id
  returning * into v_tenancy;

  return jsonb_build_object(
    'tenancy', to_jsonb(v_tenancy),
    'ending', to_jsonb(v_ending)
  );
exception
  when unique_violation then
    raise exception 'conflict: tenancy already has an ending record';
end;
$$;


ALTER FUNCTION "public"."end_tenancy"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_kind" "text", "p_effective_date" "date", "p_initiated_by" "text", "p_reason_code" "text", "p_reason_note" "text", "p_source_notice_id" "uuid", "p_source_interaction_id" "uuid") OWNER TO "postgres";

