    CONSTRAINT "comm_outbox_approval_ref_check" CHECK ((("length"("approval_ref") >= 1) AND ("length"("approval_ref") <= 200))),
    CONSTRAINT "comm_outbox_author_type_check" CHECK (("author_type" = ANY (ARRAY['landlord'::"text", 'agent'::"text", 'system'::"text"]))),
    CONSTRAINT "comm_outbox_body_check" CHECK ((("length"("body") >= 1) AND ("length"("body") <= 20000))),
    CONSTRAINT "comm_outbox_cc_email_only" CHECK ((("cc_addresses" IS NULL) OR ("channel" = 'email'::"text"))),
    CONSTRAINT "comm_outbox_cc_parties_is_array_check" CHECK ((("cc_parties" IS NULL) OR ("jsonb_typeof"("cc_parties") = 'array'::"text"))),
    CONSTRAINT "comm_outbox_cc_size" CHECK ((("cc_addresses" IS NULL) OR (("array_length"("cc_addresses", 1) >= 1) AND ("array_length"("cc_addresses", 1) <= 10)))),
    CONSTRAINT "comm_outbox_channel_check" CHECK (("channel" = ANY (ARRAY['sms'::"text", 'email'::"text", 'voice'::"text"]))),
    CONSTRAINT "comm_outbox_check" CHECK ((("channel" <> 'sms'::"text") OR ("length"("body") <= 1600))),
    CONSTRAINT "comm_outbox_group_shape" CHECK ((("to_address" IS NULL) = ("group_addresses" IS NOT NULL))),
    CONSTRAINT "comm_outbox_group_size" CHECK ((("group_addresses" IS NULL) OR (("array_length"("group_addresses", 1) >= 2) AND ("array_length"("group_addresses", 1) <= 7)))),
    CONSTRAINT "comm_outbox_group_thread" CHECK ((("group_addresses" IS NULL) OR ("thread_id" IS NOT NULL))),
    CONSTRAINT "comm_outbox_provenance_check" CHECK ((("approved_by" IS NOT NULL) OR ("approval_ref" ~~ 'grant:%'::"text") OR (("approval_ref" ~~ 'thread:%'::"text") AND ("relay_of_interaction_id" IS NOT NULL)) OR (("approval_ref" ~~ 'system:%'::"text") AND ("approved_by" IS NULL)))),
    CONSTRAINT "comm_outbox_provider_check" CHECK ((("length"("provider") >= 1) AND ("length"("provider") <= 100))),
    CONSTRAINT "comm_outbox_recipient_snapshot_check" CHECK ((("recipient_snapshot" IS NULL) OR ("jsonb_typeof"("recipient_snapshot") = 'array'::"text"))),
    CONSTRAINT "comm_outbox_rfc822_message_id_check" CHECK ((("rfc822_message_id" IS NULL) OR (("length"("rfc822_message_id") >= 3) AND ("length"("rfc822_message_id") <= 998)))),
    CONSTRAINT "comm_outbox_status_check" CHECK (("status" = ANY (ARRAY['queued'::"text", 'sending'::"text", 'sent'::"text", 'delivered'::"text", 'failed'::"text", 'undeliverable'::"text", 'needs_reconcile'::"text"]))),
    CONSTRAINT "comm_outbox_subject_check" CHECK ((("length"("subject") >= 1) AND ("length"("subject") <= 998))),
    CONSTRAINT "comm_outbox_subject_email_only" CHECK ((("subject" IS NULL) OR ("channel" = 'email'::"text"))),
    CONSTRAINT "comm_outbox_system_pairing" CHECK ((("approval_ref" ~~ 'system:%'::"text") = ("author_type" = 'system'::"text"))),
    CONSTRAINT "comm_outbox_template_id_check" CHECK ((("length"("template_id") >= 1) AND ("length"("template_id") <= 200))),
    CONSTRAINT "comm_outbox_to_address_check" CHECK ((("length"("to_address") >= 3) AND ("length"("to_address") <= 320))),
    CONSTRAINT "comm_outbox_to_party_pair_check" CHECK ((("to_party_type" IS NULL) = ("to_party_id" IS NULL))),
    CONSTRAINT "comm_outbox_to_party_type_check" CHECK ((("to_party_type" IS NULL) OR ("to_party_type" = ANY (ARRAY['tenant'::"text", 'vendor'::"text"]))))
);

