--
-- Name: fail_send("uuid", "text", "text", boolean); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."fail_send"("p_outbox_id" "uuid", "p_error_code" "text", "p_detail" "text" DEFAULT NULL::"text", "p_reconcile" boolean DEFAULT false) RETURNS "public"."comm_outbox"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_outbox public.comm_outbox%rowtype;
  v_target text := case when p_reconcile then 'needs_reconcile' else 'failed' end;
begin
  select * into v_outbox
    from public.comm_outbox
   where id = p_outbox_id
  for update;

  if not found then
    raise exception 'outbox row not found' using errcode = 'P0002';
  end if;

  -- Idempotent replay: already in the requested terminal/parked state.
  if v_outbox.status = v_target then
    return v_outbox;
  end if;

  if v_outbox.status not in ('queued', 'sending')
     and not (v_outbox.status = 'needs_reconcile' and not p_reconcile) then
    raise exception 'outbox row is not failable (status=%)', v_outbox.status
      using errcode = 'P0003';
  end if;

  update public.comm_outbox
     set status        = v_target,
         error_code    = p_error_code,
         error_message = p_detail,
         updated_at    = now()
   where id = p_outbox_id
  returning * into v_outbox;

  return v_outbox;
end;
$$;


ALTER FUNCTION "public"."fail_send"("p_outbox_id" "uuid", "p_error_code" "text", "p_detail" "text", "p_reconcile" boolean) OWNER TO "postgres";

--
-- Name: generate_rent_charges("uuid", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."generate_rent_charges"("p_account_id" "uuid", "p_as_of" timestamp with time zone) RETURNS TABLE("o_charge_id" "uuid", "o_schedule_id" "uuid", "o_period_start" "date", "o_amount_cents" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor   text := 'system:cron:rent';
  v_enabled boolean;
begin
  perform set_config('timezone', 'UTC', true);

  select a.auto_charge_enabled
    into v_enabled
    from public.accounts a
   where a.id = p_account_id
     and a.deleted_at is null;

  if not coalesce(v_enabled, false) then
    return;
  end if;

  perform set_config('audit.actor', v_actor, true);

  return query
    with derived as (
      select
        s.id, s.account_id, s.tenancy_id, s.kind, s.amount_cents, s.currency,
        s.due_day, s.start_date, s.end_date,
        case
          when extract(day from p_as_of)::int > s.due_day
          then (date_trunc('month', p_as_of) + interval '1 month'
                  + make_interval(days => s.due_day - 1))::date
          else (date_trunc('month', p_as_of)
                  + make_interval(days => s.due_day - 1))::date
        end as p_start
      from public.rent_schedules s
      where s.account_id = p_account_id
        and s.deleted_at is null
    ),
    eligible as (
      select d.*
        from derived d
        join public.tenancies t
          on t.account_id = d.account_id
         and t.id = d.tenancy_id
       where d.start_date <= d.p_start
         and (d.end_date is null or d.end_date >= d.p_start)
         and t.deleted_at is null
         and t.status <> 'ended'
         and (t.status = 'holdover' or t.end_date is null or t.end_date >= d.p_start)
    ),
    inserted as (
      insert into public.charges
        (account_id, tenancy_id, type, amount_cents, currency, due_date,
         period_start, period_end, description, source_schedule_id)
      select
        e.account_id,
        e.tenancy_id,
        case when e.kind = 'rent' then 'rent' else 'other' end,
        e.amount_cents,
        e.currency,
        e.p_start,
        e.p_start,
        (e.p_start + interval '1 month' - interval '1 day')::date,
        null,
        e.id
      from eligible e
      on conflict (source_schedule_id, period_start)
        where source_schedule_id is not null and period_start is not null
        do nothing
      returning id, source_schedule_id, period_start, amount_cents
    )
    select i.id, i.source_schedule_id, i.period_start, i.amount_cents
      from inserted i;
end;
$$;


ALTER FUNCTION "public"."generate_rent_charges"("p_account_id" "uuid", "p_as_of" timestamp with time zone) OWNER TO "postgres";

--
-- Name: generate_scheduled_task_runs("uuid", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."generate_scheduled_task_runs"("p_account_id" "uuid", "p_as_of" timestamp with time zone) RETURNS TABLE("o_run_id" "uuid", "o_task_id" "uuid", "o_period_start" "date")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor text := 'system:cron:tasks';
begin
  perform set_config('audit.actor', v_actor, true);

  return query
    with due_tasks as (
      select st.id, st.account_id
        from public.scheduled_tasks st
       where st.account_id = p_account_id
         and st.deleted_at is null
         and st.next_run is not null
         and st.next_run <= p_as_of
    ),
    inserted as (
      insert into public.scheduled_task_runs (account_id, task_id, period_start)
      select dt.account_id, dt.id, p_as_of::date
        from due_tasks dt
      on conflict (task_id, period_start) do nothing
      returning id, task_id, period_start
    )
    select i.id, i.task_id, i.period_start from inserted i;
end;
$$;


ALTER FUNCTION "public"."generate_scheduled_task_runs"("p_account_id" "uuid", "p_as_of" timestamp with time zone) OWNER TO "postgres";

--
-- Name: guard_agent_membership_delete(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."guard_agent_membership_delete"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
begin
  if exists (
    select 1 from public.agent_grants g
     where g.account_id    = new.account_id
       and g.agent_user_id = new.user_id
       and g.revoked_at is null
  ) then
    raise exception
      'cannot soft-delete an agent membership while an active agent_grant exists '
      '(account_id=%, user_id=%); revoke the grant instead',
      new.account_id, new.user_id
      using errcode = 'check_violation';
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."guard_agent_membership_delete"() OWNER TO "postgres";

--
-- Name: inspection_checkout_diff("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."inspection_checkout_diff"("p_account_id" "uuid", "p_checkout_inspection_id" "uuid") RETURNS TABLE("row_type" "text", "key" "text", "group_label" "text", "label" "text", "baseline_id" "uuid", "checkout_id" "uuid", "baseline_value" "text", "checkout_value" "text", "change_type" "text", "status" "text", "baseline_photo_count" integer, "checkout_photo_count" integer)
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
-- The RETURNS TABLE output columns (key, group_label, label, change_type,
-- status) share names with columns referenced in the subqueries below; tell
-- PL/pgSQL to resolve unqualified identifiers to the COLUMN, not the OUT var.
#variable_conflict use_column
declare
  v_kind     text;
  v_baseline uuid;
begin
  select kind, baseline_inspection_id into v_kind, v_baseline
    from public.inspections
    where account_id = p_account_id and id = p_checkout_inspection_id and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_kind <> 'move_out' then
    raise exception 'not a move_out inspection' using errcode = 'check_violation';
  end if;
  if v_baseline is null then
    raise exception 'no baseline to compare' using errcode = 'check_violation';
  end if;

  return query
  with
  base_items as (
    select it.id, it.item_key, it.group_label, it.label, it.condition
      from public.inspection_items it
      where it.account_id = p_account_id and it.inspection_id = v_baseline
        and it.deleted_at is null and it.item_key is not null
  ),
  co_items as (
    select it.id, it.item_key, it.group_label, it.label, it.condition, it.change_type
      from public.inspection_items it
      where it.account_id = p_account_id and it.inspection_id = p_checkout_inspection_id
        and it.deleted_at is null and it.item_key is not null
  ),
  item_photos as (
    select a.entity_id as item_id, count(*)::int as n
      from public.attachments a
      where a.account_id = p_account_id and a.entity_type = 'inspection_items'
        and a.deleted_at is null and a.derived_from is null
      group by a.entity_id
  )
  select
    'item'::text,
    coalesce(b.item_key, c.item_key),
    coalesce(c.group_label, b.group_label),
    coalesce(c.label, b.label),
    b.id, c.id,
    b.condition, c.condition,
    c.change_type,
    case when b.id is null then 'added_at_checkout'
         when c.id is null then 'missing_at_checkout'
         else 'matched' end,
    coalesce(bp.n, 0), coalesce(cp.n, 0)
  from base_items b
  full outer join co_items c on c.item_key = b.item_key
  left join item_photos bp on bp.item_id = b.id
  left join item_photos cp on cp.item_id = c.id

  union all

  select
    'check'::text,
    coalesce(b.field_key, c.field_key),
    coalesce(c.group_label, b.group_label),
    coalesce(c.label, b.label),
    b.id, c.id,
    b.value #>> '{}', c.value #>> '{}',
    null::text,
    case when b.id is null then 'added_at_checkout'
         when c.id is null then 'missing_at_checkout'
         else 'matched' end,
    0, 0
  from (
    select id, field_key, group_label, label, value
      from public.inspection_checks
      where account_id = p_account_id and inspection_id = v_baseline and deleted_at is null
  ) b
  full outer join (
    select id, field_key, group_label, label, value
      from public.inspection_checks
      where account_id = p_account_id and inspection_id = p_checkout_inspection_id and deleted_at is null
  ) c on c.field_key = b.field_key;
end;
$$;


ALTER FUNCTION "public"."inspection_checkout_diff"("p_account_id" "uuid", "p_checkout_inspection_id" "uuid") OWNER TO "postgres";

--
-- Name: is_account_member("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."is_account_member"("p_account_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select exists (
    select 1
    from public.account_members m
    where m.account_id = p_account_id
      and m.user_id    = (select auth.uid())
      and m.deleted_at is null
  );
$$;


