--
-- Name: is_approver_member("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."is_approver_member"("p_account_id" "uuid", "p_user_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  -- Guard: caller must themselves be a member; if not, return false so
  -- cross-account probes are indistinguishable from "not an approver".
  -- is_account_member() is security invoker and applies the caller's RLS.
  select
    public.is_account_member(p_account_id)
    and exists (
      select 1
      from public.account_members m
      where m.account_id  = p_account_id
        and m.user_id     = p_user_id
        and m.deleted_at  is null
        and m.role        <> 'agent'
    );
$$;


ALTER FUNCTION "public"."is_approver_member"("p_account_id" "uuid", "p_user_id" "uuid") OWNER TO "postgres";

--
-- Name: interactions; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."interactions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "actor" "text" NOT NULL,
    "party_type" "text" NOT NULL,
    "party_id" "uuid",
    "party_label" "text",
    "channel" "text" NOT NULL,
    "direction" "text" NOT NULL,
    "body" "text",
    "occurred_at" timestamp with time zone NOT NULL,
    "logged_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "tenancy_id" "uuid",
    "maintenance_request_id" "uuid",
    "area_id" "uuid",
    "work_order_id" "uuid",
    "vendor_id" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    "kind" "text" DEFAULT 'communication'::"text" NOT NULL,
    "corrects_id" "uuid",
    "correction_kind" "text",
    "author_type" "text",
    "approved_by" "uuid",
    "approval_ref" "text",
    "entry_type" "text",
    "external_ref" "text",
    "references_interaction_id" "uuid",
    "thread_id" "uuid",
    "attestation" "text",
    "rfc822_message_id" "text",
    "deleted_by" "uuid",
    "deleted_reason" "text",
    "confirmed_by" "uuid",
    "confirmed_at" timestamp with time zone,
    CONSTRAINT "interactions_actor_check" CHECK ((("length"("actor") >= 1) AND ("length"("actor") <= 200))),
    CONSTRAINT "interactions_agent_event_body_bound" CHECK ((("kind" <> 'agent_event'::"text") OR ("body" IS NULL) OR ("length"("body") <= 1000))),
    CONSTRAINT "interactions_agent_event_fields" CHECK ((("channel" <> 'agent_event'::"text") OR (("direction" = 'none'::"text") AND ("party_type" = 'none'::"text") AND ("party_id" IS NULL) AND ("party_label" IS NULL)))),
    CONSTRAINT "interactions_agent_event_shape" CHECK ((("kind" = 'agent_event'::"text") = ("channel" = 'agent_event'::"text"))),
    CONSTRAINT "interactions_agent_note_approval" CHECK (((NOT (("kind" = 'note'::"text") AND ("author_type" = 'agent'::"text"))) OR (("approved_by" IS NOT NULL) AND ("approval_ref" IS NOT NULL)))),
    CONSTRAINT "interactions_approval_ref_check" CHECK ((("length"("approval_ref") >= 1) AND ("length"("approval_ref") <= 200))),
    CONSTRAINT "interactions_attestation_check" CHECK ((("attestation" IS NULL) OR ("attestation" = ANY (ARRAY['provider_verified'::"text", 'attested'::"text", 'imported'::"text", 'unverified'::"text"])))),
    CONSTRAINT "interactions_attestation_kind_check" CHECK ((("kind" <> 'agent_event'::"text") OR ("attestation" IS NULL))),
    CONSTRAINT "interactions_author_type_check" CHECK (("author_type" = ANY (ARRAY['landlord'::"text", 'tenant'::"text", 'agent'::"text", 'system'::"text", 'vendor'::"text"]))),
    CONSTRAINT "interactions_channel_check" CHECK (("channel" = ANY (ARRAY['in_person'::"text", 'phone'::"text", 'voicemail'::"text", 'sms'::"text", 'email'::"text", 'letter'::"text", 'in_app'::"text", 'import'::"text", 'note'::"text", 'agent_event'::"text"]))),
    CONSTRAINT "interactions_confirm_pairing" CHECK ((("confirmed_by" IS NULL) = ("confirmed_at" IS NULL))),
    CONSTRAINT "interactions_correction_kind_check" CHECK (("correction_kind" = ANY (ARRAY['amend'::"text", 'retract'::"text", 'classify'::"text"]))),
    CONSTRAINT "interactions_correction_pairing" CHECK ((("corrects_id" IS NULL) = ("correction_kind" IS NULL))),
    CONSTRAINT "interactions_delete_stamp_pairing" CHECK ((("deleted_at" IS NOT NULL) OR (("deleted_by" IS NULL) AND ("deleted_reason" IS NULL)))),
    CONSTRAINT "interactions_deleted_reason_check" CHECK ((("deleted_reason" IS NULL) OR (("length"("deleted_reason") >= 1) AND ("length"("deleted_reason") <= 500)))),
    CONSTRAINT "interactions_direction_check" CHECK (("direction" = ANY (ARRAY['inbound'::"text", 'outbound'::"text", 'mutual'::"text", 'unspecified'::"text", 'none'::"text"]))),
    CONSTRAINT "interactions_direction_none_check" CHECK ((("direction" <> 'none'::"text") OR ("channel" = ANY (ARRAY['import'::"text", 'note'::"text", 'agent_event'::"text"])))),
    CONSTRAINT "interactions_entry_type_check" CHECK (("entry_type" = ANY (ARRAY['proposal_created'::"text", 'proposal_approved'::"text", 'proposal_rejected'::"text", 'step_executed'::"text", 'proposal_failed'::"text", 'proposal_blocked'::"text", 'resume_target_dead'::"text", 'proposal_superseded'::"text"]))),
    CONSTRAINT "interactions_entry_type_pairing" CHECK ((("entry_type" IS NOT NULL) = ("kind" = 'agent_event'::"text"))),
    CONSTRAINT "interactions_external_ref_check" CHECK ((("length"("external_ref") >= 1) AND ("length"("external_ref") <= 255))),
    CONSTRAINT "interactions_kind_check" CHECK (("kind" = ANY (ARRAY['communication'::"text", 'note'::"text", 'agent_event'::"text"]))),
    CONSTRAINT "interactions_note_fields" CHECK ((("channel" <> 'note'::"text") OR (("direction" = 'none'::"text") AND (("party_type" <> 'unspecified'::"text") OR ("party_id" IS NULL))))),
    CONSTRAINT "interactions_note_shape" CHECK ((("kind" = 'note'::"text") = ("channel" = 'note'::"text"))),
    CONSTRAINT "interactions_party_type_check" CHECK (("party_type" = ANY (ARRAY['tenant'::"text", 'vendor'::"text", 'inspector'::"text", 'other'::"text", 'none'::"text", 'unspecified'::"text"]))),
    CONSTRAINT "interactions_rfc822_message_id_len" CHECK ((("rfc822_message_id" IS NULL) OR (("length"("rfc822_message_id") >= 3) AND ("length"("rfc822_message_id") <= 998)))),
    CONSTRAINT "interactions_unspecified_comm_only" CHECK ((("party_type" <> 'unspecified'::"text") OR ("kind" = 'communication'::"text"))),
    CONSTRAINT "interactions_unspecified_party_no_id" CHECK ((("party_type" <> 'unspecified'::"text") OR ("party_id" IS NULL)))
);

ALTER TABLE ONLY "public"."interactions" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."interactions" OWNER TO "postgres";

--
-- Name: journal_with_participants("uuid", "jsonb", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."journal_with_participants"("p_account_id" "uuid", "p_entry" "jsonb", "p_participants" "jsonb") RETURNS "public"."interactions"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role        text;
  v_author_type text;
  v_interaction public.interactions%rowtype;
  v_count       int;
  r             record;
begin
  -- Self-defense: live member of the account.
  select m.role into v_role
    from public.account_members m
   where m.user_id = auth.uid()
     and m.account_id = p_account_id
     and m.deleted_at is null;
  if auth.uid() is null or v_role is null then
    raise exception 'not authorized to journal for this account'
      using errcode = '42501';
  end if;

  -- Agent principals are refused OUTRIGHT: an agent's communications are
  -- journaled (with their cast) by the verified comms paths, and an agent
  -- note carries no cast — so an agent calling this could only be
  -- fabricating an unverifiable record of who was contacted. (The capacity
  -- trigger would also reject the insert — external_ref is required on
  -- agent communications and this path never carries one — but the intent
  -- deserves its own explicit gate, not a fortunate trigger interaction.)
  if v_role = 'agent' then
    raise exception 'agent principals may not journal manual participants'
      using errcode = '42501';
  end if;

  -- Capacity from the principal, never from the caller's body.
  v_author_type := 'landlord';

  -- Only communications carry a cast (notes structurally have no party;
  -- agent_events are workflow exhaust).
  if coalesce(p_entry->>'kind', 'communication') <> 'communication' then
    raise exception 'participants are only recordable on communication entries'
      using errcode = '22023';
  end if;

  if p_participants is null or jsonb_typeof(p_participants) <> 'array' then
    raise exception 'participants must be a json array'
      using errcode = '22023';
  end if;
  v_count := jsonb_array_length(p_participants);
  if v_count < 1 or v_count > 20 then
    raise exception 'participants must contain between 1 and 20 entries'
      using errcode = '22023';
  end if;

  insert into public.interactions (
    account_id, actor, author_type, kind, channel, direction,
    party_type, party_id, party_label, body, occurred_at, attestation,
    tenancy_id, maintenance_request_id, area_id, work_order_id, vendor_id
  ) values (
    p_account_id,
    'user:' || auth.uid(),
    v_author_type,
    'communication',
    p_entry->>'channel',
    p_entry->>'direction',
    coalesce(p_entry->>'party_type', 'unspecified'),
    nullif(p_entry->>'party_id', '')::uuid,
    p_entry->>'party_label',
    p_entry->>'body',
    coalesce((p_entry->>'occurred_at')::timestamptz, now()),
    'attested',
    nullif(p_entry->>'tenancy_id', '')::uuid,
    nullif(p_entry->>'maintenance_request_id', '')::uuid,
    nullif(p_entry->>'area_id', '')::uuid,
    nullif(p_entry->>'work_order_id', '')::uuid,
    nullif(p_entry->>'vendor_id', '')::uuid
  )
  returning * into v_interaction;

  for r in
    select e->>'role'                       as role,
           e->>'party_type'                 as party_type,
           nullif(e->>'party_id', '')::uuid as party_id,
           e->>'address'                    as address,
           e->>'label'                      as label
      from jsonb_array_elements(p_participants) e
  loop
    if r.role is null or r.role not in ('sender', 'recipient', 'cc', 'attendee') then
      raise exception 'invalid participant role: %', coalesce(r.role, '(null)')
        using errcode = '22023';
    end if;
    -- 'platform' is reserved for the verified comms paths: a manual entry
    -- has no wire leg to claim.
    if r.party_type is null or r.party_type not in
       ('tenant', 'landlord_user', 'vendor', 'agent', 'inspector', 'other', 'unknown') then
      raise exception 'invalid participant party_type: %', coalesce(r.party_type, '(null)')
        using errcode = '22023';
    end if;
    insert into public.interaction_participants
      (account_id, interaction_id, role, party_type, party_id, address, label, source)
    values
      (p_account_id, v_interaction.id, r.role, r.party_type, r.party_id,
       r.address, r.label, 'capture');
  end loop;

  return v_interaction;
end;
$$;


ALTER FUNCTION "public"."journal_with_participants"("p_account_id" "uuid", "p_entry" "jsonb", "p_participants" "jsonb") OWNER TO "postgres";

--
-- Name: link_unmatched_inbound("uuid", "uuid", "text", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."link_unmatched_inbound"("p_account_id" "uuid", "p_unmatched_id" "uuid", "p_party_type" "text", "p_party_id" "uuid", "p_reply_domain" "text") RETURNS TABLE("thread_id" "uuid", "interaction_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_row         public.comm_unmatched_inbound%rowtype;
  v_role        text;
  v_thread_id   uuid;
  v_part_id     uuid;
  v_tenancy_id  uuid;
  v_interaction public.interactions%rowtype;
  v_dup_id      uuid;
  v_addr        text;
  v_cc_pt       text;
  v_cc_pid      uuid;
  v_cc_n        int;
begin
  -- Self-defense: owner|manager member (the agent principal may not resolve
  -- identity doubt — same posture as classify corrections).
  select m.role into v_role
    from public.account_members m
   where m.user_id = auth.uid()
     and m.account_id = p_account_id
     and m.deleted_at is null;
  if v_role is null or v_role not in ('owner', 'manager') then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  if p_party_type not in ('tenant', 'vendor') then
    raise exception 'party_type must be tenant or vendor' using errcode = '22023';
  end if;
  if p_party_type = 'tenant' and not exists (
    select 1 from public.tenants t
     where t.account_id = p_account_id and t.id = p_party_id and t.deleted_at is null
  ) then
    raise exception 'tenant not found' using errcode = 'P0002';
  end if;
  if p_party_type = 'vendor' and not exists (
    select 1 from public.vendors v
     where v.account_id = p_account_id and v.id = p_party_id and v.deleted_at is null
  ) then
    raise exception 'vendor not found' using errcode = 'P0002';
  end if;

  select * into v_row
    from public.comm_unmatched_inbound u
   where u.account_id = p_account_id
     and u.id = p_unmatched_id
  for update;
  if not found then
    raise exception 'unmatched row not found' using errcode = 'P0002';
  end if;
  if v_row.status <> 'pending' then
    raise exception 'already resolved (%)', v_row.status using errcode = 'P0003';
  end if;

  -- A different party's live HUMAN claim is a hard stop, checked before any
  -- journal write so the link fails whole.
  if exists (
    select 1 from public.channel_identities ci
     where ci.account_id = p_account_id
       and ci.channel = 'email'
       and ci.address = lower(btrim(v_row.from_address))
       and ci.superseded_at is null
       and ci.source = 'human_link'
       and (ci.party_type, ci.party_id) is distinct from (p_party_type, p_party_id)
  ) then
    raise exception 'conflicting human claim: % is already human-linked to another party',
      v_row.from_address using errcode = 'P0003';
  end if;

  select f.thread_id, f.cp_participant_id, f.tenancy_id
    into v_thread_id, v_part_id, v_tenancy_id
    from public._persona_find_or_create_thread(
      p_account_id, p_party_type, p_party_id, v_row.from_address,
      v_row.subject, p_reply_domain, null, null) f;

  -- The message may already be journaled (e.g. linked after a rebind let a
  -- later copy through) — link to the existing row rather than duplicating.
  if v_row.rfc822_message_id is not null then
    select i.id into v_dup_id
      from public.interactions i
     where i.account_id = p_account_id
       and i.rfc822_message_id = v_row.rfc822_message_id
       and i.thread_id = v_thread_id
     limit 1;
  end if;

  if v_dup_id is not null then
    select * into v_interaction from public.interactions where id = v_dup_id;
  else
    -- provider_verified only when the STORED verdicts authenticate the mail;
    -- a human vouching for an unauthenticated message is 'attested'.
    perform set_config('comm.verified_write', 'on', true);
    insert into public.interactions (
      account_id, actor, author_type, approved_by, approval_ref,
      entry_type, external_ref, kind, channel, direction,
      party_type, party_id, party_label, body, occurred_at,
      corrects_id, correction_kind, thread_id, attestation,
      tenancy_id, maintenance_request_id, area_id, work_order_id, vendor_id,
      rfc822_message_id
    ) values (
      p_account_id,
      'user:' || auth.uid(),
      case when p_party_type = 'vendor' then 'vendor' else 'tenant' end,
      null, null, null,
      v_row.provider_msg_id,
      'communication',
      public._comm_journal_channel('email'),
      'inbound',
      p_party_type,
      p_party_id,
      null,
      v_row.body,
      v_row.received_at,
      null, null,
      v_thread_id,
      case when v_row.dmarc = 'pass' then 'provider_verified' else 'attested' end,
      v_tenancy_id,
      null, null, null,
      case when p_party_type = 'vendor' then p_party_id else null end,
      v_row.rfc822_message_id
    )
    returning * into v_interaction;

    insert into public.interaction_participants
      (account_id, interaction_id, role, party_type, party_id, address, label, source)
    values
      (p_account_id, v_interaction.id, 'sender', p_party_type, p_party_id, v_row.from_address,
       left(coalesce(public._party_display_name(p_account_id, p_party_type, p_party_id),
                     v_row.from_display_name), 200),
       'comms'),
      (p_account_id, v_interaction.id, 'recipient', 'platform', null,
       v_row.persona_address, null, 'comms');

    for v_addr in
      select distinct x.addr
        from (
          select unnest(v_row.to_addresses) as addr
          union all
          select unnest(v_row.cc_addresses)
        ) x
       where x.addr is not null
         and length(x.addr) between 3 and 320
         and x.addr <> v_row.persona_address
         and x.addr <> v_row.from_address
    loop
      -- Same resolver-backed cc attribution as capture (single live winner or
      -- honest 'unknown'; no duplicate cast rows under multi-claim).
      v_cc_pt := null; v_cc_pid := null;
      select count(distinct (x.party_type, x.party_id)) into v_cc_n
        from public._comm_resolve_identity_claims(
               p_account_id, 'email', v_addr, v_tenancy_id, v_thread_id) x;
      if v_cc_n = 1 then
        select x.party_type, x.party_id into v_cc_pt, v_cc_pid
          from public._comm_resolve_identity_claims(
                 p_account_id, 'email', v_addr, v_tenancy_id, v_thread_id) x
         limit 1;
      end if;
      insert into public.interaction_participants
        (account_id, interaction_id, role, party_type, party_id, address, label, source)
      values
        (p_account_id, v_interaction.id, 'cc',
         coalesce(v_cc_pt, 'unknown'),
         v_cc_pid,
         v_addr,
         left(public._party_display_name(p_account_id, v_cc_pt, v_cc_pid), 200),
         'comms');
    end loop;
  end if;

  -- The learning step, human edition. Supersede (never delete) live learned/
  -- legacy claims that point at someone else…
  update public.channel_identities ci
     set superseded_at = now(),
         updated_at    = now()
   where ci.account_id = p_account_id
     and ci.channel = 'email'
     and ci.address = lower(btrim(v_row.from_address))
     and ci.superseded_at is null
     and ci.source in ('provider_learned', 'legacy')
     and (ci.party_type, ci.party_id) is distinct from (p_party_type, p_party_id);

  -- …then make the human claim live. A same-party row of any source (even a
  -- superseded one) is upgraded/revived so the link ALWAYS takes effect.
  insert into public.channel_identities
    (account_id, party_type, party_id, channel, address, source, created_by)
  values (p_account_id, p_party_type, p_party_id, 'email', v_row.from_address,
          'human_link', auth.uid())
  on conflict (account_id, channel, address, party_type, party_id, scope_type, scope_id)
  do update set source        = 'human_link',
                superseded_at = null,
                created_by    = excluded.created_by,
                updated_at    = now();

  update public.comm_unmatched_inbound
     set status                = 'linked',
         resolved_by           = auth.uid(),
         resolved_at           = now(),
         linked_thread_id      = v_thread_id,
         linked_interaction_id = v_interaction.id,
         linked_party_type     = p_party_type,
         linked_party_id       = p_party_id,
         updated_at            = now()
   where account_id = p_account_id
     and id = p_unmatched_id;

  thread_id      := v_thread_id;
  interaction_id := v_interaction.id;
  return next;
end;
$$;


ALTER FUNCTION "public"."link_unmatched_inbound"("p_account_id" "uuid", "p_unmatched_id" "uuid", "p_party_type" "text", "p_party_id" "uuid", "p_reply_domain" "text") OWNER TO "postgres";

--
-- Name: comm_opt_outs; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."comm_opt_outs" (
    "channel" "text" NOT NULL,
    "address" "text" NOT NULL,
    "opted_out_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "keyword" "text",
    "source_ref" "text",
    CONSTRAINT "comm_opt_outs_address_check" CHECK ((("length"("address") >= 3) AND ("length"("address") <= 320))),
    CONSTRAINT "comm_opt_outs_channel_check" CHECK (("channel" = ANY (ARRAY['sms'::"text", 'email'::"text", 'voice'::"text"]))),
    CONSTRAINT "comm_opt_outs_keyword_check" CHECK ((("length"("keyword") >= 1) AND ("length"("keyword") <= 50))),
    CONSTRAINT "comm_opt_outs_source_ref_check" CHECK ((("length"("source_ref") >= 1) AND ("length"("source_ref") <= 200)))
);

ALTER TABLE ONLY "public"."comm_opt_outs" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."comm_opt_outs" OWNER TO "postgres";

--
-- Name: list_account_opt_outs("uuid", "text", integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_account_opt_outs"("p_account_id" "uuid", "p_channel" "text" DEFAULT NULL::"text", "p_limit" integer DEFAULT 50, "p_offset" integer DEFAULT 0) RETURNS SETOF "public"."comm_opt_outs"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_limit  int := greatest(1, least(coalesce(p_limit, 50), 101));
  v_offset int := greatest(0, coalesce(p_offset, 0));
begin
  if auth.uid() is null or not exists (
    select 1 from public.account_members m
     where m.user_id = auth.uid()
       and m.account_id = p_account_id
       and m.deleted_at is null
  ) then
    raise exception 'not authorized to list opt-outs for this account'
      using errcode = '42501';
  end if;

  -- The channel_identities intersection scopes WHICH addresses are visible;
  -- keyword/source_ref are nulled because the register is global and carries
  -- no account provenance. Limit/offset are applied here so API pagination
  -- does not materialize the full visible register.
  return query
    select oo.channel, oo.address, oo.opted_out_at, null::text, null::text
      from public.comm_opt_outs oo
     where (p_channel is null or oo.channel = p_channel)
       and exists (
         select 1 from public.channel_identities ci
          where ci.account_id = p_account_id
            and ci.channel = oo.channel
            and ci.address = oo.address
       )
     order by oo.opted_out_at desc
     limit v_limit
     offset v_offset;
end;
$$;


ALTER FUNCTION "public"."list_account_opt_outs"("p_account_id" "uuid", "p_channel" "text", "p_limit" integer, "p_offset" integer) OWNER TO "postgres";

