--
-- Name: interactions_with_chain; Type: VIEW; Schema: public; Owner: postgres
--

CREATE OR REPLACE VIEW "public"."interactions_with_chain" WITH ("security_invoker"='true') AS
 SELECT "i"."id",
    "i"."account_id",
    "i"."actor",
    "i"."party_type",
    "i"."party_id",
    "i"."party_label",
    "i"."channel",
    "i"."direction",
    "i"."body",
    "i"."occurred_at",
    "i"."logged_at",
    "i"."tenancy_id",
    "i"."maintenance_request_id",
    "i"."area_id",
    "i"."work_order_id",
    "i"."vendor_id",
    "i"."created_at",
    "i"."updated_at",
    "i"."deleted_at",
    "i"."kind",
    "i"."corrects_id",
    "i"."correction_kind",
    "i"."author_type",
    "i"."approved_by",
    "i"."approval_ref",
    "i"."entry_type",
    "i"."external_ref",
    "i"."references_interaction_id",
    "i"."thread_id",
    "i"."attestation",
    "i"."rfc822_message_id",
    "c"."id" AS "superseded_by_id",
    ("c"."id" IS NULL) AS "is_head",
    "o"."id" AS "outbox_id",
    "o"."status" AS "delivery_status",
    "o"."delivered_at",
    "a"."property_id"
   FROM ((("public"."interactions" "i"
     LEFT JOIN "public"."interactions" "c" ON (("c"."corrects_id" = "i"."id")))
     LEFT JOIN "public"."comm_outbox" "o" ON ((("o"."interaction_id" = "i"."id") AND ("o"."relay_of_interaction_id" IS NULL))))
     LEFT JOIN "public"."areas" "a" ON ((("a"."account_id" = "i"."account_id") AND ("a"."id" = "i"."area_id"))));


ALTER VIEW "public"."interactions_with_chain" OWNER TO "postgres";

--
-- Name: list_interactions_for_party("uuid", "text", "uuid", "uuid", "uuid", "uuid", "text", boolean, timestamp with time zone, "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_interactions_for_party"("p_account_id" "uuid", "p_party_type" "text", "p_party_id" "uuid", "p_tenancy_id" "uuid", "p_maintenance_request_id" "uuid", "p_area_id" "uuid", "p_direction" "text", "p_latest_only" boolean, "p_before_occurred_at" timestamp with time zone, "p_before_id" "uuid", "p_limit" integer) RETURNS SETOF "public"."interactions_with_chain"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select v.*
  from public.interactions_with_chain v
  where v.account_id = p_account_id
    and v.deleted_at is null
    -- Resolve the person through the cast (semi-join), pruning parents that
    -- carry no matching participant. party_type, when supplied, narrows the
    -- SAME participant (a tenant leg vs. a vendor leg), never the row slot.
    and exists (
      select 1
        from public.interaction_participants ip
       where ip.account_id = v.account_id
         and ip.interaction_id = v.id
         and ip.party_id = p_party_id
         and (p_party_type is null or ip.party_type = p_party_type)
    )
    and (p_tenancy_id is null or v.tenancy_id = p_tenancy_id)
    and (p_maintenance_request_id is null or v.maintenance_request_id = p_maintenance_request_id)
    and (p_area_id is null or v.area_id = p_area_id)
    and (p_direction is null or v.direction = p_direction)
    and (not coalesce(p_latest_only, false) or v.is_head)
    -- Ascending (occurred_at, id) keyset: strictly after the last-seen row.
    and (
      p_before_occurred_at is null
      or v.occurred_at > p_before_occurred_at
      or (v.occurred_at = p_before_occurred_at and v.id > p_before_id)
    )
  order by v.occurred_at asc, v.id asc
  limit p_limit;
$$;


ALTER FUNCTION "public"."list_interactions_for_party"("p_account_id" "uuid", "p_party_type" "text", "p_party_id" "uuid", "p_tenancy_id" "uuid", "p_maintenance_request_id" "uuid", "p_area_id" "uuid", "p_direction" "text", "p_latest_only" boolean, "p_before_occurred_at" timestamp with time zone, "p_before_id" "uuid", "p_limit" integer) OWNER TO "postgres";

--
-- Name: list_interactions_for_party("uuid", "text", "uuid", "uuid", "uuid", "uuid", "uuid", "text", boolean, timestamp with time zone, "uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."list_interactions_for_party"("p_account_id" "uuid", "p_party_type" "text", "p_party_id" "uuid", "p_tenancy_id" "uuid", "p_maintenance_request_id" "uuid", "p_area_id" "uuid", "p_property_id" "uuid", "p_direction" "text", "p_latest_only" boolean, "p_before_occurred_at" timestamp with time zone, "p_before_id" "uuid", "p_limit" integer) RETURNS SETOF "public"."interactions_with_chain"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select v.*
  from public.interactions_with_chain v
  where v.account_id = p_account_id
    and v.deleted_at is null
    and exists (
      select 1
        from public.interaction_participants ip
       where ip.account_id = v.account_id
         and ip.interaction_id = v.id
         and ip.party_id = p_party_id
         and (p_party_type is null or ip.party_type = p_party_type)
    )
    and (p_tenancy_id is null or v.tenancy_id = p_tenancy_id)
    and (p_maintenance_request_id is null or v.maintenance_request_id = p_maintenance_request_id)
    and (p_area_id is null or v.area_id = p_area_id)
    and (p_property_id is null or v.property_id = p_property_id)
    and (p_direction is null or v.direction = p_direction)
    and (not coalesce(p_latest_only, false) or v.is_head)
    and (
      p_before_occurred_at is null
      or v.occurred_at > p_before_occurred_at
      or (v.occurred_at = p_before_occurred_at and v.id > p_before_id)
    )
  order by v.occurred_at asc, v.id asc
  limit p_limit;
$$;


ALTER FUNCTION "public"."list_interactions_for_party"("p_account_id" "uuid", "p_party_type" "text", "p_party_id" "uuid", "p_tenancy_id" "uuid", "p_maintenance_request_id" "uuid", "p_area_id" "uuid", "p_property_id" "uuid", "p_direction" "text", "p_latest_only" boolean, "p_before_occurred_at" timestamp with time zone, "p_before_id" "uuid", "p_limit" integer) OWNER TO "postgres";

--
-- Name: normalize_search_text("text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."normalize_search_text"("p_text" "text") RETURNS "text"
    LANGUAGE "sql" IMMUTABLE
    AS $$
  select btrim(
    regexp_replace(
      regexp_replace(
        regexp_replace(lower(coalesce(p_text, '')),
          '\y(apartment|apt|suite|ste)\y', 'unit', 'g'),
          '\y(bldg)\y', 'building', 'g'),
          '\s+', ' ', 'g')
  );
$$;


ALTER FUNCTION "public"."normalize_search_text"("p_text" "text") OWNER TO "postgres";

--
-- Name: prune_idempotency_keys(integer, integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."prune_idempotency_keys"("p_completed_ttl_seconds" integer DEFAULT 2592000, "p_in_flight_ttl_seconds" integer DEFAULT 604800) RETURNS TABLE("pruned_completed" integer, "pruned_in_flight" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_actor text := 'system:cron:janitor';
  v_completed int := 0;
  v_in_flight int := 0;
begin
  perform set_config('audit.actor', v_actor, true);

  -- (i) completed past TTL: safe -- the cached response is already old;
  -- any client retry past 30 days is semantically a new request.
  delete from public.idempotency_keys
   where completed_at is not null
     and completed_at < now() - make_interval(secs => p_completed_ttl_seconds);
  get diagnostics v_completed = row_count;

  -- (ii) in-flight WAY past any plausible client retry (7d default).
  -- A handler that committed always flips completed_at; a handler that
  -- crashed pre-commit leaves completed_at null. 7+ days later, any
  -- in-flight client retry has long given up; freeing the key is safe.
  delete from public.idempotency_keys
   where completed_at is null
     and created_at < now() - make_interval(secs => p_in_flight_ttl_seconds);
  get diagnostics v_in_flight = row_count;

  pruned_completed := v_completed;
  pruned_in_flight := v_in_flight;
  return next;
end;
$$;


ALTER FUNCTION "public"."prune_idempotency_keys"("p_completed_ttl_seconds" integer, "p_in_flight_ttl_seconds" integer) OWNER TO "postgres";

--
-- Name: prune_inbound_raw(interval); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."prune_inbound_raw"("p_older_than" interval DEFAULT '90 days'::interval) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_pruned integer;
begin
  delete from public.inbound_raw r
   where r.received_at < now() - p_older_than
     and not exists (
       select 1 from public.account_legal_holds h
        where h.account_id = r.matched_account_id
          and h.active
     );
  get diagnostics v_pruned = row_count;
  return v_pruned;
end;
$$;


ALTER FUNCTION "public"."prune_inbound_raw"("p_older_than" interval) OWNER TO "postgres";

--
-- Name: prune_ip_rate_buckets(integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."prune_ip_rate_buckets"("p_max_window_sec" integer DEFAULT 7200) RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_count int;
begin
  delete from public.ip_rate_buckets
   where window_start < now() - make_interval(secs => p_max_window_sec);
  get diagnostics v_count = row_count;
  return v_count;
end;
$$;


ALTER FUNCTION "public"."prune_ip_rate_buckets"("p_max_window_sec" integer) OWNER TO "postgres";

