-- Name: reconcile_scan("uuid", integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."reconcile_scan"("p_account_id" "uuid", "p_ttl_seconds" integer DEFAULT 3600) RETURNS SETOF "public"."comm_outbox"
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  select * from public.comm_outbox
   where account_id = p_account_id
     and status = 'sending'
     and updated_at < now() - make_interval(secs => p_ttl_seconds)
   order by updated_at asc;
$$;


