--
-- Name: inbound_provenance; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."inbound_provenance" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "provider" "text" NOT NULL,
    "provider_msg_id" "text" NOT NULL,
    "body_sha256" "text" NOT NULL,
    "signature" "text",
    "signature_timestamp" "text",
    "storage_path" "text" NOT NULL,
    "received_at" timestamp with time zone NOT NULL,
    "purged_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "inbound_provenance_body_sha256_check" CHECK (("body_sha256" ~ '^[0-9a-f]{64}$'::"text")),
    CONSTRAINT "inbound_provenance_provider_check" CHECK ((("length"("provider") >= 1) AND ("length"("provider") <= 100))),
    CONSTRAINT "inbound_provenance_signature_check" CHECK ((("length"("signature") >= 1) AND ("length"("signature") <= 2000))),
    CONSTRAINT "inbound_provenance_signature_timestamp_check" CHECK ((("length"("signature_timestamp") >= 1) AND ("length"("signature_timestamp") <= 100))),
    CONSTRAINT "inbound_provenance_storage_path_check" CHECK ((("length"("storage_path") >= 1) AND ("length"("storage_path") <= 1024)))
);

ALTER TABLE ONLY "public"."inbound_provenance" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."inbound_provenance" OWNER TO "postgres";

--
-- Name: record_inbound_provenance("uuid", "text", "text", "text", "text", "text", "text", timestamp with time zone); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_inbound_provenance"("p_account_id" "uuid", "p_provider" "text", "p_provider_msg_id" "text", "p_body_sha256" "text", "p_signature" "text", "p_signature_timestamp" "text", "p_storage_path" "text", "p_received_at" timestamp with time zone) RETURNS "public"."inbound_provenance"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.inbound_provenance%rowtype;
begin
  if auth.uid() is null or not exists (
    select 1 from public.account_members m
     where m.user_id = auth.uid()
       and m.account_id = p_account_id
       and m.role = 'agent'
       and m.deleted_at is null
  ) then
    raise exception 'not authorized to record inbound provenance for this account'
      using errcode = '42501';
  end if;

  insert into public.inbound_provenance (
    account_id, provider, provider_msg_id, body_sha256,
    signature, signature_timestamp, storage_path, received_at
  ) values (
    p_account_id, p_provider, p_provider_msg_id, lower(p_body_sha256),
    p_signature, p_signature_timestamp, p_storage_path, p_received_at
  )
  on conflict (provider_msg_id) do nothing
  returning * into v_row;

  if found then
    return v_row;
  end if;

  -- Replay. Answer from the committed row, pinned to the calling account —
  -- and refuse LOUDLY if the body hash disagrees: the first archived claim
  -- is the evidence; a differing retry must never silently win.
  select * into v_row
    from public.inbound_provenance
   where provider_msg_id = p_provider_msg_id;
  if v_row.account_id is distinct from p_account_id then
    raise exception 'provider_msg_id already archived for another account'
      using errcode = 'P0003';
  end if;
  if v_row.body_sha256 is distinct from lower(p_body_sha256) then
    raise exception 'provider_msg_id already archived with a different body hash'
      using errcode = 'P0003';
  end if;
  return v_row;
end;
$$;


ALTER FUNCTION "public"."record_inbound_provenance"("p_account_id" "uuid", "p_provider" "text", "p_provider_msg_id" "text", "p_body_sha256" "text", "p_signature" "text", "p_signature_timestamp" "text", "p_storage_path" "text", "p_received_at" timestamp with time zone) OWNER TO "postgres";

--
-- Name: record_opt_out("uuid", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_opt_out"("p_account_id" "uuid", "p_channel" "text", "p_address" "text", "p_keyword" "text", "p_source_ref" "text") RETURNS "public"."comm_opt_outs"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.comm_opt_outs%rowtype;
begin
  if auth.uid() is not null and not exists (
    select 1 from public.account_members m
     where m.user_id = auth.uid()
       and m.account_id = p_account_id
       and m.role = 'agent'
       and m.deleted_at is null
  ) then
    raise exception 'not authorized to record opt-outs for this account'
      using errcode = '42501';
  end if;

  -- Insert-or-nothing: RETURNING populates v_row only when THIS call created
  -- the row, so we echo keyword/source_ref only for our own fresh recording.
  insert into public.comm_opt_outs (channel, address, keyword, source_ref)
  values (p_channel, p_address, p_keyword, p_source_ref)
  on conflict (channel, address) do nothing
  returning * into v_row;

  if not found then
    -- Pre-existing registration (this or another account): return existence
    -- + timestamp only, never the stored recording metadata.
    select oo.channel, oo.address, oo.opted_out_at, null::text, null::text
      into v_row
      from public.comm_opt_outs oo
     where oo.channel = p_channel and oo.address = p_address;
  end if;

  -- Park queued-but-unsent intents to this address (compliance is global):
  -- 1:1 rows dialing it, and group rows whose recipient set contains it.
  update public.comm_outbox
     set status        = 'undeliverable',
         error_code    = 'opted_out',
         error_message = 'destination opted out before dispatch',
         updated_at    = now()
   where status = 'queued'
     and channel = p_channel
     and (to_address = p_address
          or (to_address is null and p_address = any(group_addresses)));

  return v_row;
end;
$$;


ALTER FUNCTION "public"."record_opt_out"("p_account_id" "uuid", "p_channel" "text", "p_address" "text", "p_keyword" "text", "p_source_ref" "text") OWNER TO "postgres";

--
-- Name: platform_numbers; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."platform_numbers" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "number" "text" NOT NULL,
    "provider" "text" NOT NULL,
    "capabilities" "text"[] DEFAULT '{sms}'::"text"[] NOT NULL,
    "status" "text" DEFAULT 'active'::"text" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "platform_numbers_number_check" CHECK (("number" ~ '^\+[1-9][0-9]{6,14}$'::"text")),
    CONSTRAINT "platform_numbers_provider_check" CHECK ((("length"("provider") >= 1) AND ("length"("provider") <= 100))),
    CONSTRAINT "platform_numbers_status_check" CHECK (("status" = ANY (ARRAY['active'::"text", 'released'::"text"])))
);

ALTER TABLE ONLY "public"."platform_numbers" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."platform_numbers" OWNER TO "postgres";

--
-- Name: record_platform_number("uuid", "text", "text", "text"[]); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."record_platform_number"("p_account_id" "uuid", "p_number" "text", "p_provider" "text", "p_capabilities" "text"[]) RETURNS "public"."platform_numbers"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.platform_numbers%rowtype;
  v_caps text[];
begin
  -- Agent-principal self-defense (mirrors set_owner_phone_verified and the
  -- comms-ledger RPCs). This is what makes an `authenticated` EXECUTE grant
  -- safe on a DEFINER function -- see db/test/check_definer_grants.sql.
  if auth.uid() is null or not exists (
    select 1
      from public.account_members m
     where m.account_id = p_account_id
       and m.user_id    = (select auth.uid())
       and m.role       = 'agent'
       and m.deleted_at is null
  ) then
    raise exception 'caller is not the agent principal for this account'
      using errcode = '42501';
  end if;

  v_caps := coalesce(nullif(p_capabilities, '{}'::text[]), array['sms']::text[]);

  -- An empty capabilities array would make the number invisible to
  -- POST /comms/threads (which filters with `capabilities @> [channel]`), so
  -- the account would hold a number it could never send from -- a silent
  -- black hole. Coalesced to {sms} above rather than rejected: the caller's
  -- intent when registering a number is unambiguous.
  insert into public.platform_numbers (account_id, number, provider, capabilities, status)
  values (p_account_id, p_number, p_provider, v_caps, 'active')
  on conflict (account_id, number) do update
     set provider     = excluded.provider,
         capabilities = excluded.capabilities,
         status       = 'active',
         updated_at   = now()
  returning * into v_row;

  return v_row;
end;
$$;


ALTER FUNCTION "public"."record_platform_number"("p_account_id" "uuid", "p_number" "text", "p_provider" "text", "p_capabilities" "text"[]) OWNER TO "postgres";

--
-- Name: rent_rollup("uuid", "text"[], "date"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."rent_rollup"("p_account_id" "uuid", "p_statuses" "text"[] DEFAULT ARRAY['active'::"text", 'holdover'::"text"], "p_as_of" "date" DEFAULT CURRENT_DATE) RETURNS TABLE("tenancy_id" "uuid", "status" "text", "currency" "text", "rent_balance_cents" bigint, "deposit_balance_cents" bigint, "unapplied_credit_cents" bigint, "non_deposit_overdue_cents" bigint, "non_deposit_due_today_cents" bigint, "non_deposit_upcoming_cents" bigint, "deposit_owed_cents" bigint, "deposit_held_cents" bigint)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  with t as (
    select id, tenancies.status
      from public.tenancies
     where account_id = p_account_id
       and deleted_at is null
       and tenancies.status = any(coalesce(p_statuses, array['active', 'holdover']))
  ),
  live_charges as (
    select c.id, c.tenancy_id, c.type, c.amount_cents, c.due_date
      from public.charges c
      join t on t.id = c.tenancy_id
     where c.account_id = p_account_id
       and c.deleted_at is null
       and c.voided_at is null
  ),
  live_payments as (
    select p.tenancy_id, sum(p.amount_cents) as received
      from public.payments p
      join t on t.id = p.tenancy_id
     where p.account_id = p_account_id
       and p.deleted_at is null
       and p.voided_at is null
     group by p.tenancy_id
  ),
  active_allocations_by_charge as (
    select c.id as charge_id, c.tenancy_id, sum(a.amount_cents) as allocated
      from public.payment_allocations a
      join live_charges c on c.id = a.charge_id
      join public.payments p
        on p.account_id = a.account_id
       and p.id = a.payment_id
       and p.tenancy_id = c.tenancy_id
     where a.account_id = p_account_id
       and a.deleted_at is null
       and p.deleted_at is null
       and p.voided_at is null
     group by c.id, c.tenancy_id
  ),
  charge_balances as (
    select c.*,
           coalesce(a.allocated, 0)::bigint as allocated,
           (c.amount_cents - coalesce(a.allocated, 0))::bigint as open_balance
      from live_charges c
      left join active_allocations_by_charge a on a.charge_id = c.id
  ),
  money as (
    select cb.tenancy_id,
           coalesce(sum(cb.open_balance) filter (where cb.type <> 'deposit'), 0)::bigint
             as rent_balance,
           coalesce(sum(cb.open_balance) filter (where cb.type = 'deposit'), 0)::bigint
             as deposit_owed,
           coalesce(sum(cb.allocated) filter (where cb.type = 'deposit'), 0)::bigint
             as deposit_held,
           coalesce(sum(cb.open_balance) filter (
             where cb.type <> 'deposit' and cb.due_date < p_as_of
           ), 0)::bigint as overdue,
           coalesce(sum(cb.open_balance) filter (
             where cb.type <> 'deposit' and cb.due_date = p_as_of
           ), 0)::bigint as due_today,
           coalesce(sum(cb.open_balance) filter (
             where cb.type <> 'deposit' and cb.due_date > p_as_of
           ), 0)::bigint as upcoming,
           coalesce(sum(cb.allocated), 0)::bigint as total_allocated
      from charge_balances cb
     group by cb.tenancy_id
  ),
  currencies as (
    select t.id as tenancy_id,
           (select min(c.currency) from public.charges c
             where c.account_id = p_account_id and c.tenancy_id = t.id
               and c.deleted_at is null) as charge_currency,
           (select min(p.currency) from public.payments p
             where p.account_id = p_account_id and p.tenancy_id = t.id
               and p.deleted_at is null) as payment_currency
      from t
  )
  select t.id,
         t.status,
         coalesce(cu.charge_currency, cu.payment_currency),
         coalesce(m.rent_balance, 0)::bigint,
         coalesce(m.deposit_owed, 0)::bigint,
         (coalesce(lp.received, 0) - coalesce(m.total_allocated, 0))::bigint,
         coalesce(m.overdue, 0)::bigint,
         coalesce(m.due_today, 0)::bigint,
         coalesce(m.upcoming, 0)::bigint,
         coalesce(m.deposit_owed, 0)::bigint,
         coalesce(m.deposit_held, 0)::bigint
    from t
    left join money         m  on m.tenancy_id = t.id
    left join live_payments lp on lp.tenancy_id = t.id
    left join currencies    cu on cu.tenancy_id = t.id
   where t.status <> 'ended'
      or coalesce(m.rent_balance, 0) <> 0
      or coalesce(m.deposit_owed, 0) <> 0
      or coalesce(m.deposit_held, 0) <> 0
      or (coalesce(lp.received, 0) - coalesce(m.total_allocated, 0)) <> 0
$$;


ALTER FUNCTION "public"."rent_rollup"("p_account_id" "uuid", "p_statuses" "text"[], "p_as_of" "date") OWNER TO "postgres";

--
-- Name: resolve_relay_landlord_recipient("uuid", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."resolve_relay_landlord_recipient"("p_account_id" "uuid", "p_user_id" "uuid", "p_source_interaction_id" "uuid", "p_fallback_address" "text") RETURNS TABLE("to_address" "text", "already_delivered" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_authoritative text;
begin
  -- Self-defense (DEFINER bypasses RLS): same roles as the send path (outbox
  -- POST). A viewer may not use this as an address->party confirm-oracle.
  if auth.uid() is null or not exists (
    select 1 from public.account_members m
     where m.user_id = auth.uid()
       and m.account_id = p_account_id
       and m.role in ('owner', 'manager', 'agent')
       and m.deleted_at is null
  ) then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  -- The authoritative email: the participant's own LIVE owner/manager member
  -- row joined to auth.users — the account_member tier of
  -- _comm_resolve_context_party, pinned to one user id instead of matched by
  -- address. 'agent'/'viewer' members deliberately resolve nothing: the cast
  -- vocabulary reserves landlord_user for the humans the CC arm copies.
  select nullif(lower(btrim(u.email)), '')
    into v_authoritative
    from public.account_members m
    join auth.users u on u.id = m.user_id
   where m.account_id = p_account_id
     and m.user_id    = p_user_id
     and m.deleted_at is null
     and m.role in ('owner', 'manager')
   limit 1;

  to_address := coalesce(v_authoritative, p_fallback_address);

  if to_address is null then
    -- No authoritative email and no fallback: the API answers with its
    -- existing "no destination address" 422.
    already_delivered := false;
    return next;
    return;
  end if;

  -- CC-overlap suppression: did the landlord already physically receive the
  -- relayed mail (any cast entry — a visible Cc, or the sender itself when a
  -- bad binding would bounce the tenant's own words back)? Lowercase compare
  -- only: a different spelling of the same mailbox does NOT suppress the leg.
  select exists (
    select 1
      from public.interaction_participants ip
     where ip.account_id     = p_account_id
       and ip.interaction_id = p_source_interaction_id
       and ip.address is not null
       and lower(btrim(ip.address))
             = lower(btrim(to_address))
  ) into already_delivered;

  return next;
end;
$$;


ALTER FUNCTION "public"."resolve_relay_landlord_recipient"("p_account_id" "uuid", "p_user_id" "uuid", "p_source_interaction_id" "uuid", "p_fallback_address" "text") OWNER TO "postgres";

--
-- Name: retract_unverified_interaction("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."retract_unverified_interaction"("p_account_id" "uuid", "p_interaction_id" "uuid", "p_reason" "text") RETURNS TABLE("id" "uuid", "deleted_at" timestamp with time zone, "deleted_reason" "text")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_role text;
  v_row  public.interactions%rowtype;
begin
  select m.role into v_role
    from public.account_members m
   where m.user_id = auth.uid()
     and m.account_id = p_account_id
     and m.deleted_at is null;
  if v_role is null or v_role not in ('owner', 'manager') then
    raise exception 'not authorized' using errcode = '42501';
  end if;

  -- The route validates too (Zod 1..500); this is the evidence-grade backstop.
  if p_reason is null or length(btrim(p_reason)) not between 1 and 500 then
    raise exception 'reason must be 1..500 characters' using errcode = '22023';
  end if;

  select * into v_row
    from public.interactions i
   where i.account_id = p_account_id
     and i.id = p_interaction_id
  for update;
  if not found then
    raise exception 'interaction not found' using errcode = 'P0002';
  end if;
  if v_row.deleted_at is not null then
    raise exception 'already retracted' using errcode = 'P0003';
  end if;
  if v_row.attestation is distinct from 'unverified' then
    raise exception 'only unverified journal entries can be retracted (attestation=%)',
      coalesce(v_row.attestation, 'null') using errcode = 'P0003';
  end if;

  update public.interactions i
     set deleted_at     = now(),
         deleted_by     = auth.uid(),
         deleted_reason = btrim(p_reason),
         updated_at     = now()
   where i.account_id = p_account_id
     and i.id = p_interaction_id
  returning i.id, i.deleted_at, i.deleted_reason
       into id, deleted_at, deleted_reason;
  return next;
end;
$$;


ALTER FUNCTION "public"."retract_unverified_interaction"("p_account_id" "uuid", "p_interaction_id" "uuid", "p_reason" "text") OWNER TO "postgres";

--
-- Name: search_entities("uuid", "text", "text"[], "text"[], integer); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."search_entities"("p_account_id" "uuid", "p_q" "text", "p_types" "text"[], "p_exclude" "text"[], "p_limit" integer) RETURNS TABLE("entity_type" "text", "entity_id" "uuid", "title" "text", "subtitle" "text", "score" real, "context" "jsonb")
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
declare
  v_q       text;
  v_pattern text;
begin
  if char_length(btrim(p_q)) < 2 then
    return;
  end if;

  v_q := public.normalize_search_text(p_q);
  if char_length(v_q) < 1 then
    return;
  end if;
  v_pattern := '%' || replace(replace(replace(v_q, '\', '\\'), '%', '\%'), '_', '\_') || '%';

  return query
  select
    s.entity_type, s.entity_id, s.title, s.subtitle, s.score,
    case
      -- tenant: current unit + property + is_primary + the tenant's OTHER tenancies.
      when s.entity_type = 'tenant' then (
        select jsonb_build_object(
          'kind',           'tenant',
          'unit_name',      ar.name,
          'property_name',  pr.name,
          'area_id',        ar.id,
          'tenancy_id',     tn.id,
          'tenancy_status', tn.status,
          'is_primary',     (tt.role = 'primary'),
          'other_tenancies', coalesce((
            select jsonb_agg(
              jsonb_build_object(
                'tenancy_id',     tn2.id,
                'unit_name',      ar2.name,
                'property_name',  pr2.name,
                'tenancy_status', tn2.status,
                'is_primary',     (tt2.role = 'primary')
              )
              order by tn2.start_date desc, tn2.id desc
            )
            from public.tenancy_tenants tt2
            join public.tenancies  tn2 on tn2.id = tt2.tenancy_id  and tn2.account_id = p_account_id and tn2.deleted_at is null
            join public.areas      ar2 on ar2.id = tn2.area_id     and ar2.account_id = p_account_id and ar2.deleted_at is null
            join public.properties pr2 on pr2.id = ar2.property_id and pr2.account_id = p_account_id and pr2.deleted_at is null
            where tt2.tenant_id  = s.entity_id
              and tt2.account_id = p_account_id
              and tt2.deleted_at is null
              and tn2.id <> tn.id
          ), '[]'::jsonb)
        )
        from public.tenancy_tenants tt
        join public.tenancies  tn on tn.id = tt.tenancy_id  and tn.account_id = p_account_id and tn.deleted_at is null
        join public.areas      ar on ar.id = tn.area_id     and ar.account_id = p_account_id and ar.deleted_at is null
        join public.properties pr on pr.id = ar.property_id and pr.account_id = p_account_id and pr.deleted_at is null
        where tt.tenant_id  = s.entity_id
          and tt.account_id = p_account_id
          and tt.deleted_at is null
        order by (tn.status in ('active','holdover')) desc, tn.start_date desc, tn.id desc
        limit 1
      )
      -- area: property disambiguator + occupancy + the active-tenancy handoff.
      when s.entity_type = 'area' then (
        select jsonb_build_object(
          'kind',              'area',
          'property_id',       p.id,
          'property_name',     p.name,
          'address',           nullif(p.address->>'line1', ''),
          'area_kind',         a.kind,
          'active_tenancy_id', act.tenancy_id,
          'tenant_names',      coalesce(act.tenant_names, array[]::text[]),
          'occupancy_status',  case when act.tenancy_id is not null then 'occupied' else 'vacant' end
        )
        from public.areas a
        join public.properties p
          on p.id = a.property_id and p.account_id = p_account_id and p.deleted_at is null
        left join lateral (
          select
            tn2.id as tenancy_id,
            array_remove(
              array_agg(te.full_name order by (tt2.role = 'primary') desc, te.full_name),
              null
            ) as tenant_names
          from public.tenancies tn2
          left join public.tenancy_tenants tt2
            on tt2.tenancy_id = tn2.id and tt2.account_id = p_account_id and tt2.deleted_at is null
          left join public.tenants te
            on te.id = tt2.tenant_id and te.account_id = p_account_id and te.deleted_at is null
          where tn2.area_id    = a.id
            and tn2.account_id = p_account_id
            and tn2.deleted_at is null
            and tn2.status in ('active', 'holdover')
          group by tn2.id, tn2.start_date
          order by tn2.start_date desc, tn2.id desc
          limit 1
        ) act on true
        where a.id = s.entity_id and a.account_id = p_account_id and a.deleted_at is null
      )
      -- property: address + unit count (the within-account disambiguators).
      when s.entity_type = 'property' then (
        select jsonb_build_object(
          'kind',       'property',
          'address',    nullif(p.address->>'line1', ''),
          'unit_count', (
            select count(*)::int
            from public.areas a
            where a.property_id = p.id and a.account_id = p_account_id
              and a.kind = 'unit' and a.deleted_at is null
          )
        )
        from public.properties p
        where p.id = s.entity_id and p.account_id = p_account_id and p.deleted_at is null
      )
      -- maintenance_request: status/severity/date + location ids + the latest
      -- assigned vendor + the area's current tenancy (DERIVED scope hint).
      when s.entity_type = 'maintenance_request' then (
        select jsonb_build_object(
          'kind',               'maintenance_request',
          'status',             m.status,
          'severity',           m.severity,
          'created_at',         m.created_at,
          'area_id',            m.area_id,
          'unit_name',          a.name,
          'property_name',      p.name,
          'assigned_vendor_id', wo.vendor_id,
          'tenancy_id',         act.tenancy_id
        )
        from public.maintenance_requests m
        join public.areas      a on a.id = m.area_id     and a.account_id = p_account_id and a.deleted_at is null
        join public.properties p on p.id = a.property_id and p.account_id = p_account_id and p.deleted_at is null
        left join lateral (
          select wo.vendor_id
          from public.work_orders wo
          where wo.maintenance_request_id = m.id
            and wo.account_id = p_account_id
            and wo.deleted_at is null
            and wo.vendor_id is not null
          order by wo.created_at desc
          limit 1
        ) wo on true
        left join lateral (
          select tn.id as tenancy_id
          from public.tenancies tn
          where tn.area_id = a.id and tn.account_id = p_account_id and tn.deleted_at is null
            and tn.status in ('active', 'holdover')
          order by tn.start_date desc, tn.id desc
          limit 1
        ) act on true
        where m.id = s.entity_id and m.account_id = p_account_id and m.deleted_at is null
      )
      -- vendor: outreach target + work-order history ("the vendor we used last time").
      when s.entity_type = 'vendor' then (
        select jsonb_build_object(
          'kind',         'vendor',
          'contact',      nullif(coalesce(v.contact->>'email', v.contact->>'phone'), ''),
          'last_used_at', wh.last_used_at,
          'job_count',    coalesce(wh.job_count, 0)
        )
        from public.vendors v
        left join lateral (
          select
            max(coalesce(wo.completed_at, wo.scheduled_for, wo.created_at)) as last_used_at,
            count(*)::int                                                   as job_count
          from public.work_orders wo
          where wo.vendor_id = v.id and wo.account_id = p_account_id and wo.deleted_at is null
        ) wh on true
        where v.id = s.entity_id and v.account_id = p_account_id and v.deleted_at is null
      )
      else null
    end as context
  from (
    -- ---- tenants ---------------------------------------------------------
    select
      'tenant'::text as entity_type,
      t.id           as entity_id,
      t.full_name    as title,
      nullif(array_to_string(t.emails, ', '), '') as subtitle,
      word_similarity(v_q, public.normalize_search_text(public.tenant_search_text(t.full_name, t.emails)))::real as score
    from public.tenants t
    where t.deleted_at is null
      and t.account_id = p_account_id
      and (p_types   is null or 'tenant' = any(p_types))
      and (p_exclude is null or 'tenant' <> all(p_exclude))
      and public.normalize_search_text(public.tenant_search_text(t.full_name, t.emails)) ilike v_pattern escape '\'

    union all

    -- ---- vendors ---------------------------------------------------------
    select
      'vendor'::text as entity_type,
      v.id           as entity_id,
      v.name         as title,
      nullif(coalesce(v.contact->>'email', v.contact->>'phone'), '') as subtitle,
      word_similarity(v_q, public.normalize_search_text(v.name || ' ' || coalesce(v.contact->>'email','') || ' ' || coalesce(v.contact->>'phone','')))::real as score
    from public.vendors v
    where v.deleted_at is null
      and v.account_id = p_account_id
      and (p_types   is null or 'vendor' = any(p_types))
      and (p_exclude is null or 'vendor' <> all(p_exclude))
      and public.normalize_search_text(v.name || ' ' || coalesce(v.contact->>'email','') || ' ' || coalesce(v.contact->>'phone','')) ilike v_pattern escape '\'

    union all

    -- ---- properties ------------------------------------------------------
    select
      'property'::text as entity_type,
      p.id             as entity_id,
      p.name           as title,
      nullif(p.address->>'line1', '') as subtitle,
      word_similarity(v_q, public.normalize_search_text(p.name || ' ' || coalesce(p.address->>'line1','')))::real as score
    from public.properties p
    where p.deleted_at is null
      and p.account_id = p_account_id
      and (p_types   is null or 'property' = any(p_types))
      and (p_exclude is null or 'property' <> all(p_exclude))
      and public.normalize_search_text(p.name || ' ' || coalesce(p.address->>'line1','')) ilike v_pattern escape '\'

    union all

    -- ---- areas -----------------------------------------------------------
    select
      'area'::text as entity_type,
      a.id         as entity_id,
      a.name       as title,
      a.kind       as subtitle,
      word_similarity(v_q, public.normalize_search_text(a.name))::real as score
    from public.areas a
    where a.deleted_at is null
      and a.account_id = p_account_id
      and (p_types   is null or 'area' = any(p_types))
      and (p_exclude is null or 'area' <> all(p_exclude))
      and public.normalize_search_text(a.name) ilike v_pattern escape '\'

    union all

    -- ---- maintenance_requests --------------------------------------------
    select
      'maintenance_request'::text as entity_type,
      m.id                        as entity_id,
      m.title                     as title,
      m.status                    as subtitle,
      word_similarity(v_q, public.normalize_search_text(m.title))::real as score
    from public.maintenance_requests m
    where m.deleted_at is null
      and m.account_id = p_account_id
      and (p_types   is null or 'maintenance_request' = any(p_types))
      and (p_exclude is null or 'maintenance_request' <> all(p_exclude))
      and public.normalize_search_text(m.title) ilike v_pattern escape '\'
  ) s
  order by s.score desc, s.title asc, s.entity_type asc
  limit greatest(p_limit, 0);
end;
$$;


ALTER FUNCTION "public"."search_entities"("p_account_id" "uuid", "p_q" "text", "p_types" "text"[], "p_exclude" "text"[], "p_limit" integer) OWNER TO "postgres";

--
-- Name: seed_inspection_items_from_template("uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."seed_inspection_items_from_template"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_template_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_completed     timestamptz;
  v_template_id   uuid;
  v_schema        jsonb;
  v_section       jsonb;
  v_item          jsonb;
  v_check         jsonb;
  v_section_key   text;
  v_section_label text;
  v_items         jsonb;
  v_checks        jsonb;
begin
  select completed_at, template_id into v_completed, v_template_id
    from public.inspections
    where account_id = p_account_id and id = p_inspection_id and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_completed is not null then
    raise exception 'inspection is completed' using errcode = 'check_violation';
  end if;

  v_template_id := coalesce(p_template_id, v_template_id);
  if v_template_id is null then
    raise exception 'no template to seed from' using errcode = 'check_violation';
  end if;

  select schema into v_schema
    from public.inspection_templates
    where account_id = p_account_id and id = v_template_id and deleted_at is null;
  if v_schema is null then
    raise exception 'template_not_found' using errcode = 'P0002';
  end if;

  for v_section in select * from jsonb_array_elements(coalesce(v_schema->'sections', '[]'::jsonb))
  loop
    v_section_key   := v_section->>'key';
    v_section_label := v_section->>'label';

    for v_item in select * from jsonb_array_elements(coalesce(v_section->'items', '[]'::jsonb))
    loop
      insert into public.inspection_items
        (account_id, inspection_id, label, item_key, group_label, sort_order)
      values
        (p_account_id, p_inspection_id,
         coalesce(v_item->>'label', v_item->>'key'),
         v_section_key || '/' || (v_item->>'key'),
         v_section_label,
         nullif(v_item->>'sort', '')::int)
      on conflict (inspection_id, item_key) where item_key is not null and deleted_at is null
      do nothing;
    end loop;

    for v_check in select * from jsonb_array_elements(coalesce(v_section->'checks', '[]'::jsonb))
    loop
      insert into public.inspection_checks
        (account_id, inspection_id, field_key, label, group_label, sort_order, input_kind)
      values
        (p_account_id, p_inspection_id,
         v_section_key || '/' || (v_check->>'key'),
         coalesce(v_check->>'label', v_check->>'key'),
         v_section_label,
         nullif(v_check->>'sort', '')::int,
         case when v_check->>'input_kind' in ('boolean', 'count', 'text')
              then v_check->>'input_kind' else null end)
      on conflict (inspection_id, field_key) where deleted_at is null
      do nothing;
    end loop;
  end loop;

  select coalesce(jsonb_agg(to_jsonb(it) order by it.sort_order nulls last, it.created_at, it.id), '[]'::jsonb)
    into v_items
    from public.inspection_items it
    where it.account_id = p_account_id and it.inspection_id = p_inspection_id and it.deleted_at is null;

  select coalesce(jsonb_agg(to_jsonb(ck) order by ck.sort_order nulls last, ck.created_at, ck.id), '[]'::jsonb)
    into v_checks
    from public.inspection_checks ck
    where ck.account_id = p_account_id and ck.inspection_id = p_inspection_id and ck.deleted_at is null;

  return jsonb_build_object('items', v_items, 'checks', v_checks);
end;
$$;


ALTER FUNCTION "public"."seed_inspection_items_from_template"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_template_id" "uuid") OWNER TO "postgres";

--
-- Name: users; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."users" (
    "id" "uuid" NOT NULL,
    "display_name" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    "phone" "text",
    "phone_verified_at" timestamp with time zone,
    CONSTRAINT "users_phone_check" CHECK ((("phone" IS NULL) OR ("phone" ~ '^\+[1-9][0-9]{6,14}$'::"text")))
);

ALTER TABLE ONLY "public"."users" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."users" OWNER TO "postgres";

--
-- Name: set_owner_phone_verified("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."set_owner_phone_verified"("p_account_id" "uuid", "p_user_id" "uuid", "p_phone" "text") RETURNS "public"."users"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_user public.users%rowtype;
begin
  if not exists (
    select 1 from public.account_members m
    where m.account_id = p_account_id
      and m.user_id    = (select auth.uid())
      and m.role       = 'agent'
      and m.deleted_at is null
  ) then
    raise exception 'caller is not the agent principal for this account'
      using errcode = '42501';
  end if;

  if not exists (
    select 1 from public.account_members m
    where m.account_id = p_account_id
      and m.user_id    = p_user_id
      and m.deleted_at is null
  ) then
    raise exception 'target user is not a member of this account'
      using errcode = 'P0002';
  end if;

  update public.users
     set phone             = p_phone,
         phone_verified_at = now(),
         updated_at        = now()
   where id = p_user_id
     and deleted_at is null
  returning * into v_user;

  if not found then
    raise exception 'user not found' using errcode = 'P0002';
  end if;

  return v_user;
end;
$$;


ALTER FUNCTION "public"."set_owner_phone_verified"("p_account_id" "uuid", "p_user_id" "uuid", "p_phone" "text") OWNER TO "postgres";

--
-- Name: inspections; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."inspections" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "area_id" "uuid" NOT NULL,
    "template_id" "uuid",
    "performed_by" "uuid",
    "performed_at" timestamp with time zone,
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    "completed_at" timestamp with time zone,
    "kind" "text" DEFAULT 'general'::"text" NOT NULL,
    "tenancy_id" "uuid",
    "baseline_inspection_id" "uuid",
    "status" "text" DEFAULT 'draft'::"text" NOT NULL,
    "capture_mode" "text" DEFAULT 'landlord'::"text" NOT NULL,
    "supersedes_inspection_id" "uuid",
    "voided_at" timestamp with time zone,
    "void_reason" "text",
    "template_snapshot" "jsonb",
    "subject_snapshot" "jsonb",
    "link_delivered_at" timestamp with time zone,
    "form_opened_at" timestamp with time zone,
    "form_started_at" timestamp with time zone,
    "submitted_at" timestamp with time zone,
    CONSTRAINT "inspections_capture_mode_check" CHECK (("capture_mode" = ANY (ARRAY['landlord'::"text", 'tenant'::"text", 'collaborative'::"text"]))),
    CONSTRAINT "inspections_kind_check" CHECK (("kind" = ANY (ARRAY['move_in'::"text", 'move_out'::"text", 'periodic'::"text", 'general'::"text"]))),
    CONSTRAINT "inspections_status_check" CHECK (("status" = ANY (ARRAY['draft'::"text", 'tenant_submitted'::"text", 'landlord_reviewed'::"text", 'completed'::"text", 'voided'::"text"]))),
    CONSTRAINT "inspections_void_reason_check" CHECK ((("void_reason" IS NULL) OR (("length"("void_reason") >= 1) AND ("length"("void_reason") <= 2000))))
);

ALTER TABLE ONLY "public"."inspections" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."inspections" OWNER TO "postgres";

--
-- Name: start_checkout_from_checkin("uuid", "uuid", timestamp with time zone, "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."start_checkout_from_checkin"("p_account_id" "uuid", "p_baseline_inspection_id" "uuid", "p_performed_at" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_template_id" "uuid" DEFAULT NULL::"uuid", "p_notes" "text" DEFAULT NULL::"text") RETURNS "public"."inspections"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_base public.inspections;
  v_new  public.inspections;
begin
  select * into v_base
    from public.inspections
    where account_id = p_account_id and id = p_baseline_inspection_id and deleted_at is null;
  if not found then
    raise exception 'baseline_not_found' using errcode = 'P0002';
  end if;
  if v_base.completed_at is null then
    raise exception 'baseline inspection must be completed' using errcode = 'check_violation';
  end if;
  if v_base.tenancy_id is null then
    raise exception 'baseline inspection has no tenancy' using errcode = 'check_violation';
  end if;

  insert into public.inspections
    (account_id, area_id, template_id, kind, tenancy_id, baseline_inspection_id,
     capture_mode, performed_by, performed_at, notes, status)
  values
    (p_account_id, v_base.area_id, coalesce(p_template_id, v_base.template_id),
     'move_out', v_base.tenancy_id, v_base.id, v_base.capture_mode,
     (select auth.uid()), p_performed_at, p_notes, 'draft')
  returning * into v_new;

  insert into public.inspection_items
    (account_id, inspection_id, label, item_key, group_label, sort_order)
  select p_account_id, v_new.id, it.label, it.item_key, it.group_label, it.sort_order
    from public.inspection_items it
    where it.account_id = p_account_id and it.inspection_id = v_base.id
      and it.deleted_at is null and it.item_key is not null;

  insert into public.inspection_checks
    (account_id, inspection_id, field_key, label, group_label, sort_order, input_kind)
  select p_account_id, v_new.id, ck.field_key, ck.label, ck.group_label, ck.sort_order, ck.input_kind
    from public.inspection_checks ck
    where ck.account_id = p_account_id and ck.inspection_id = v_base.id
      and ck.deleted_at is null;

  return v_new;
end;
$$;


ALTER FUNCTION "public"."start_checkout_from_checkin"("p_account_id" "uuid", "p_baseline_inspection_id" "uuid", "p_performed_at" timestamp with time zone, "p_template_id" "uuid", "p_notes" "text") OWNER TO "postgres";

--
-- Name: submit_intake("uuid", "uuid", "uuid", "text", "text", "text", timestamp with time zone, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."submit_intake"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_area_id" "uuid", "p_title" "text", "p_description" "text", "p_severity" "text", "p_occurred_at" timestamp with time zone, "p_actor" "text") RETURNS TABLE("maintenance_request_id" "uuid", "interaction_id" "uuid", "deduped" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
declare
  v_existing_req   uuid;
  v_new_req        uuid;
  v_interaction_id uuid;
  v_deduped        boolean := false;
begin
  -- Anchor the actor for this transaction. audit triggers fire AFTER each
  -- INSERT below and pick this value up via current_setting('audit.actor').
  -- set_config(..., true) = transaction-local, so this can't leak across
  -- requests on a pooled connection.
  perform set_config('audit.actor', p_actor, true);

  -- Dedupe: an OPEN, non-voided request on the same area with the same title.
  select id into v_existing_req
    from public.maintenance_requests
    where account_id = p_account_id
      and area_id    = p_area_id
      and status     = 'open'
      and title      = p_title
      and deleted_at is null
    limit 1;

  if v_existing_req is not null then
    v_new_req := v_existing_req;
    v_deduped := true;
  else
    insert into public.maintenance_requests
      (account_id, area_id, title, description, severity, status, intake_token)
    values
      (p_account_id, p_area_id, p_title, p_description, p_severity, 'open', p_actor)
    returning id into v_new_req;
  end if;

  insert into public.interactions
    (account_id, actor, party_type, channel, direction, body,
     occurred_at, tenancy_id, maintenance_request_id, area_id)
  values
    (p_account_id, p_actor, 'tenant', 'in_app', 'inbound',
     p_description, p_occurred_at, p_tenancy_id, v_new_req, p_area_id)
  returning id into v_interaction_id;

  maintenance_request_id := v_new_req;
  interaction_id         := v_interaction_id;
  deduped                := v_deduped;
  return next;
end;
$$;


ALTER FUNCTION "public"."submit_intake"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_area_id" "uuid", "p_title" "text", "p_description" "text", "p_severity" "text", "p_occurred_at" timestamp with time zone, "p_actor" "text") OWNER TO "postgres";

--
-- Name: submit_intake_with_attachment("uuid", "uuid", "uuid", "text", "text", "text", timestamp with time zone, "text", "text", "text", bigint, "text", "text", "text", bigint, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."submit_intake_with_attachment"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_area_id" "uuid", "p_title" "text", "p_description" "text", "p_severity" "text", "p_occurred_at" timestamp with time zone, "p_actor" "text", "p_attachment_hash" "text", "p_attachment_mime" "text", "p_attachment_size" bigint, "p_attachment_path" "text", "p_derivative_hash" "text" DEFAULT NULL::"text", "p_derivative_mime" "text" DEFAULT NULL::"text", "p_derivative_size" bigint DEFAULT NULL::bigint, "p_derivative_path" "text" DEFAULT NULL::"text") RETURNS TABLE("maintenance_request_id" "uuid", "interaction_id" "uuid", "attachment_id" "uuid", "derivative_id" "uuid", "deduped" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'auth'
    AS $$
declare
  v_existing_req   uuid;
  v_new_req        uuid;
  v_interaction_id uuid;
  v_attachment_id  uuid;
  v_derivative_id  uuid;
  v_deduped        boolean := false;
begin
  perform set_config('audit.actor', p_actor, true);

  select id into v_existing_req
    from public.maintenance_requests
    where account_id = p_account_id
      and area_id    = p_area_id
      and status     = 'open'
      and title      = p_title
      and deleted_at is null
    limit 1;

  if v_existing_req is not null then
    v_new_req := v_existing_req;
    v_deduped := true;
  else
    insert into public.maintenance_requests
      (account_id, area_id, title, description, severity, status, intake_token)
    values
      (p_account_id, p_area_id, p_title, p_description, p_severity, 'open', p_actor)
    returning id into v_new_req;
  end if;

  insert into public.interactions
    (account_id, actor, party_type, channel, direction, body,
     occurred_at, tenancy_id, maintenance_request_id, area_id)
  values
    (p_account_id, p_actor, 'tenant', 'in_app', 'inbound',
     p_description, p_occurred_at, p_tenancy_id, v_new_req, p_area_id)
  returning id into v_interaction_id;

  if p_attachment_hash is not null then
    -- Content idempotency: re-submitting the same bytes to the same (deduped)
    -- request must reuse the existing attachment row, not collide on
    -- attachments_content_idem_idx. DO NOTHING returns no row on conflict;
    -- fall back to the live row's id below.
    insert into public.attachments
      (account_id, entity_type, entity_id, storage_path, content_hash,
       mime_type, size_bytes, uploaded_by)
    values
      (p_account_id, 'maintenance_requests', v_new_req, p_attachment_path,
       p_attachment_hash, p_attachment_mime, p_attachment_size, null)
    on conflict (account_id, entity_type, entity_id, content_hash)
      where deleted_at is null
      do nothing
    returning id into v_attachment_id;

    if v_attachment_id is null then
      select id into v_attachment_id
        from public.attachments
       where account_id  = p_account_id
         and entity_type = 'maintenance_requests'
         and entity_id   = v_new_req
         and content_hash = p_attachment_hash
         and deleted_at is null
       order by received_at, created_at, id
       limit 1;
    end if;

    if p_derivative_hash is not null then
      insert into public.attachments
        (account_id, entity_type, entity_id, storage_path, content_hash,
         mime_type, size_bytes, uploaded_by, derived_from)
      values
        (p_account_id, 'maintenance_requests', v_new_req, p_derivative_path,
         p_derivative_hash, p_derivative_mime, p_derivative_size, null,
         v_attachment_id)
      on conflict (account_id, entity_type, entity_id, content_hash)
        where deleted_at is null
        do nothing
      returning id into v_derivative_id;

      if v_derivative_id is null then
        select id into v_derivative_id
          from public.attachments
         where account_id  = p_account_id
           and entity_type = 'maintenance_requests'
           and entity_id   = v_new_req
           and content_hash = p_derivative_hash
           and deleted_at is null
         order by received_at, created_at, id
         limit 1;
      end if;
    end if;
  end if;

  maintenance_request_id := v_new_req;
  interaction_id         := v_interaction_id;
  attachment_id          := v_attachment_id;
  derivative_id          := v_derivative_id;
  deduped                := v_deduped;
  return next;
end;
$$;


ALTER FUNCTION "public"."submit_intake_with_attachment"("p_account_id" "uuid", "p_tenancy_id" "uuid", "p_area_id" "uuid", "p_title" "text", "p_description" "text", "p_severity" "text", "p_occurred_at" timestamp with time zone, "p_actor" "text", "p_attachment_hash" "text", "p_attachment_mime" "text", "p_attachment_size" bigint, "p_attachment_path" "text", "p_derivative_hash" "text", "p_derivative_mime" "text", "p_derivative_size" bigint, "p_derivative_path" "text") OWNER TO "postgres";

--
-- Name: sync_agent_membership_from_grant(); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."sync_agent_membership_from_grant"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'pg_temp'
    AS $$
begin
  if new.revoked_at is null then
    -- Grant active: ensure the agent membership exists and is live. The WHERE
    -- on the conflict path skips a no-op write (and its audit event) when the
    -- row is already an active agent membership.
    insert into public.account_members (account_id, user_id, role, deleted_at, updated_at)
    values (new.account_id, new.agent_user_id, 'agent', null, now())
    on conflict (account_id, user_id) do update
      set deleted_at = null,
          role       = 'agent',
          updated_at = now()
      where account_members.deleted_at is not null
         or account_members.role <> 'agent';
  else
    -- Grant revoked: soft-delete the agent membership, but ONLY if no other
    -- active grant still covers this (account, agent_user) pairing.
    update public.account_members m
       set deleted_at = now(),
           updated_at = now()
     where m.account_id = new.account_id
       and m.user_id    = new.agent_user_id
       and m.role       = 'agent'
       and m.deleted_at is null
       and not exists (
         select 1 from public.agent_grants g
          where g.account_id    = new.account_id
            and g.agent_user_id = new.agent_user_id
            and g.revoked_at is null
       );
  end if;
  return new;
end;
$$;


ALTER FUNCTION "public"."sync_agent_membership_from_grant"() OWNER TO "postgres";

--
-- Name: tenant_attach_inspection_item_photo("uuid", "uuid", "uuid", "uuid", "text", "text", bigint, "text", "text", "text", bigint, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."tenant_attach_inspection_item_photo"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid", "p_item_id" "uuid", "p_attachment_hash" "text", "p_attachment_mime" "text", "p_attachment_size" bigint, "p_attachment_path" "text", "p_derivative_hash" "text" DEFAULT NULL::"text", "p_derivative_mime" "text" DEFAULT NULL::"text", "p_derivative_size" bigint DEFAULT NULL::bigint, "p_derivative_path" "text" DEFAULT NULL::"text") RETURNS TABLE("attachment_id" "uuid", "derivative_id" "uuid")
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_status        text;
  v_capture_mode  text;
  v_completed     timestamptz;
  v_attachment_id uuid;
  v_derivative_id uuid;
begin
  perform set_config('audit.actor', 'tenant:' || p_token_id::text, true);

  select status, capture_mode, completed_at
    into v_status, v_capture_mode, v_completed
    from public.inspections
    where account_id = p_account_id and id = p_inspection_id and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_completed is not null or v_status <> 'draft'
     or v_capture_mode not in ('tenant', 'collaborative') then
    raise exception 'not_editable_by_tenant' using errcode = 'check_violation';
  end if;

  perform 1
    from public.inspection_items
    where account_id = p_account_id and inspection_id = p_inspection_id
      and id = p_item_id and deleted_at is null;
  if not found then
    raise exception 'item_not_found' using errcode = 'P0002';
  end if;

  perform public._tenant_stamp_form_started(p_account_id, p_inspection_id);

  -- idempotency: identical bytes already attached to this item -> return the
  -- existing attachment (and its derivative, if any) without inserting.
  select id into v_attachment_id
    from public.attachments
    where account_id = p_account_id and entity_type = 'inspection_items'
      and entity_id = p_item_id and content_hash = p_attachment_hash
      and deleted_at is null
    limit 1;
  if found then
    select id into v_derivative_id
      from public.attachments
      where account_id = p_account_id and derived_from = v_attachment_id
        and deleted_at is null
      limit 1;
    attachment_id := v_attachment_id;
    derivative_id := v_derivative_id;
    return next;
    return;
  end if;

  insert into public.attachments
    (account_id, entity_type, entity_id, storage_path, content_hash,
     mime_type, size_bytes, uploaded_by)
  values
    (p_account_id, 'inspection_items', p_item_id, p_attachment_path,
     p_attachment_hash, p_attachment_mime, p_attachment_size, null)
  returning id into v_attachment_id;

  if p_derivative_hash is not null then
    insert into public.attachments
      (account_id, entity_type, entity_id, storage_path, content_hash,
       mime_type, size_bytes, uploaded_by, derived_from)
    values
      (p_account_id, 'inspection_items', p_item_id, p_derivative_path,
       p_derivative_hash, p_derivative_mime, p_derivative_size, null,
       v_attachment_id)
    returning id into v_derivative_id;
  end if;

  attachment_id := v_attachment_id;
  derivative_id := v_derivative_id;
  return next;
end;
$$;


ALTER FUNCTION "public"."tenant_attach_inspection_item_photo"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid", "p_item_id" "uuid", "p_attachment_hash" "text", "p_attachment_mime" "text", "p_attachment_size" bigint, "p_attachment_path" "text", "p_derivative_hash" "text", "p_derivative_mime" "text", "p_derivative_size" bigint, "p_derivative_path" "text") OWNER TO "postgres";

