CREATE OR REPLACE FUNCTION "public"."tenant_confirm_inspection_room"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid", "p_group_label" "text") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
