--
-- Name: tenant_submit_inspection("uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."tenant_submit_inspection"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid") RETURNS "public"."inspections"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.inspections;
begin
  perform set_config('audit.actor', 'tenant:' || p_token_id::text, true);

  update public.inspections
     set status = 'tenant_submitted', submitted_at = now(), updated_at = now()
   where account_id = p_account_id and id = p_inspection_id and deleted_at is null
     and completed_at is null and status = 'draft'
     and capture_mode in ('tenant', 'collaborative')
  returning * into v_row;
  if found then
    return v_row;
  end if;

  -- Not draft: re-fetch for idempotency / a precise error.
  select * into v_row
    from public.inspections
    where account_id = p_account_id and id = p_inspection_id and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_row.status = 'tenant_submitted' then
    return v_row; -- already submitted: idempotent
  end if;
  raise exception 'not_submittable' using errcode = 'check_violation';
end;
$$;


ALTER FUNCTION "public"."tenant_submit_inspection"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid") OWNER TO "postgres";

--
-- Name: inspection_items; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."inspection_items" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "inspection_id" "uuid" NOT NULL,
    "label" "text" NOT NULL,
    "condition" "text",
    "notes" "text",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    "item_key" "text",
    "group_label" "text",
    "change_type" "text",
    "sort_order" integer,
    CONSTRAINT "inspection_items_change_type_check" CHECK ((("change_type" IS NULL) OR ("change_type" = ANY (ARRAY['unchanged'::"text", 'normal_wear'::"text", 'damage'::"text", 'not_present_at_baseline'::"text", 'new_at_checkout'::"text"])))),
    CONSTRAINT "inspection_items_group_label_check" CHECK ((("group_label" IS NULL) OR (("length"("group_label") >= 1) AND ("length"("group_label") <= 200)))),
    CONSTRAINT "inspection_items_item_key_check" CHECK ((("item_key" IS NULL) OR (("length"("item_key") >= 1) AND ("length"("item_key") <= 200)))),
    CONSTRAINT "inspection_items_label_check" CHECK ((("length"("label") >= 1) AND ("length"("label") <= 200)))
);

