--
-- Name: tenant_upsert_inspection_checks("uuid", "uuid", "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."tenant_upsert_inspection_checks"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid", "p_checks" "jsonb") RETURNS SETOF "public"."inspection_checks"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_status       text;
  v_capture_mode text;
  v_completed    timestamptz;
begin
  perform set_config('audit.actor', 'tenant:' || p_token_id::text, true);

  select status, capture_mode, completed_at
    into v_status, v_capture_mode, v_completed
    from public.inspections
    where account_id = p_account_id and id = p_inspection_id and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_completed is not null or v_status <> 'draft'
     or v_capture_mode not in ('tenant', 'collaborative') then
    raise exception 'not_editable_by_tenant' using errcode = 'check_violation';
  end if;

  perform public._tenant_stamp_form_started(p_account_id, p_inspection_id);

  return query
  insert into public.inspection_checks
    (account_id, inspection_id, field_key, label, group_label, value, sort_order, input_kind, answered_by, answered_at)
  select
    p_account_id, p_inspection_id,
    e->>'field_key',
    case when e ? 'label' then coalesce(e->>'label', e->>'field_key')
         else coalesce(ex.label, e->>'field_key') end,
    case when e ? 'group_label' then e->>'group_label' else ex.group_label end,
    case when not (e ? 'value')                 then ex.value
         when jsonb_typeof(e->'value') = 'null' then null::jsonb
         else e->'value' end,
    case when e ? 'sort_order' then nullif(e->>'sort_order', '')::int else ex.sort_order end,
    case when e ? 'input_kind' then e->>'input_kind' else ex.input_kind end,
    case when not (e ? 'value')                 then ex.answered_by
         when jsonb_typeof(e->'value') = 'null' then null
         else ex.answered_by end,
    case when not (e ? 'value')                 then ex.answered_at
         when jsonb_typeof(e->'value') = 'null' then null
         else now() end
  from jsonb_array_elements(p_checks) as e
  left join public.inspection_checks ex
    on ex.inspection_id = p_inspection_id
   and ex.field_key = e->>'field_key'
   and ex.deleted_at is null
  where coalesce(e->>'field_key', '') <> ''
  on conflict (inspection_id, field_key) where deleted_at is null
  do update set
    label       = excluded.label,
    group_label = excluded.group_label,
    value       = excluded.value,
    sort_order  = excluded.sort_order,
    input_kind  = excluded.input_kind,
    answered_by = excluded.answered_by,
    answered_at = excluded.answered_at,
    updated_at  = now()
  returning *;
end;
$$;


ALTER FUNCTION "public"."tenant_upsert_inspection_checks"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid", "p_checks" "jsonb") OWNER TO "postgres";

--
-- Name: tenant_upsert_inspection_items("uuid", "uuid", "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."tenant_upsert_inspection_items"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid", "p_items" "jsonb") RETURNS SETOF "public"."inspection_items"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_status       text;
  v_capture_mode text;
  v_completed    timestamptz;
begin
  perform set_config('audit.actor', 'tenant:' || p_token_id::text, true);

  select status, capture_mode, completed_at
    into v_status, v_capture_mode, v_completed
    from public.inspections
    where account_id = p_account_id and id = p_inspection_id and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_completed is not null or v_status <> 'draft'
     or v_capture_mode not in ('tenant', 'collaborative') then
    raise exception 'not_editable_by_tenant' using errcode = 'check_violation';
  end if;

  -- Stamp form_started_at ONLY when >=1 item actually changes (all-unknown
  -- item_keys are a silent no-op and must not flip the funnel). The stamp is a
  -- data-modifying CTE gated on `exists (select 1 from upd)`, so it stays
  -- atomic with the update and matches the single-item PATCH's "on real write"
  -- semantics. (The set-once/completed guards live in the stamp CTE's WHERE.)
  return query
  with upd as (
    update public.inspection_items it
       set condition   = case when e ? 'condition'   then e->>'condition'   else it.condition   end,
           notes       = case when e ? 'notes'       then e->>'notes'       else it.notes       end,
           updated_at  = now()
      from jsonb_array_elements(p_items) as e
     where it.account_id    = p_account_id
       and it.inspection_id = p_inspection_id
       and it.item_key      = e->>'item_key'
       and coalesce(e->>'item_key', '') <> ''
       and it.deleted_at is null
    returning it.*
  ),
  stamp as (
    update public.inspections
       set form_started_at = now(), updated_at = now()
     where account_id = p_account_id and id = p_inspection_id
       and form_started_at is null and completed_at is null
       and exists (select 1 from upd)
    returning 1
  )
  select * from upd;
end;
$$;


ALTER FUNCTION "public"."tenant_upsert_inspection_items"("p_account_id" "uuid", "p_token_id" "uuid", "p_inspection_id" "uuid", "p_items" "jsonb") OWNER TO "postgres";

--
-- Name: update_delivery("uuid", "text", timestamp with time zone, "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."update_delivery"("p_outbox_id" "uuid", "p_status" "text", "p_provider_ts" timestamp with time zone, "p_error_code" "text" DEFAULT NULL::"text") RETURNS "public"."comm_outbox"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_outbox   public.comm_outbox%rowtype;
  v_cur_rank int;
  v_new_rank int;
begin
  select * into v_outbox
    from public.comm_outbox
   where id = p_outbox_id
  for update;

  if not found then
    raise exception 'outbox row not found' using errcode = 'P0002';
  end if;

  v_cur_rank := case v_outbox.status
    when 'queued' then 0 when 'sending' then 1 when 'needs_reconcile' then 2
    when 'sent' then 3 when 'delivered' then 4 else 9 end;
  v_new_rank := case p_status
    when 'sending' then 1 when 'sent' then 3 when 'delivered' then 4
    when 'failed' then 9 when 'undeliverable' then 9 else -1 end;

  -- Unknown status input, already-terminal row, or a non-forward move:
  -- return unchanged (callbacks are at-least-once and unordered).
  if v_new_rank = -1 or v_cur_rank = 9 or v_new_rank <= v_cur_rank then
    return v_outbox;
  end if;

  -- A row can only be marked sent/delivered through complete_send first
  -- (the journal append is what 'sent' MEANS); a callback for a row that
  -- was never completed must park for reconciliation instead of minting
  -- delivery state with no journal entry.
  if v_new_rank >= 3 and v_outbox.provider_sid is null then
    return v_outbox;
  end if;

  update public.comm_outbox
     set status        = p_status,
         error_code    = case when p_status in ('failed', 'undeliverable') then p_error_code else error_code end,
         error_message = case when p_status in ('failed', 'undeliverable') then coalesce(error_message, 'provider delivery failure') else error_message end,
         delivered_at  = case when p_status = 'delivered' then p_provider_ts else delivered_at end,
         updated_at    = now()
   where id = p_outbox_id
  returning * into v_outbox;

  return v_outbox;
end;
$$;


ALTER FUNCTION "public"."update_delivery"("p_outbox_id" "uuid", "p_status" "text", "p_provider_ts" timestamp with time zone, "p_error_code" "text") OWNER TO "postgres";

--
-- Name: upsert_inspection_checks("uuid", "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_inspection_checks"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_checks" "jsonb") RETURNS SETOF "public"."inspection_checks"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_completed timestamptz;
begin
  select completed_at into v_completed
    from public.inspections
    where account_id = p_account_id and id = p_inspection_id and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_completed is not null then
    raise exception 'inspection is completed' using errcode = 'check_violation';
  end if;

  return query
  insert into public.inspection_checks
    (account_id, inspection_id, field_key, label, group_label, value, sort_order, input_kind, answered_by, answered_at)
  select
    p_account_id, p_inspection_id,
    e->>'field_key',
    case when e ? 'label' then coalesce(e->>'label', e->>'field_key')
         else coalesce(ex.label, e->>'field_key') end,
    case when e ? 'group_label' then e->>'group_label' else ex.group_label end,
    case when not (e ? 'value')                 then ex.value
         when jsonb_typeof(e->'value') = 'null' then null::jsonb
         else e->'value' end,
    case when e ? 'sort_order' then nullif(e->>'sort_order', '')::int else ex.sort_order end,
    case when e ? 'input_kind' then e->>'input_kind' else ex.input_kind end,
    case when not (e ? 'value')                 then ex.answered_by
         when jsonb_typeof(e->'value') = 'null' then null
         else (select auth.uid()) end,
    case when not (e ? 'value')                 then ex.answered_at
         when jsonb_typeof(e->'value') = 'null' then null
         else now() end
  from jsonb_array_elements(p_checks) as e
  left join public.inspection_checks ex
    on ex.inspection_id = p_inspection_id
   and ex.field_key = e->>'field_key'
   and ex.deleted_at is null
  where coalesce(e->>'field_key', '') <> ''
  on conflict (inspection_id, field_key) where deleted_at is null
  do update set
    label       = excluded.label,
    group_label = excluded.group_label,
    value       = excluded.value,
    sort_order  = excluded.sort_order,
    input_kind  = excluded.input_kind,
    answered_by = excluded.answered_by,
    answered_at = excluded.answered_at,
    updated_at  = now()
  returning *;
end;
$$;


ALTER FUNCTION "public"."upsert_inspection_checks"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_checks" "jsonb") OWNER TO "postgres";

--
-- Name: upsert_inspection_items("uuid", "uuid", "jsonb"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."upsert_inspection_items"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_items" "jsonb") RETURNS SETOF "public"."inspection_items"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_completed timestamptz;
begin
  select completed_at into v_completed
    from public.inspections
    where account_id = p_account_id and id = p_inspection_id and deleted_at is null;
  if not found then
    raise exception 'inspection_not_found' using errcode = 'P0002';
  end if;
  if v_completed is not null then
    raise exception 'inspection is completed' using errcode = 'check_violation';
  end if;

  return query
  insert into public.inspection_items
    (account_id, inspection_id, label, item_key, group_label, condition, notes, change_type, sort_order)
  select
    p_account_id, p_inspection_id,
    coalesce(e->>'label', e->>'item_key'),
    e->>'item_key',
    e->>'group_label',
    e->>'condition',
    e->>'notes',
    e->>'change_type',
    nullif(e->>'sort_order', '')::int
  from jsonb_array_elements(p_items) as e
  where coalesce(e->>'item_key', '') <> ''
  on conflict (inspection_id, item_key) where item_key is not null and deleted_at is null
  do update set
    label       = excluded.label,
    group_label = excluded.group_label,
    condition   = excluded.condition,
    notes       = excluded.notes,
    change_type = excluded.change_type,
    sort_order  = excluded.sort_order,
    updated_at  = now()
  returning *;
end;
$$;


ALTER FUNCTION "public"."upsert_inspection_items"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_items" "jsonb") OWNER TO "postgres";

--
-- Name: verify_chain("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."verify_chain"("p_account_id" "uuid") RETURNS TABLE("ok" boolean, "broken_at" "uuid", "broken_event_no" bigint, "reason" "text")
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  e          record;
  v_prev     bytea := decode(repeat('00', 32), 'hex');
  v_canonical jsonb;
  v_expected bytea;
  v_n        bigint := 0;
begin
  for e in
    select id, account_id, account_seq, entity_type, entity_id, event_type, payload,
           occurred_at, prev_event_hash, event_hash
    from public.events
    where account_id = p_account_id
    order by account_seq asc
  loop
    v_n := v_n + 1;

    if e.account_seq <> v_n then
      ok := false; broken_at := e.id; broken_event_no := v_n;
      reason := format('account_seq gap at position %s: row has account_seq %s', v_n, e.account_seq);
      return next; return;
    end if;

    if e.prev_event_hash is distinct from v_prev then
      ok := false; broken_at := e.id; broken_event_no := v_n;
      reason := 'prev_event_hash mismatch';
      return next; return;
    end if;

    v_canonical := jsonb_build_object(
      'account_id',  e.account_id,
      'account_seq', e.account_seq,
      'entity_id',   e.entity_id,
      'entity_type', e.entity_type,
      'event_type',  e.event_type,
      'occurred_at', e.occurred_at,
      'payload',     e.payload,
      'prev',        encode(v_prev, 'hex')
    );
    v_expected := digest(v_canonical::text, 'sha256');

    if e.event_hash is distinct from v_expected then
      ok := false; broken_at := e.id; broken_event_no := v_n;
      reason := 'event_hash recomputation mismatch';
      return next; return;
    end if;

    v_prev := e.event_hash;
  end loop;

  ok := true; broken_at := null; broken_event_no := null; reason := null;
  return next;
end;
$$;


ALTER FUNCTION "public"."verify_chain"("p_account_id" "uuid") OWNER TO "postgres";

--
-- Name: verify_chain_incremental("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."verify_chain_incremental"("p_account_id" "uuid") RETURNS TABLE("ok" boolean, "broken_at" "uuid", "broken_event_no" bigint, "reason" "text", "events_checked" bigint)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  wm          record;
  e           record;
  v_prev      bytea  := decode(repeat('00', 32), 'hex'); -- genesis
  v_start     bigint := 0;
  v_n         bigint;
  v_checked   bigint := 0;
  v_full      record;
  v_canonical jsonb;
  v_expected  bytea;
  v_did_full  boolean := false;
begin
  select w.last_verified_seq, w.last_verified_hash
    into wm
    from public.chain_watermarks w
   where w.account_id = p_account_id;

  if found then
    -- Anchor re-check: the event the watermark points at must still exist
    -- with the recorded hash. O(1) via the (account_id, account_seq) index.
    perform 1 from public.events ev
      where ev.account_id = p_account_id
        and ev.account_seq = wm.last_verified_seq
        and ev.event_hash  = wm.last_verified_hash;
    if not found then
      -- Watermark and events disagree: full verify, and report its verdict.
      select vc.ok, vc.broken_at, vc.broken_event_no, vc.reason
        into v_full from public.verify_chain(p_account_id) vc;
      v_did_full := true;
      if not v_full.ok then
        ok := false; broken_at := v_full.broken_at;
        broken_event_no := v_full.broken_event_no;
        reason := 'watermark anchor mismatch; full verify: ' || coalesce(v_full.reason, 'broken');
        events_checked := (select count(*) from public.events where account_id = p_account_id);
        return next; return;
      end if;
      -- Full verify passed (e.g. watermark was stale garbage): rebuild it
      -- from the chain head below.
      select ev.account_seq, ev.event_hash into v_start, v_prev
        from public.events ev where ev.account_id = p_account_id
        order by ev.account_seq desc limit 1;
    else
      v_prev  := wm.last_verified_hash;
      v_start := wm.last_verified_seq;
    end if;
  end if;

  -- A walk that starts at genesis (no usable watermark) IS a full
  -- verification; record it as such so the sweep's 24h cadence is honest.
  if v_start = 0 then
    v_did_full := true;
  end if;

  v_n := v_start;
  for e in
    select ev.id, ev.account_id, ev.account_seq, ev.entity_type, ev.entity_id,
           ev.event_type, ev.payload, ev.occurred_at, ev.prev_event_hash, ev.event_hash
      from public.events ev
     where ev.account_id = p_account_id and ev.account_seq > v_start
     order by ev.account_seq asc
  loop
    v_n := v_n + 1;
    v_checked := v_checked + 1;

    if e.account_seq <> v_n then
      ok := false; broken_at := e.id; broken_event_no := v_n;
      reason := format('account_seq gap at position %s: row has account_seq %s', v_n, e.account_seq);
      events_checked := v_checked;
      return next; return;
    end if;

    if e.prev_event_hash is distinct from v_prev then
      ok := false; broken_at := e.id; broken_event_no := v_n;
      reason := 'prev_event_hash mismatch';
      events_checked := v_checked;
      return next; return;
    end if;

    v_canonical := jsonb_build_object(
      'account_id',  e.account_id,
      'account_seq', e.account_seq,
      'entity_id',   e.entity_id,
      'entity_type', e.entity_type,
      'event_type',  e.event_type,
      'occurred_at', e.occurred_at,
      'payload',     e.payload,
      'prev',        encode(v_prev, 'hex')
    );
    v_expected := digest(v_canonical::text, 'sha256');
    if e.event_hash is distinct from v_expected then
      ok := false; broken_at := e.id; broken_event_no := v_n;
      reason := 'event_hash recomputation mismatch';
      events_checked := v_checked;
      return next; return;
    end if;

    v_prev := e.event_hash;
  end loop;

  -- Verified through v_n; advance the watermark (if the chain has any events).
  if v_n >= 1 then
    insert into public.chain_watermarks
      (account_id, last_verified_seq, last_verified_hash, verified_at, last_full_at)
    values
      (p_account_id, v_n, v_prev, now(), case when v_did_full then now() else to_timestamp(0) end)
    on conflict (account_id) do update
      set last_verified_seq  = excluded.last_verified_seq,
          last_verified_hash = excluded.last_verified_hash,
          verified_at        = now(),
          last_full_at       = case when v_did_full then now()
                                    else public.chain_watermarks.last_full_at end,
          updated_at         = now();
  end if;

  ok := true; broken_at := null; broken_event_no := null; reason := null;
  events_checked := v_checked;
  return next;
end;
$$;


ALTER FUNCTION "public"."verify_chain_incremental"("p_account_id" "uuid") OWNER TO "postgres";

--
-- Name: verify_chain_sweep("uuid"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."verify_chain_sweep"("p_account_id" "uuid") RETURNS TABLE("ok" boolean, "alert_inserted" boolean, "alerts_resolved" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
declare
  v_actor    text := 'system:cron:chain_sweep';
  v_result   record;
  v_inserted boolean := false;
  v_resolved int := 0;
  v_need_full boolean;
  v_head     record;
begin
  perform set_config('audit.actor', v_actor, true);

  select (w.account_id is null or w.last_full_at < now() - interval '24 hours')
    into v_need_full
    from (select 1) one
    left join public.chain_watermarks w on w.account_id = p_account_id;

  if v_need_full then
    select vc.ok, vc.broken_at, vc.broken_event_no, vc.reason
      into v_result from public.verify_chain(p_account_id) vc;
    if v_result.ok then
      select ev.account_seq, ev.event_hash into v_head
        from public.events ev where ev.account_id = p_account_id
        order by ev.account_seq desc limit 1;
      if v_head.account_seq is not null then
        insert into public.chain_watermarks
          (account_id, last_verified_seq, last_verified_hash, verified_at, last_full_at)
        values (p_account_id, v_head.account_seq, v_head.event_hash, now(), now())
        on conflict (account_id) do update
          set last_verified_seq  = excluded.last_verified_seq,
              last_verified_hash = excluded.last_verified_hash,
              verified_at        = now(),
              last_full_at       = now(),
              updated_at         = now();
      end if;
    end if;
  else
    select vi.ok, vi.broken_at, vi.broken_event_no, vi.reason
      into v_result from public.verify_chain_incremental(p_account_id) vi;
  end if;

  if v_result.ok then
    update public.chain_verification_alerts
       set resolved_at = now(), updated_at = now()
     where account_id = p_account_id
       and resolved_at is null;
    get diagnostics v_resolved = row_count;
  else
    insert into public.chain_verification_alerts
      (account_id, broken_event_id, broken_event_no, reason)
    values
      (p_account_id, v_result.broken_at, v_result.broken_event_no,
       coalesce(v_result.reason, 'verify reported broken with no reason'))
    on conflict (account_id, broken_event_no) do update
      set last_detected_at = now(),
          updated_at       = now(),
          reason           = excluded.reason,
          -- Re-detection REOPENS a previously-resolved alert. The Phase 11
          -- sweep left resolved_at untouched on conflict, so a break that
          -- was resolved and later re-detected at the same position stayed
          -- silently "resolved" -- surfaced by the watermark DoD tests.
          resolved_at      = null;
    select (created_at = updated_at) into v_inserted
      from public.chain_verification_alerts
     where account_id = p_account_id and broken_event_no = v_result.broken_event_no;
  end if;

  ok               := v_result.ok;
  alert_inserted   := v_inserted;
  alerts_resolved  := v_resolved;
  return next;
end;
$$;


ALTER FUNCTION "public"."verify_chain_sweep"("p_account_id" "uuid") OWNER TO "postgres";

--
-- Name: void_inspection("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: postgres
--

CREATE OR REPLACE FUNCTION "public"."void_inspection"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_reason" "text") RETURNS "public"."inspections"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
declare
  v_row public.inspections;
begin
  update public.inspections
     set status      = 'voided',
         voided_at   = now(),
         void_reason = p_reason,
         updated_at  = now()
   where account_id = p_account_id and id = p_inspection_id
     and deleted_at is null and status <> 'voided'
  returning * into v_row;
  if not found then
    raise exception 'inspection_not_found_or_already_voided' using errcode = 'P0002';
  end if;
  return v_row;
end;
$$;


ALTER FUNCTION "public"."void_inspection"("p_account_id" "uuid", "p_inspection_id" "uuid", "p_reason" "text") OWNER TO "postgres";

