-- Name: document_versions; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."document_versions" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "document_id" "uuid" NOT NULL,
    "version_no" integer NOT NULL,
    "source" "text" NOT NULL,
    "attachment_id" "uuid",
    "static_template_id" "text",
    "static_asset_path" "text",
    "content_hash" "text" NOT NULL,
    "mime_type" "text" DEFAULT 'application/pdf'::"text" NOT NULL,
    "size_bytes" bigint NOT NULL,
    "created_by" "uuid",
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "deleted_at" timestamp with time zone,
    CONSTRAINT "document_versions_content_hash_check" CHECK (("content_hash" ~ '^[a-f0-9]{64}$'::"text")),
    CONSTRAINT "document_versions_size_bytes_check" CHECK (("size_bytes" >= 0)),
    CONSTRAINT "document_versions_source_attachment_check" CHECK (((("source" = ANY (ARRAY['landlord_upload'::"text", 'inspection_report'::"text"])) AND ("attachment_id" IS NOT NULL) AND ("static_template_id" IS NULL) AND ("static_asset_path" IS NULL)) OR (("source" = 'bundled_static'::"text") AND ("attachment_id" IS NULL) AND ("static_template_id" IS NOT NULL) AND ("static_asset_path" IS NOT NULL)))),
    CONSTRAINT "document_versions_source_check" CHECK (("source" = ANY (ARRAY['landlord_upload'::"text", 'bundled_static'::"text", 'inspection_report'::"text"]))),
    CONSTRAINT "document_versions_static_asset_path_check" CHECK ((("static_asset_path" IS NULL) OR (("length"("static_asset_path") >= 1) AND ("length"("static_asset_path") <= 500)))),
    CONSTRAINT "document_versions_static_template_id_check" CHECK ((("static_template_id" IS NULL) OR (("length"("static_template_id") >= 1) AND ("length"("static_template_id") <= 100)))),
    CONSTRAINT "document_versions_version_no_check" CHECK (("version_no" > 0))
);

ALTER TABLE ONLY "public"."document_versions" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."document_versions" OWNER TO "postgres";

