    "storage_path" "text" NOT NULL,
    "mime_type" "text" NOT NULL,
    "size_bytes" bigint NOT NULL,
    "uploaded_by" "uuid" NOT NULL,
    "derived_from_receipt_id" "uuid",
    "received_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "stored_at" timestamp with time zone,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "document_upload_receipts_check" CHECK ((("derived_from_receipt_id" IS NULL) OR ("derived_from_receipt_id" <> "id"))),
    CONSTRAINT "document_upload_receipts_check1" CHECK (("storage_path" = ((((((("account_id")::"text" || '/document-uploads/'::"text") || ("id")::"text") || '/'::"text") || "content_hash") || '.'::"text") ||
CASE "mime_type"
    WHEN 'application/pdf'::"text" THEN 'pdf'::"text"
    WHEN 'image/jpeg'::"text" THEN 'jpg'::"text"
    WHEN 'image/png'::"text" THEN 'png'::"text"
    WHEN 'image/webp'::"text" THEN 'webp'::"text"
    WHEN 'image/heic'::"text" THEN 'heic'::"text"
    WHEN 'image/heif'::"text" THEN 'heif'::"text"
    ELSE NULL::"text"
END))),
    CONSTRAINT "document_upload_receipts_content_hash_check" CHECK (("content_hash" ~ '^[a-f0-9]{64}$'::"text")),
    CONSTRAINT "document_upload_receipts_mime_type_check" CHECK (("mime_type" = ANY (ARRAY['application/pdf'::"text", 'image/jpeg'::"text", 'image/png'::"text", 'image/webp'::"text", 'image/heic'::"text", 'image/heif'::"text"]))),
    CONSTRAINT "document_upload_receipts_size_bytes_check" CHECK ((("size_bytes" >= 1) AND ("size_bytes" <= 20971520))),
    CONSTRAINT "document_upload_receipts_storage_path_check" CHECK ((("length"("storage_path") >= 1) AND ("length"("storage_path") <= 1024)))
);

