    CONSTRAINT "scheduled_tasks_check" CHECK ((("area_id" IS NOT NULL) OR ("asset_id" IS NOT NULL))),
    CONSTRAINT "scheduled_tasks_kind_check" CHECK ((("length"("kind") >= 1) AND ("length"("kind") <= 100))),
    CONSTRAINT "scheduled_tasks_recurrence_check" CHECK ((("length"("recurrence") >= 1) AND ("length"("recurrence") <= 200)))
);

