--
-- Name: tenancy_endings; Type: TABLE; Schema: public; Owner: postgres
--

CREATE TABLE IF NOT EXISTS "public"."tenancy_endings" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "account_id" "uuid" NOT NULL,
    "tenancy_id" "uuid" NOT NULL,
    "kind" "text" NOT NULL,
    "effective_date" "date" NOT NULL,
    "initiated_by" "text" DEFAULT 'unknown'::"text" NOT NULL,
    "reason_code" "text" DEFAULT 'other'::"text" NOT NULL,
    "reason_note" "text",
    "source_notice_id" "uuid",
    "source_interaction_id" "uuid",
    "created_by" "uuid" DEFAULT "auth"."uid"() NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    CONSTRAINT "tenancy_endings_check" CHECK (((("kind" = 'ended'::"text") AND ("reason_code" = ANY (ARRAY['notice'::"text", 'abandonment'::"text", 'fixed_term_completed'::"text", 'mutual_surrender'::"text", 'other'::"text"]))) OR (("kind" = 'cancelled_before_move_in'::"text") AND ("reason_code" = ANY (ARRAY['applicant_withdrew'::"text", 'landlord_withdrew'::"text", 'other'::"text"]))))),
    CONSTRAINT "tenancy_endings_initiated_by_check" CHECK (("initiated_by" = ANY (ARRAY['tenant'::"text", 'landlord'::"text", 'mutual'::"text", 'unknown'::"text"]))),
    CONSTRAINT "tenancy_endings_kind_check" CHECK (("kind" = ANY (ARRAY['ended'::"text", 'cancelled_before_move_in'::"text"]))),
    CONSTRAINT "tenancy_endings_reason_note_check" CHECK ((("reason_note" IS NULL) OR (("length"("reason_note") >= 1) AND ("length"("reason_note") <= 2000))))
);

ALTER TABLE ONLY "public"."tenancy_endings" FORCE ROW LEVEL SECURITY;


ALTER TABLE "public"."tenancy_endings" OWNER TO "postgres";

