--
-- Name: account_legal_holds account_legal_holds_manager_write; Type: POLICY; Schema: public; Owner: postgres
--

CREATE POLICY "account_legal_holds_manager_write" ON "public"."account_legal_holds" USING (("account_id" IN ( SELECT "m"."account_id"
   FROM "public"."account_members" "m"
  WHERE (("m"."user_id" = ( SELECT "auth"."uid"() AS "uid")) AND ("m"."role" = ANY (ARRAY['owner'::"text", 'manager'::"text"])) AND ("m"."deleted_at" IS NULL))))) WITH CHECK (("account_id" IN ( SELECT "m"."account_id"
   FROM "public"."account_members" "m"
  WHERE (("m"."user_id" = ( SELECT "auth"."uid"() AS "uid")) AND ("m"."role" = ANY (ARRAY['owner'::"text", 'manager'::"text"])) AND ("m"."deleted_at" IS NULL)))));


--
