CREATE POLICY "account_legal_holds_member_select" ON "public"."account_legal_holds" FOR SELECT USING (("account_id" IN ( SELECT "m"."account_id"
   FROM "public"."account_members" "m"
  WHERE (("m"."user_id" = ( SELECT "auth"."uid"() AS "uid")) AND ("m"."deleted_at" IS NULL)))));


